let currentUser = null;
let currentScreen = 'home';

// MVP feature cuts. Reads the config served at /js/features.js. Fail-closed:
// if that script is missing, cut features stay hidden (the server seals cut
// routes anyway). Only ever called on cut/gated surfaces, so it can never
// wrongly hide a core feature. Simple element hides ride on body classes +
// CSS (.feat-marketplace / .feat-directory / .feat-voice) so even
// late-rendered panels pick them up.
function featureVisible(key) {
  return window.tmgFeatureVisible ? !!window.tmgFeatureVisible(key) : false;
}
function applyFeatureCuts() {
  if (!document.body) return;
  document.body.classList.toggle('feat-hide-marketplace', !featureVisible('marketplace'));
  document.body.classList.toggle('feat-hide-directory', !featureVisible('find_musicians_directory'));
  document.body.classList.toggle('feat-hide-voice', !featureVisible('voice_notes'));
  document.body.classList.toggle('feat-hide-dep', !featureVisible('dep_offers'));
}
window.applyFeatureCuts = applyFeatureCuts;
if (document.body) applyFeatureCuts();
else document.addEventListener('DOMContentLoaded', applyFeatureCuts);

// Pre-production diagnostic: surface uncaught JS errors as a visible banner
// so device-only failures (iOS quirks, stale bundles) report themselves
// instead of taps silently doing nothing. Remove before launch.
window.addEventListener('error', function (e) {
  try {
    var file = String(e.filename || '').split('/').pop();
    var msg = (e.message || 'Script error') + (file ? ' @' + file + ':' + e.lineno : '');
    var el = document.getElementById('tmgErrBanner');
    if (!el) {
      el = document.createElement('div');
      el.id = 'tmgErrBanner';
      el.style.cssText = 'position:fixed;left:10px;right:10px;bottom:90px;z-index:2147483647;background:#3a1115;border:1px solid #F85149;color:#ffd7d5;font:12px -apple-system,sans-serif;padding:10px 12px;border-radius:10px;word-break:break-word;';
      el.onclick = function () { el.remove(); };
      (document.body || document.documentElement).appendChild(el);
    }
    el.textContent = 'App error: ' + msg + ' (tap to dismiss)';
    clearTimeout(window._tmgErrBannerT);
    window._tmgErrBannerT = setTimeout(function () { if (el.parentNode) el.remove(); }, 12000);
  } catch (_) {}
});

// Fix iOS Safari viewport height: Safari's toolbar overlaps position:fixed elements
// when viewport-fit=cover. Use visualViewport API to get actual visible height.
function setAppHeight() {
  var vh = window.visualViewport ? window.visualViewport.height : window.innerHeight;
  // Lengths inside a zoomed body are multiplied by the zoom factor, so the
  // shell height must be expressed in zoomed units or the bottom nav lands
  // beyond the real viewport.
  var z = parseFloat(document.body && document.body.style.zoom) || 1;
  document.documentElement.style.setProperty('--app-height', (vh / z) + 'px');
  // --app-nav-h positions panel-keep-header panels above the bottom nav. The
  // nav's height varies by device (safe-area inset padding), so measure the
  // real thing; a stale constant leaves a strip of the underlying screen
  // visible between the panel bottom and the nav.
  var nav = document.querySelector('.app-nav');
  if (nav && nav.offsetHeight) {
    document.documentElement.style.setProperty('--app-nav-h', (nav.offsetHeight / z) + 'px');
  }
}
window.setAppHeight = setAppHeight;
setAppHeight();
window.addEventListener('resize', setAppHeight);
if (window.visualViewport) {
  window.visualViewport.addEventListener('resize', setAppHeight);
  window.visualViewport.addEventListener('scroll', setAppHeight);
}

// ── Navigation integrity guard ───────────────────────────────────────────────
// Doctrine (Gareth 2026-07-02): never a place you can't easily go back from.
// The hardware/browser Back button must close the topmost layer (sheet, then
// panel, then non-home screen) instead of exiting the app. One synthetic
// history entry sits under the UI whenever something dismissible is open;
// popstate consumes it, dismisses the top layer, and re-arms while layers
// remain. On Home with nothing open, Back exits naturally.
var _navGuardArmed = false;
function _armNavGuard() {
  if (_navGuardArmed) return;
  try { history.pushState({ tmgNavGuard: true }, ''); _navGuardArmed = true; } catch (_) {}
}
window._armNavGuard = _armNavGuard;

function _topDismissible() {
  const adHoc = ['peFormSheet', 'peDetailSheet', 'onboardingOverlay'];
  for (const id of adHoc) {
    const el = document.getElementById(id);
    if (el) return { kind: 'adhoc', el };
  }
  const sheets = document.querySelectorAll('.sheet-overlay');
  if (sheets.length) return { kind: 'sheet', el: sheets[sheets.length - 1] };
  const panels = document.querySelectorAll('.panel-overlay.open');
  if (panels.length) return { kind: 'panel', el: panels[panels.length - 1] };
  if (typeof currentScreen !== 'undefined' && currentScreen !== 'home') return { kind: 'screen' };
  return null;
}

window.addEventListener('popstate', function () {
  _navGuardArmed = false;
  const top = _topDismissible();
  if (!top) return; // Home, nothing open: let the browser continue back out.
  if (top.kind === 'sheet' || top.kind === 'adhoc') {
    if (top.el.parentNode) top.el.parentNode.removeChild(top.el);
  } else if (top.kind === 'panel') {
    closePanel(top.el.id);
  } else {
    showScreen('home');
  }
  if (_topDismissible()) _armNavGuard();
});

// Ad-hoc bottom sheets are created all over the codebase; watch for them
// appearing rather than hooking every creation site.
new MutationObserver(function (muts) {
  for (const m of muts) {
    for (const node of m.addedNodes) {
      if (node.nodeType !== 1) continue;
      if ((node.classList && node.classList.contains('sheet-overlay'))
          || node.id === 'peFormSheet' || node.id === 'peDetailSheet' || node.id === 'onboardingOverlay') {
        _armNavGuard();
        return;
      }
    }
  }
}).observe(document.documentElement, { childList: true, subtree: true });

// Desktop scroll-anywhere: on viewports wider than the 390px app column,
// the gutters to the left and right of the centered content don't respond
// to mouse-wheel or trackpad scroll because body is overflow:hidden and the
// event target isn't inside .app-content / .panel-body. This listener
// forwards any wheel event that fires outside a natively-scrollable
// container to whichever scrollable region is currently on top (an open
// panel-body if there is one, otherwise the active .app-content). Does
// nothing on mobile because the gutters don't exist there, and lets the
// event pass through untouched whenever the user is already over a
// scrollable element so nested scroll still works as expected.
(function enableScrollAnywhere() {
  function findActiveScrollable() {
    // Prefer the topmost open panel. Stacked panels (e.g. profile over
    // edit-profile) both carry .open, and the later DOM node is visually on
    // top, so the last match wins.
    var openPanels = document.querySelectorAll('.panel-overlay.open');
    if (openPanels.length) {
      var top = openPanels[openPanels.length - 1];
      var body = top.querySelector('.panel-body');
      if (body) return body;
    }
    var screen = document.querySelector('.screen.active .app-content')
              || document.querySelector('.app-content');
    return screen || null;
  }
  window.addEventListener('wheel', function(ev) {
    // Ignore pinch-zoom gestures (trackpad sends wheel + ctrlKey).
    if (ev.ctrlKey) return;
    // Walk up from the target; if any ancestor is itself scrollable and
    // has overflowing content, let the browser handle it natively.
    var node = ev.target;
    while (node && node !== document.documentElement) {
      if (node.nodeType === 1 && node.scrollHeight > node.clientHeight) {
        var oy = getComputedStyle(node).overflowY;
        if (oy === 'auto' || oy === 'scroll') return;
      }
      node = node.parentNode;
    }
    var target = findActiveScrollable();
    if (!target) return;
    target.scrollTop += ev.deltaY;
    ev.preventDefault();
  }, { passive: false });
})();

// Run text scaling immediately so all screens (including auth) scale correctly
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', () => { if (typeof setupTextScaling === 'function') setupTextScaling(); });
} else {
  // DOM already ready (e.g. script loaded at end of body)
  setTimeout(() => { if (typeof setupTextScaling === 'function') setupTextScaling(); }, 0);
}

// Keep --app-nav-h in sync with the actual rendered height of the bottom nav so
// the quick-action panels (.panel-keep-header) stop exactly above it. Using the
// measured value covers safe-area-inset-bottom differences on iOS home-indicator
// devices, text-scaling changes, and any future nav-row additions without the
// CSS having to track them.
function syncAppNavHeight() {
  var nav = document.querySelector('.app-nav');
  if (!nav) return;
  var h = nav.getBoundingClientRect().height;
  if (h > 0) document.documentElement.style.setProperty('--app-nav-h', h + 'px');
}
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', syncAppNavHeight);
} else {
  setTimeout(syncAppNavHeight, 0);
}
window.addEventListener('resize', syncAppNavHeight);

// Wizard state
let gigWizardStep = 1;
let gigWizardData = {};
window._cachedGigs = null;
window._cachedStats = null;
window._cachedStatsTime = 0;
window._cachedContacts = [];
window._contactFilterType = 'all';
window._cachedProfile = null;
window._cachedProfileTime = 0;
window._cachedInvoices = null;
window._cachedInvoicesTime = 0;
window._cachedOffers = null;
window._cachedOffersTime = 0;
window._calViewMode = localStorage.getItem('tmg_cal_view') || 'list';
window._calDate = new Date();

// Cache TTL in ms
// Home stats can be up to 5min old before we show a skeleton instead of stale
// data. renderHomeScreen() uses stale-while-revalidate regardless — it always
// renders the cache first, then refetches silently in the background — so this
// TTL really only bounds how old we'll allow the very first paint to be.
const STATS_CACHE_TTL = 300000;
const PROFILE_CACHE_TTL = 60000;
const DATA_CACHE_TTL = 30000;

// Hydrate _cachedStats from localStorage on module load so the first open of the
// app after a cold boot paints real-looking data instantly instead of a skeleton.
// The background fetch in renderHomeScreen() then refreshes to live data.
// Keyed by user id so switching accounts never surfaces another user's stats.
try {
  const raw = localStorage.getItem('tmg_cachedStats_v1');
  if (raw) {
    const parsed = JSON.parse(raw);
    if (parsed && parsed.stats && parsed.userId && parsed.time) {
      window._cachedStats = parsed.stats;
      window._cachedStatsTime = parsed.time;
      window._cachedStatsUser = parsed.userId;
    }
  }
} catch (_) { /* corrupt localStorage entry — ignore */ }

function persistCachedStats() {
  try {
    if (!window._cachedStats || !window._cachedStatsUser) return;
    localStorage.setItem('tmg_cachedStats_v1', JSON.stringify({
      stats: window._cachedStats,
      userId: window._cachedStatsUser,
      time: window._cachedStatsTime || Date.now(),
    }));
  } catch (_) { /* quota / privacy mode — ignore */ }
}

// Hydrate _cachedGigs and _cachedBlocked from localStorage at script parse
// time so the Calendar screen paints instantly on a cold open instead of
// running through the 3-5s skeleton + fetch path every time. Stale-while-
// revalidate refresh happens in renderCalendarScreen().
// Keyed by user id so switching accounts never leaks calendar data.
try {
  const raw = localStorage.getItem('tmg_cachedCalendar_v1');
  if (raw) {
    const parsed = JSON.parse(raw);
    if (parsed && parsed.userId && parsed.time) {
      window._cachedGigs = parsed.gigs || null;
      window._cachedBlocked = parsed.blocked || null;
      window._cachedBlockedTime = parsed.time;
      window._cachedCalendarUser = parsed.userId;
    }
  }
} catch (_) { /* corrupt localStorage entry — ignore */ }

function persistCachedCalendar() {
  try {
    const userId = window._currentUser?.id || window._cachedCalendarUser || null;
    if (!userId) return;
    window._cachedCalendarUser = userId;
    // Only persist if we have at least one piece of data worth keeping
    if (!window._cachedGigs && !window._cachedBlocked) {
      localStorage.removeItem('tmg_cachedCalendar_v1');
      return;
    }
    localStorage.setItem('tmg_cachedCalendar_v1', JSON.stringify({
      gigs: window._cachedGigs || null,
      blocked: window._cachedBlocked || null,
      userId,
      time: window._cachedBlockedTime || Date.now(),
    }));
  } catch (_) { /* quota / privacy mode — ignore */ }
}

function initApp(user) {
  currentUser = user;
  window._currentUser = user;
  setupTextScaling();
  setupThemeToggle();
  setupNavigation();
  setupScreenHandlers();

  // Strip ?calendar_connected=true from the URL once we've landed, so a
  // refresh doesn't re-show any connected banner keyed off that param.
  // First-import modal hook (2026-04-23): if the URL flag is present and
  // this user has never bulk-imported, open the modal before we strip.
  const justConnected = (typeof URL !== 'undefined')
    && new URL(window.location.href).searchParams.get('calendar_connected') === 'true';
  // Phase C (2026-04-27): same dance for sheets_connected. Strip the flag,
  // and if the user kicked off OAuth from inside the onboarding picker,
  // resume them at the URL-paste step so they can finish the import.
  const sheetsJustConnected = (typeof URL !== 'undefined')
    && new URL(window.location.href).searchParams.get('sheets_connected') === 'true';
  if (sheetsJustConnected) {
    try {
      const u = new URL(window.location.href);
      u.searchParams.delete('sheets_connected');
      const qs = u.searchParams.toString();
      history.replaceState(null, '', u.pathname + (qs ? `?${qs}` : '') + u.hash);
    } catch (_) {}
    const sheetsResume = (function () {
      try { return localStorage.getItem('tmg_onboarding_resume'); } catch (_) { return null; }
    })();
    if (sheetsResume === 'sheets') {
      try { localStorage.removeItem('tmg_onboarding_resume'); } catch (_) {}
      // Skip the welcome/profile slides and drop straight into the Sheets
      // URL paste step. _onboardingShown stops the regular tour from also
      // firing. _sheetsResumeAutoFetch tells showSheetsUrlStep to auto-
      // trigger the preview so the user doesn't have to click Read again
      // after the OAuth bounce.
      window._onboardingShown = true;
      window._sheetsResumeAutoFetch = true;
      setTimeout(() => {
        if (typeof showSheetsUrlStep === 'function') showSheetsUrlStep();
      }, 400);
    }
  }
  if (typeof clearCalendarConnectedParam === 'function') {
    clearCalendarConnectedParam();
  }
  if (justConnected) {
    // Onboarding resume (2026-04-27): if the user kicked off Google Calendar
    // OAuth from inside the onboarding picker we left a marker in
    // localStorage. Resume the picker at the "Anything else?" pass with
    // calendar removed from the available sources, then run the existing
    // first-import bulk-import modal so the user can pull historical gigs in.
    const resumeFrom = (function () {
      try { return localStorage.getItem('tmg_onboarding_resume'); } catch (_) { return null; }
    })();
    if (resumeFrom === 'calendar') {
      try { localStorage.removeItem('tmg_onboarding_resume'); } catch (_) {}
      // Pre-seed onboarding state so the picker hides the calendar option.
      window._onboardingState = window._onboardingState || { completed: [] };
      if (!window._onboardingState.completed.includes('calendar')) {
        window._onboardingState.completed.push('calendar');
      }
      // Tell maybeStartOnboarding to skip to the picker rather than walking
      // the user through the whole tour again.
      window._onboardingResumePicker = true;
    }

    // 2026-04-27: scope the first-import-done flag per user. The original
    // global key suppressed the modal for users who shared a Chrome
    // session with a different TMG account that already did the import.
    // Using user.id in the key means each fresh user gets the modal once,
    // regardless of who used this browser before.
    const firstImportKey = (function () {
      const uid = window._currentUser?.id;
      return uid ? `tmg_first_import_done:${uid}` : 'tmg_first_import_done';
    })();
    const firstDone = (function () {
      try { return localStorage.getItem(firstImportKey) === '1'; }
      catch (_) { return false; }
    })();
    if (!firstDone && typeof openFirstImportModal === 'function') {
      // Small delay so the Calendar panel is ready under the modal.
      setTimeout(() => openFirstImportModal(), 600);
    }
  }

  // Stripe handshake (task #282):
  //   ?intent=premium&plan=<monthly|annual> — landing bounced the user here
  //     because they weren't signed in when they clicked Go Premium. Now that
  //     they're authed, fire checkout and forward them to Stripe.
  //   ?premium=success&session_id=... — Stripe checkout completed. Show a
  //     welcome toast; the webhook has already flipped the premium flag.
  //   ?premium=cancelled — user backed out of checkout. Quiet acknowledgement.
  // All three params are stripped from the address bar after handling so a
  // refresh doesn't re-trigger the flow.
  try {
    const url = new URL(window.location.href);
    const intent = url.searchParams.get('intent');
    const premiumStatus = url.searchParams.get('premium');
    const plan = url.searchParams.get('plan');
    let needsStrip = false;
    if (intent === 'premium' && (plan === 'monthly' || plan === 'annual')) {
      needsStrip = true;
      if (typeof startPremiumCheckout === 'function') {
        setTimeout(() => startPremiumCheckout(plan), 400);
      }
    }
    if (premiumStatus === 'success') {
      needsStrip = true;
      if (typeof toast === 'function') {
        setTimeout(() => toast('Welcome to premium. Your 14-day trial has started.'), 500);
      }
      // Invalidate caches so premium-gated UI re-reads the new flag.
      try { window._cachedProfile = null; } catch (_) {}
      try { window._cachedStats = null; window._cachedStatsTime = 0; } catch (_) {}
    } else if (premiumStatus === 'cancelled') {
      needsStrip = true;
      if (typeof toast === 'function') {
        setTimeout(() => toast('Checkout cancelled. No charge made.'), 300);
      }
    }
    if (needsStrip) {
      url.searchParams.delete('intent');
      url.searchParams.delete('plan');
      url.searchParams.delete('premium');
      url.searchParams.delete('session_id');
      const qs = url.searchParams.toString();
      history.replaceState(null, '', url.pathname + (qs ? `?${qs}` : '') + url.hash);
    }
  } catch (_) { /* never block boot on this */ }

  // Seed calendar connection state from the user record we already have,
  // so Profile and Calendar panels render correctly on first paint.
  if (user && typeof user === 'object') {
    if (user.calendar_connected !== undefined) {
      window._googleConnected = !!user.calendar_connected;
    }
    if (user.calendar_email) {
      window._googleCalendarEmail = user.calendar_email;
    }
  }

  // Update the fixed header with user info
  updateAppHeader();

  // Show home immediately (uses skeleton while data loads)
  showScreen('home');

  // Arm the 5-min calendar background poll + visibility listener. Idempotent.
  try { startCalendarPollingOnce(); } catch (_) { /* optional */ }

  // Prefetch ALL screen data in parallel so every tab opens instantly
  window._prefetchPromise = prefetchAllData();

  // S14-08: honour the `?shortcut=…` URL param that PWA launcher shortcuts set.
  // Wait a tick so the screen framework has mounted before opening a panel,
  // then clear the param from the address bar to keep copy-paste links clean.
  try {
    const params = new URLSearchParams(location.search);
    const shortcut = params.get('shortcut');
    if (shortcut) {
      setTimeout(() => {
        try {
          if (shortcut === 'new-gig' && typeof openGigWizard === 'function') {
            openGigWizard();
          } else if (shortcut === 'new-expense') {
            if (typeof openPanel === 'function') openPanel('panel-receipt');
            setTimeout(() => { if (typeof showReceiptForm === 'function') showReceiptForm('manual'); }, 150);
          } else if (shortcut === 'invoices' && typeof showScreen === 'function') {
            showScreen('invoices');
          } else if (shortcut === 'finance' && typeof openPanel === 'function') {
            openPanel('panel-finance');
          }
        } catch (_) { /* shortcut is a nice-to-have, never block boot */ }
        // Strip the param so refreshes don't re-trigger the shortcut
        params.delete('shortcut');
        const qs = params.toString();
        history.replaceState(null, '', location.pathname + (qs ? `?${qs}` : '') + location.hash);
      }, 250);
    }
  } catch (_) { /* ignore */ }
}

async function prefetchAllData() {
  // /api/stats is fetched by renderHomeScreen() already via fetchStatsWithCache
  // (which dedupes concurrent callers), so we just grab its promise here rather
  // than opening a second connection. The other fetches fire in parallel.
  const statsPromise = fetchStatsWithCache(false).catch((err) => {
    console.error('prefetch stats failed:', err);
    return null;
  });

  const [gigsRes, invoicesRes, offersRes, profileRes, blockedRes] = await Promise.allSettled([
    fetch('/api/gigs'),
    fetch('/api/invoices'),
    fetch('/api/offers'),
    fetch('/api/user/profile'),
    fetch('/api/blocked-dates'),
  ]);

  const now = Date.now();

  const stats = await statsPromise;
  if (stats && currentScreen === 'home') {
    const content = document.getElementById('homeScreen');
    if (content) buildHomeHTML(content, stats);
  }

  if (gigsRes.status === 'fulfilled' && gigsRes.value.ok) {
    window._cachedGigs = await gigsRes.value.json();
    persistCachedCalendar();
  }

  if (invoicesRes.status === 'fulfilled' && invoicesRes.value.ok) {
    window._cachedInvoices = await invoicesRes.value.json();
    window._cachedInvoicesTime = now;
  }

  if (offersRes.status === 'fulfilled' && offersRes.value.ok) {
    window._cachedOffers = await offersRes.value.json();
    window._cachedOffersTime = now;
  }
  // Keep the nav Offers badge consistent with the Offers screen:
  // derive it from the actual pending offers list rather than a
  // separately-counted server stat that can drift.
  const pendingOffersCount = (window._cachedOffers || []).filter(o => o.status === 'pending').length;
  updateOffersBadge(pendingOffersCount);

  if (profileRes.status === 'fulfilled' && profileRes.value.ok) {
    window._cachedProfile = await profileRes.value.json();
    window._cachedProfileTime = now;
    // Seed calendar connection state so any screen that renders before
    // /api/calendar/status is probed has the right connect/disconnect UI.
    if (window._cachedProfile.google_access_token !== undefined) {
      window._googleConnected = !!window._cachedProfile.google_access_token;
    }
    if (window._cachedProfile.google_calendar_email) {
      window._googleCalendarEmail = window._cachedProfile.google_calendar_email;
    }
    // Sync colour theme from profile (server wins over localStorage)
    if (window._cachedProfile.colour_theme) {
      localStorage.setItem('colourTheme', window._cachedProfile.colour_theme);
      applyColourTheme(window._cachedProfile.colour_theme);
    }
  }

  if (blockedRes.status === 'fulfilled' && blockedRes.value.ok) {
    window._cachedBlocked = await blockedRes.value.json();
    window._cachedBlockedTime = now;
    persistCachedCalendar();
  }

  // Show onboarding tour on very first load (profile has no onboarded_at yet).
  // Delay by a tick so the home screen paints first, then the tour appears over it.
  setTimeout(() => {
    if (typeof maybeStartOnboarding === 'function') maybeStartOnboarding();
  }, 400);
}

// Update the bottom nav Offers tab badge based on pending offer count.
// Hides the badge entirely when there are zero pending offers, shows "9+" when above 9.
function updateOffersBadge(count) {
  const badge = document.getElementById('offersBadge');
  if (!badge) return;
  const n = parseInt(count || 0, 10);
  if (!n || isNaN(n) || n <= 0) {
    badge.style.display = 'none';
    badge.textContent = '';
    return;
  }
  badge.style.display = '';
  badge.textContent = n > 9 ? '9+' : String(n);
}

function updateAppHeader() {
  // Prefer display_name (the user's real name) over name (which may be an act/band name)
  const name = window._currentUser?.display_name || window._currentUser?.name || 'Guest';
  const initial = (name || 'G')[0].toUpperCase();
  const hour = new Date().getHours();
  // 'Good evening, <name>' cannot share a phone-width line with the full
  // name and three header icons; the shorter form keeps the size Gareth
  // likes and the whole name visible.
  let greeting = 'Morning';
  if (hour >= 12 && hour < 18) greeting = 'Afternoon';
  if (hour >= 18) greeting = 'Evening';

  const avatarEl = document.getElementById('userAvatar');
  if (avatarEl) {
    const pUrl = (window._cachedProfile && window._cachedProfile.photo_url)
      || (window._currentUser && window._currentUser.photo_url) || null;
    if (pUrl) {
      avatarEl.textContent = '';
      avatarEl.style.backgroundImage = `url('${pUrl}')`;
      avatarEl.style.backgroundSize = 'cover';
      avatarEl.style.backgroundPosition = 'center';
    } else {
      avatarEl.style.backgroundImage = '';
      avatarEl.textContent = initial;
    }
  }
  window.refreshHeaderAvatar = () => {
    const el = document.getElementById('userAvatar');
    const u = (window._cachedProfile && window._cachedProfile.photo_url) || null;
    if (!el) return;
    if (u) {
      el.textContent = '';
      el.style.backgroundImage = `url('${u}')`;
      el.style.backgroundSize = 'cover';
      el.style.backgroundPosition = 'center';
    } else {
      el.style.backgroundImage = '';
      el.textContent = initial;
    }
  };

  const greetingEl = document.getElementById('greeting');
  if (greetingEl) greetingEl.textContent = `${greeting}, ${name}`;
}

// prefetchGigs replaced by prefetchAllData above

function buildSkeletonHTML() {
  // S11-08: Skeleton must mirror the real Home layout so the content doesn't
  // jump when stats resolve. Order here matches buildHomeHTML(): next-gig
  // card, alert tile row (3 tiles), messages preview, quick-stats row,
  // forecast chart. Heights and margins are set to match the real elements.
  const pulse = 'background:var(--card);border-radius:var(--r);animation:pulse 1.5s ease-in-out infinite;';
  const pulseSm = 'background:var(--card);border-radius:var(--rs);animation:pulse 1.5s ease-in-out infinite;';
  return `
    <style>@keyframes pulse{0%,100%{opacity:.4}50%{opacity:.8}}</style>
    <div style="margin:0 16px 8px;${pulse}height:88px;"></div>
    <div style="display:flex;gap:6px;margin:0 16px 6px;">
      <div style="flex:1;${pulseSm}height:54px;"></div>
      <div style="flex:1;${pulseSm}height:54px;"></div>
      <div style="flex:1;${pulseSm}height:54px;"></div>
    </div>
    <div style="margin:0 16px 8px;${pulseSm}height:56px;"></div>
    <div style="display:flex;gap:6px;margin:0 16px 8px;">
      <div style="flex:1;${pulseSm}height:64px;"></div>
      <div style="flex:1;${pulseSm}height:64px;"></div>
    </div>
    <div style="margin:0 16px 8px;${pulseSm}height:72px;"></div>`;
}

function setupTextScaling() {
  // Whole-app scaling (2026-06-10, Gareth's standing request). The UI is
  // px-based throughout, so honouring the phone's text size by scaling
  // only rem text inflated random fragments. Instead the ENTIRE app zooms
  // uniformly (text, spacing, buttons together) from the system preference,
  // detected via the -apple-system-body probe (iOS Dynamic Type; Android
  // font scale comes through the same way in Chrome).
  // Preview/override: open the app with ?textscale=1.3 (or 0.9 ... 1.35);
  // the choice persists until ?textscale=reset.
  try {
    var scale = null;
    var qs = new URLSearchParams(window.location.search).get('textscale');
    if (qs === 'reset') localStorage.removeItem('tmg_text_scale');
    else if (qs && !isNaN(parseFloat(qs))) {
      scale = parseFloat(qs);
      localStorage.setItem('tmg_text_scale', String(scale));
    }
    if (scale === null) {
      var saved = parseFloat(localStorage.getItem('tmg_text_scale'));
      if (saved > 0) scale = saved;
    }
    if (scale === null) {
      var probe = document.createElement('p');
      probe.textContent = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
      probe.setAttribute('style', 'font: -apple-system-body !important; position: absolute !important; left: -9999px !important; visibility: hidden !important;');
      document.body.appendChild(probe);
      var preferredSize = parseFloat(window.getComputedStyle(probe).fontSize);
      document.body.removeChild(probe);
      if (preferredSize > 0 && Math.abs(preferredSize - 16) > 0.5) scale = preferredSize / 16;
    }
    if (scale && scale > 1.02) {
      // Text-only scaling: -webkit-text-size-adjust grows the WORDS while
      // the layout keeps its shape (WhatsApp-style), unlike body zoom which
      // inflated boxes and text together. Mobile engines honour it; desktop
      // ignores it, which is fine - this is a phone feature. Clamped at
      // 135% so dense layouts wrap rather than break.
      var pct = Math.round(Math.min(1.35, scale) * 100) + '%';
      document.documentElement.style.webkitTextSizeAdjust = pct;
      document.documentElement.style.textSizeAdjust = pct;
    } else {
      document.documentElement.style.webkitTextSizeAdjust = '100%';
      document.documentElement.style.textSizeAdjust = '100%';
    }
    document.body.style.zoom = '';
    if (typeof setAppHeight === 'function') setAppHeight();
  } catch (e) { /* default 1x */ }
}

// In-app text size picker: the guaranteed path (auto-detection of the
// phone's setting stays as the default behaviour).
function openTextSizePicker() {
  const cur = localStorage.getItem('tmg_text_scale');
  const existing = document.getElementById('textSizeSheet');
  if (existing) existing.remove();
  const sheet = document.createElement('div');
  sheet.id = 'textSizeSheet';
  sheet.style.cssText = 'position:fixed;inset:0;z-index:99999;background:rgba(0,0,0,0.55);display:flex;align-items:flex-end;justify-content:center;';
  const opt = (label, val, sample) => {
    const sel = (val === null && !cur) || (cur && parseFloat(cur) === val);
    return `<div onclick="setTextSize(${val === null ? 'null' : val})" style="display:flex;align-items:center;justify-content:space-between;padding:13px 14px;border:1px solid ${sel ? 'var(--accent)' : 'var(--border)'};border-radius:10px;margin-bottom:8px;cursor:pointer;${sel ? 'background:var(--accent-dim);' : 'background:var(--card);'}">
      <span style="font-size:${sample}px;font-weight:600;color:var(--text);">${label}</span>
      ${sel ? '<span style="color:var(--accent);font-weight:800;">\u2713</span>' : ''}
    </div>`;
  };
  sheet.innerHTML = '<div style="width:100%;max-width:480px;background:var(--card);border-radius:16px 16px 0 0;padding:16px 16px 24px;border-top:1px solid var(--border);">'
    + '<div style="width:40px;height:4px;background:var(--border);border-radius:2px;margin:0 auto 12px;"></div>'
    + '<div style="font-size:14px;font-weight:700;text-align:center;margin-bottom:4px;">Text size</div>'
    + '<div style="font-size:11px;color:var(--text-2);text-align:center;margin-bottom:12px;">Scales the whole app. Auto follows your phone\u2019s setting.</div>'
    + opt('Auto (follow my phone)', null, 14)
    + opt('Default', 1, 14)
    + opt('Large', 1.15, 16)
    + opt('Extra large', 1.35, 19)
    + '<button onclick="document.getElementById(\'textSizeSheet\').remove()" style="width:100%;background:transparent;color:var(--text-2);border:none;padding:10px;font-size:13px;cursor:pointer;">Close</button>'
    + '</div>';
  sheet.addEventListener('click', (ev) => { if (ev.target === sheet) sheet.remove(); });
  document.body.appendChild(sheet);
}

function setTextSize(val) {
  if (val === null) localStorage.removeItem('tmg_text_scale');
  else localStorage.setItem('tmg_text_scale', String(val));
  setupTextScaling();
  const row = document.getElementById('textSizeRowValue');
  if (row) row.textContent = val === null ? 'Auto' : val === 1 ? 'Default' : val === 1.15 ? 'Large' : 'Extra large';
  // Re-render the sheet in place so the change shows immediately while
  // the options are still on screen.
  openTextSizePicker();
}
window.openTextSizePicker = openTextSizePicker;
window.setTextSize = setTextSize;

function setupThemeToggle() {
  const themeToggle = document.getElementById('themeToggle');
  const savedTheme = localStorage.getItem('theme') || 'dark';

  if (savedTheme === 'light') {
    document.body.classList.add('light-mode');
    themeToggle.innerHTML = '<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="var(--accent)" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:middle;"><circle cx="12" cy="12" r="4"/><path d="M12 2v2M12 20v2M4.93 4.93l1.41 1.41M17.66 17.66l1.41 1.41M2 12h2M20 12h2M4.93 19.07l1.41-1.41M17.66 6.34l1.41-1.41"/></svg>';
  } else {
    document.body.classList.remove('light-mode');
    themeToggle.innerHTML = '<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="var(--accent)" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:middle;"><path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"/></svg>';
  }

  // Apply saved colour theme
  const savedColour = localStorage.getItem('colourTheme') || 'amber';
  applyColourTheme(savedColour);

  themeToggle.addEventListener('click', () => {
    document.body.classList.toggle('light-mode');
    const newTheme = document.body.classList.contains('light-mode')
      ? 'light'
      : 'dark';
    localStorage.setItem('theme', newTheme);
    themeToggle.innerHTML = newTheme === 'light' ? '<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="var(--accent)" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:middle;"><circle cx="12" cy="12" r="4"/><path d="M12 2v2M12 20v2M4.93 4.93l1.41 1.41M17.66 17.66l1.41 1.41M2 12h2M20 12h2M4.93 19.07l1.41-1.41M17.66 6.34l1.41-1.41"/></svg>' : '<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="var(--accent)" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:middle;"><path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"/></svg>';
  });
}

function setupNavigation() {
  const navItems = document.querySelectorAll('.nav-item');
  navItems.forEach((item) => {
    item.addEventListener('click', () => {
      const screen = item.getAttribute('data-screen');
      // Receipt isn't a screen, it's an overlay panel. Open it directly
      // rather than rerouting through showScreen which would close any
      // open panels first.
      if (screen === 'receipt') {
        openPanel('panel-receipt');
        if (typeof initReceiptPanel === 'function') initReceiptPanel();
        // Receipts lives in an overlay, not a screen, but the nav should
        // still behave like a tab: highlight it. showScreen() clears the
        // active class again when any other tab is tapped.
        document.querySelectorAll('.nav-item').forEach((n) => n.classList.remove('active'));
        item.classList.add('active');
        return;
      }
      // Money is the Finance dashboard, also an overlay panel. Same tab dance.
      if (screen === 'money') {
        openPanel('panel-finance');
        if (typeof renderFinancePanel === 'function') renderFinancePanel();
        document.querySelectorAll('.nav-item').forEach((n) => n.classList.remove('active'));
        item.classList.add('active');
        return;
      }
      showScreen(screen);
    });
  });
}

function setupScreenHandlers() {
  setupGigsScreen();
  setupInvoicesScreen();
  setupOffersScreen();
}

function showScreen(screenName) {
  // Money and Receipt are nav tabs but not screens: they live in overlay
  // panels (see setupNavigation). Route them here too so any caller of
  // showScreen('money') gets the Finance panel instead of a blank app.
  if (screenName === 'money' || screenName === 'receipt') {
    const panelId = screenName === 'money' ? 'panel-finance' : 'panel-receipt';
    openPanel(panelId);
    if (screenName === 'money' && typeof renderFinancePanel === 'function') renderFinancePanel();
    if (screenName === 'receipt' && typeof initReceiptPanel === 'function') initReceiptPanel();
    document.querySelectorAll('.nav-item').forEach((n) => n.classList.remove('active'));
    const navItem = document.querySelector(`.nav-item[data-screen="${screenName}"]`);
    if (navItem) navItem.classList.add('active');
    return;
  }
  // Close any open overlay panels before switching screens. The bottom-row
  // quick actions (Invoice, Block, Dep, Receipt) open .panel-keep-header
  // overlays that leave the nav visible and clickable. When the user taps a
  // main-nav item from inside one of those panels they expect to navigate
  // away; without this, the overlay stays on top of the new screen and the
  // nav appears broken.
  var openOverlays = document.querySelectorAll('.panel-overlay.open');
  openOverlays.forEach(function (p) {
    closePanel(p.id);
  });

  const screens = document.querySelectorAll('.app-content .screen');
  screens.forEach((s) => s.classList.remove('active'));

  const screen = document.getElementById(`${screenName}Screen`);
  if (screen) {
    screen.classList.add('active');
  }

  const navItems = document.querySelectorAll('.nav-item');
  navItems.forEach((item) => {
    item.classList.remove('active');
  });

  const activeNav = document.querySelector(
    `.nav-item[data-screen="${screenName}"]`
  );
  if (activeNav) {
    activeNav.classList.add('active');
  }

  currentScreen = screenName;
  if (screenName !== 'home') _armNavGuard();

  if (screenName === 'home') {
    renderHomeScreen();
  } else if (screenName === 'gigs') {
    renderGigsScreen();
  } else if (screenName === 'calendar') {
    // Reset to today when navigating to calendar from elsewhere, so user
    // always lands on the current month (not a stale stored date).
    window._calDate = new Date();
    window._calViewMode = window._calViewMode || localStorage.getItem('tmg_cal_view') || 'list';
    renderCalendarScreen();
  } else if (screenName === 'invoices') {
    renderInvoicesScreen();
  } else if (screenName === 'offers') {
    renderOffersScreen();
  } else if (screenName === 'profile') {
    renderProfileScreen();
  }
}

// S11-07: Stats cache must belong to a specific user so account switches
// (dev-login, log out / log back in) never render the previous user's data.
// _cachedStatsUser tracks who the cache belongs to and the cache is
// invalidated whenever it doesn't match the currently logged-in user id.
async function fetchStatsWithCache(forceRefresh) {
  const now = Date.now();
  const currentUserId = window._currentUser?.id || null;
  const cacheMatchesUser = window._cachedStatsUser && window._cachedStatsUser === currentUserId;
  if (!forceRefresh && cacheMatchesUser && window._cachedStats && (now - window._cachedStatsTime) < STATS_CACHE_TTL) {
    return window._cachedStats;
  }
  // Dedupe concurrent fetches: if we're already refetching, reuse the pending
  // promise instead of opening a second network request. This matters because
  // /api/stats runs 13 parallel DB queries and is expensive on Neon.
  if (window._inflightStatsPromise) {
    return window._inflightStatsPromise;
  }
  const p = fetch('/api/stats').then(async (res) => {
    if (!res.ok) throw new Error('Failed to fetch stats');
    const stats = await res.json();
    window._cachedStats = stats;
    window._cachedStatsTime = Date.now();
    window._cachedStatsUser = currentUserId;
    persistCachedStats();
    return stats;
  }).finally(() => {
    window._inflightStatsPromise = null;
  });
  window._inflightStatsPromise = p;
  return p;
}

function hideBootSplash() {
  const s = document.getElementById('bootSplash');
  if (s && s.parentNode) s.parentNode.removeChild(s);
}

async function renderHomeScreen() {
  hideBootSplash();
  const content = document.getElementById('homeScreen');
  const currentUserId = window._currentUser?.id || null;
  const cacheMatchesUser = window._cachedStatsUser && window._cachedStatsUser === currentUserId;

  // Once per session, opportunistically pull from Google Calendar / Sheets
  // if the user has them connected and the last pull is stale. Fire-and-
  // forget so it doesn't block Home render.
  if (typeof maybeBackgroundSync === 'function') maybeBackgroundSync();

  // Stale-while-revalidate: if ANY cached stats exist for this user, paint
  // them immediately so the home page never shows a skeleton after the very
  // first load, then ALWAYS refetch in the background. Gating the refetch on
  // STATS_CACHE_TTL left action chips (fees owed, unpaid invoices) frozen for
  // up to 5 minutes after the user had actually done the work. Repaint only
  // when the numbers changed so identical data never causes a visible swap.
  if (cacheMatchesUser && window._cachedStats) {
    buildHomeHTML(content, window._cachedStats);
    const painted = JSON.stringify(window._cachedStats);
    fetchStatsWithCache(true)
      .then((stats) => {
        // Only re-render if the user is still on Home and something changed
        if (currentScreen === 'home' && JSON.stringify(stats) !== painted) {
          buildHomeHTML(content, stats);
        }
      })
      .catch((err) => console.error('Background stats refresh failed:', err));
    return;
  }

  // No cache (first ever load, or freshly logged-in user) — show skeleton.
  content.innerHTML = buildSkeletonHTML();

  try {
    const stats = await fetchStatsWithCache(false);
    buildHomeHTML(content, stats);
  } catch (err) {
    console.error('Home screen error:', err);
    // S11-09: Give the user a way out. A retry button that re-fetches the
    // stats with the cache bypassed is far kinder than "Check your connection
    // and refresh" with no affordance.
    content.innerHTML = `
      <div style="padding:40px 20px;text-align:center;">
        <div style="font-size:32px;margin-bottom:8px;">&#9888;&#65039;</div>
        <div style="font-weight:600;color:var(--text);margin-bottom:4px;">Couldn&#x2019;t load home</div>
        <div style="font-size:13px;color:var(--text-2);margin-bottom:16px;">Check your connection and try again.</div>
        <button onclick="retryHomeScreen()" style="background:var(--accent);color:#000;border:none;border-radius:20px;padding:10px 20px;font-size:13px;font-weight:700;cursor:pointer;">Try again</button>
      </div>`;
  }
}

// S11-09: Companion helper for the retry button. Clears stale cache and
// re-renders the home screen from scratch.
function retryHomeScreen() {
  window._cachedStats = null;
  window._cachedStatsTime = 0;
  window._cachedStatsUser = null;
  renderHomeScreen();
}

// ── Home v2 ──────────────────────────────────────────────────────────────────
// Three regions only: hero (state-driven), needs-you alert strip (chips), and
// action grid (six tiles). Finance numbers and the 12-month chart now live in
// the Finance panel, accessible via the More tile + the Tax-year /
// Month-insight chips when relevant.
function buildHomeHTML(content, stats) {
  // Update notification dot in the fixed header (carried over from v1)
  const notifDot = document.getElementById('notificationDot');
  if (notifDot) notifDot.style.display = stats.unread_notifications > 0 ? 'block' : 'none';

  const state = determineHomeState(stats);

  let html = '<div style="padding:8px 0 16px;">';
  // On a gig day the tonight card is urgent, so it leads. Every other day the
  // vitals + week strip lead so the home reads as a dashboard rather than an
  // empty "nothing on" card.
  if (state.kind === 'day-of') {
    html += buildHomeHero(state, stats);
    html += buildHomeVitals(stats);
    html += buildHomeWeekStrip();
  } else {
    html += buildHomeVitals(stats);
    html += buildHomeWeekStrip();
    html += buildHomeHero(state, stats);
  }
  html += buildHomeNeedsStrip(stats, state);
  html += '<div id="homeSyncReviewSlot"></div>';
  html += '<div id="homeRebookSlot"></div>';
  html += '<div id="homeFollowupSlot"></div>';
  html += '<div id="homeSetupSlot"></div>';
  html += buildHomeActionGrid();
  html += '</div>';

  content.innerHTML = html;
  // The week strip is always in the DOM now, so hydrate its gig / blocked-day
  // dots on every render, not just the busy state.
  hydrateNext7DaysStrip();
  paintHomeSyncReviewCard();
  paintHomeRebookCard();
  paintHomeFollowupCard();
  paintHomeSetupCard(stats);
}

// ── Home sync-review card ────────────────────────────────────────────────────
// North star: after syncing a calendar, importing the real gigs should be the
// most obvious, fastest action in the app. Surfaces the calendar nudges
// ("this synced event looks like a gig") on Home with a one-tap-per-event
// review sheet, instead of leaving them buried in the Calendar tab.
async function paintHomeSyncReviewCard() {
  if (!document.getElementById('homeSyncReviewSlot')) return;
  let nudges = null;
  try { nudges = await loadCalendarNudges(); } catch (_) {}
  // Re-resolve after the await: the nudge fetch is a live Google round-trip,
  // and Home's stale-while-revalidate re-render can replace the DOM in the
  // meantime, leaving the pre-await node detached.
  const slot = document.getElementById('homeSyncReviewSlot');
  if (!slot) return;
  if (!Array.isArray(nudges) || nudges.length === 0) { slot.innerHTML = ''; return; }
  const n = nudges.length;
  slot.innerHTML = `
    <div onclick="openSyncReviewSheet()" style="margin:0 16px 12px;background:linear-gradient(135deg,rgba(240,165,0,.12),transparent);border:1px solid rgba(240,165,0,.4);border-radius:12px;padding:12px 14px;display:flex;align-items:center;gap:12px;cursor:pointer;">
      <span style="font-size:20px;flex-shrink:0;">🎵</span>
      <div style="flex:1;min-width:0;">
        <div style="font-size:13px;font-weight:700;color:var(--text);">${n} synced event${n === 1 ? ' looks' : 's look'} like gigs</div>
        <div style="font-size:11px;color:var(--text-2);margin-top:1px;">Import the real ones in one tap each</div>
      </div>
      <span style="background:var(--accent);color:#000;font-size:12px;font-weight:700;border-radius:999px;padding:7px 14px;flex-shrink:0;">Review</span>
    </div>`;
}

function openSyncReviewSheet() {
  const nudges = Array.isArray(window._calendarNudges) ? window._calendarNudges : [];
  if (nudges.length === 0) return;
  document.querySelectorAll('.sheet-overlay').forEach(o => o.remove());
  const overlay = document.createElement('div');
  overlay.className = 'sheet-overlay';
  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.55);z-index:99999;display:flex;align-items:flex-end;justify-content:center;';

  const rowHtml = (e) => {
    const times = [e.start_time, e.end_time].filter(Boolean).join(' – ');
    const feeBit = e.suggested_fee ? ` · ~£${e.suggested_fee}` : '';
    return `
      <div data-nudge-row="${escapeAttr(e.id)}" style="display:flex;align-items:center;gap:10px;padding:11px 12px;background:var(--card);border:1px solid var(--border);border-radius:12px;margin-bottom:8px;">
        <div style="flex:1;min-width:0;">
          <div style="font-size:13px;font-weight:600;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${escapeHtml(e.title || 'Untitled event')}</div>
          <div style="font-size:11px;color:var(--text-2);margin-top:1px;">${escapeHtml([e.date_formatted, times].filter(Boolean).join(' · '))}${feeBit}</div>
        </div>
        <button onclick="syncReviewAct('${escapeAttr(e.id)}', true)" title="Import as gig" style="width:36px;height:36px;border-radius:18px;background:var(--success);border:none;color:#000;font-size:15px;font-weight:700;cursor:pointer;flex-shrink:0;">✓</button>
        <button onclick="syncReviewAct('${escapeAttr(e.id)}', false)" title="Not a gig" style="width:36px;height:36px;border-radius:18px;background:var(--card);border:1px solid var(--border);color:var(--text-2);font-size:14px;cursor:pointer;flex-shrink:0;">✕</button>
      </div>`;
  };

  overlay.innerHTML = `
    <div style="background:var(--surface);border-top:1px solid var(--border);border-radius:16px 16px 0 0;padding:14px 16px 24px;width:100%;max-width:390px;max-height:80vh;overflow-y:auto;">
      <div style="width:36px;height:4px;background:var(--border);border-radius:2px;margin:0 auto 12px;"></div>
      <div style="display:flex;align-items:center;margin-bottom:4px;">
        <div style="font-size:12px;font-weight:700;color:var(--text-3);text-transform:uppercase;letter-spacing:.5px;flex:1;">Synced events to review</div>
        <div id="syncReviewCount" style="font-size:11px;color:var(--text-3);font-weight:700;">${nudges.length} left</div>
      </div>
      <div style="font-size:11px;color:var(--text-3);margin-bottom:12px;">✓ imports it as a gig · ✕ marks it not-a-gig (it stays a personal event)</div>
      <div id="syncReviewList">${nudges.map(rowHtml).join('')}</div>
      <button onclick="document.querySelectorAll('.sheet-overlay').forEach(o => o.remove());" style="width:100%;margin-top:6px;background:transparent;border:1px solid var(--border);color:var(--text-2);padding:11px;border-radius:12px;font-size:13px;font-weight:600;cursor:pointer;">Done for now</button>
    </div>`;
  overlay.addEventListener('click', (e) => { if (e.target === overlay) overlay.remove(); });
  document.body.appendChild(overlay);
}
window.openSyncReviewSheet = openSyncReviewSheet;

function syncReviewAct(eventId, isGig) {
  if (isGig) quickImportNudgeByEventId(eventId);
  else dismissNudgeByEventId(eventId);
  const row = document.querySelector(`[data-nudge-row="${CSS.escape(eventId)}"]`);
  if (row) row.remove();
  const left = document.querySelectorAll('#syncReviewList [data-nudge-row]').length;
  const counter = document.getElementById('syncReviewCount');
  if (counter) counter.textContent = `${left} left`;
  if (left === 0) {
    document.querySelectorAll('.sheet-overlay').forEach(o => o.remove());
    showToast('All reviewed 🎉');
  }
  paintHomeSyncReviewCard();
}
window.syncReviewAct = syncReviewAct;

// Zone label shared across the Home stack: same dot + uppercase grammar as
// the Gigs needs-attention groups, so every zone announces itself (Gareth
// 2026-07-02: a full home felt overwhelming without separation).
function _homeZoneLabel(text, color) {
  return `<div style="display:flex;align-items:center;gap:6px;margin:14px 16px 6px;font-size:10px;font-weight:800;letter-spacing:.8px;text-transform:uppercase;color:var(--text-3);"><span style="width:8px;height:8px;border-radius:2px;background:${color};flex-shrink:0;"></span>${text}</div>`;
}

// ── Home vitals row ──────────────────────────────────────────────────────────
// Three glanceable numbers at the top of Home: money booked this month, money
// awaiting payment, and gigs in the next 30 days. Money figures are confirmed
// only (month_earnings = confirmed gigs; unpaid_total = sent invoices), never
// forecasts. Each cell taps through to the relevant screen.
function buildHomeVitals(stats) {
  const fmtGBP = (n) => '£' + Math.round(Number(n) || 0).toLocaleString('en-GB');
  const owedTotal = Number(stats.unpaid_total) || 0;
  const owedCount = parseInt(stats.unpaid_invoices || 0, 10);
  const next30 = parseInt(stats.gigs_next_30_days || 0, 10);
  const monthName = new Date().toLocaleDateString('en-GB', { month: 'short' });
  const cell = (value, label, color, onclick) => `
    <div onclick="${onclick}" style="flex:1;min-width:0;background:var(--card);border:1px solid var(--border);border-radius:12px;padding:10px 11px;cursor:pointer;">
      <div style="font-size:18px;font-weight:800;line-height:1.1;color:${color};white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${value}</div>
      <div style="font-size:10px;color:var(--text-3);margin-top:3px;font-weight:600;">${label}</div>
    </div>`;
  return `
    ${_homeZoneLabel('At a glance', 'var(--accent)')}
    <div style="margin:0 16px 12px;display:flex;gap:8px;">
      ${cell(fmtGBP(stats.month_earnings), 'Booked · ' + monthName, 'var(--text)', "showScreen('money')")}
      ${cell(fmtGBP(owedTotal), owedCount > 0 ? 'Awaiting pay' : 'Nothing owed', owedTotal > 0 ? 'var(--danger)' : 'var(--text)', "showScreen('invoices')")}
      ${cell(String(next30), 'Gigs · 30d', 'var(--text)', "showScreen('gigs')")}
    </div>`;
}

// ── Home week strip ──────────────────────────────────────────────────────────
// A standalone 7-day strip (today + 6) rendered on every home state. Cells are
// hydrated by hydrateNext7DaysStrip() which paints a gig dot or blocked-day
// colour. Tapping a day opens that day's action sheet.
function buildHomeWeekStrip() {
  const today = new Date();
  const dows = ['S', 'M', 'T', 'W', 'T', 'F', 'S'];
  const cells = [];
  for (let i = 0; i < 7; i++) {
    const d = new Date(today.getFullYear(), today.getMonth(), today.getDate() + i);
    const iso = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
    const dow = dows[d.getDay()];
    const isToday = i === 0;
    cells.push(`<div data-next7-iso="${iso}" onclick="if (typeof openDayActionSheet === 'function') openDayActionSheet('${iso}'); else showScreen('calendar');" style="flex:1;min-width:0;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:3px;padding:7px 0;border-radius:9px;background:var(--card);border:1px solid var(--border);${isToday ? 'box-shadow:inset 0 0 0 1px var(--accent);' : ''}cursor:pointer;"><div style="font-size:9px;color:var(--text-3);font-weight:700;letter-spacing:.3px;">${dow}</div><div data-next7-num style="font-size:14px;font-weight:700;color:var(--text);">${d.getDate()}</div></div>`);
  }
  return `
    ${_homeZoneLabel('This week', 'var(--accent)')}
    <div style="margin:0 16px 12px;">
      <div id="next7DaysStrip" style="display:flex;gap:5px;">${cells.join('')}</div>
    </div>`;
}

// Returns the hero variant to render. Priority: day-of > busy > upcoming > quiet.
function determineHomeState(stats) {
  const next = stats.next_gig;
  if (!next) return { kind: 'quiet', daysUntil: null };

  const todayMid = new Date(); todayMid.setHours(0, 0, 0, 0);
  const gigMid = new Date(next.date); gigMid.setHours(0, 0, 0, 0);
  const daysUntil = Math.round((gigMid - todayMid) / 86400000);

  if (daysUntil <= 0) return { kind: 'day-of', gig: next };
  const next7Count = parseInt(stats.gigs_next_7_days || 0, 10);
  if (next7Count >= 2 && daysUntil <= 7) return { kind: 'busy', gig: next, count: next7Count };
  if (daysUntil <= 14) return { kind: 'upcoming', gig: next, daysUntil };
  return { kind: 'quiet', daysUntil, gig: next };
}

function buildHomeHero(state) {
  if (state.kind === 'day-of')   return buildHomeHeroDayOf(state.gig);
  if (state.kind === 'busy')     return buildHomeHeroBusy(state.gig, state.count);
  if (state.kind === 'upcoming') return buildHomeHeroUpcoming(state.gig, state.daysUntil);
  return buildHomeHeroQuiet(state.daysUntil, state.gig);
}

// ── Hero: Day of gig ─────────────────────────────────────────────────────────
function buildHomeHeroDayOf(gig) {
  // Countdown to load-in (fallback to start_time if load-in not set)
  const targetTime = gig.load_in_time || gig.start_time;
  let countdownLabel = '';
  if (targetTime) {
    const parts = String(targetTime).split(':');
    const target = new Date();
    target.setHours(parseInt(parts[0], 10) || 0, parseInt(parts[1], 10) || 0, 0, 0);
    const diffMs = target - new Date();
    if (diffMs > 0) {
      const totalMin = Math.round(diffMs / 60000);
      const h = Math.floor(totalMin / 60);
      const m = totalMin % 60;
      const prefix = gig.load_in_time ? 'Load-in in ' : 'Set 1 in ';
      countdownLabel = prefix + (h > 0 ? h + 'h ' : '') + m + 'm';
    } else {
      countdownLabel = gig.load_in_time ? 'Load-in time passed' : 'Gig in progress';
    }
  }

  // Maps URL: prefer lat/lng for precision, fall back to encoded address/name.
  // Google Maps universal link works on iOS, Android, and desktop.
  let mapsUrl = '';
  if (gig.venue_lat != null && gig.venue_lng != null) {
    mapsUrl = 'https://www.google.com/maps/search/?api=1&query=' + gig.venue_lat + ',' + gig.venue_lng;
  } else if (gig.venue_address) {
    mapsUrl = 'https://www.google.com/maps/search/?api=1&query=' + encodeURIComponent(gig.venue_address);
  } else if (gig.venue_name) {
    mapsUrl = 'https://www.google.com/maps/search/?api=1&query=' + encodeURIComponent(gig.venue_name);
  }

  // Gig leader action: prefer phone (tel:), then email (mailto:), then detail.
  let leaderOnclick = "openGigDetail('" + escapeAttr(gig.id) + "')";
  if (gig.gig_leader_phone) {
    const tel = String(gig.gig_leader_phone).replace(/\s+/g, '');
    leaderOnclick = "window.location.href='tel:" + escapeAttr(tel) + "'";
  } else if (gig.gig_leader_email) {
    leaderOnclick = "window.location.href='mailto:" + escapeAttr(gig.gig_leader_email) + "'";
  }

  // First two set times if defined
  let setTimes = [];
  try {
    const raw = gig.set_times;
    const sets = Array.isArray(raw) ? raw : (raw ? JSON.parse(raw) : []);
    setTimes = (sets || []).slice(0, 2).map((s, i) => ({
      label: s.name || s.label || ('Set ' + (i + 1)),
      val: (s.start && s.end) ? (formatTime(s.start) + ' — ' + formatTime(s.end)) : (s.time || s.start || ''),
    }));
  } catch (_) {}

  const hasTimesRow = setTimes.length > 0 || gig.load_in_time;
  const timesRowHtml = hasTimesRow
    ? `<div style="display:flex;gap:12px;padding:10px 0;border-top:1px solid rgba(63,185,80,.18);border-bottom:1px solid rgba(63,185,80,.18);margin-bottom:12px;">
        ${gig.load_in_time ? `<div style="flex:1;"><div style="font-size:9px;font-weight:700;color:var(--text-3);text-transform:uppercase;letter-spacing:.7px;margin-bottom:3px;">Load-in</div><div style="font-size:13px;font-weight:700;color:var(--text);">${formatTime(gig.load_in_time)}</div></div>` : ''}
        ${setTimes.map(t => `<div style="flex:1;min-width:0;"><div style="font-size:9px;font-weight:700;color:var(--text-3);text-transform:uppercase;letter-spacing:.7px;margin-bottom:3px;">${escapeHtml(t.label)}</div><div style="font-size:12px;font-weight:700;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${escapeHtml(t.val || '')}</div></div>`).join('')}
      </div>`
    : '<div style="height:6px;"></div>';

  const whereLine = [gig.venue_address, gig.venue_postcode].filter(Boolean).map(escapeHtml).join(' · ');

  return `
    <div onclick="openGigDetail('${escapeAttr(gig.id)}')" style="margin:0 16px 10px;background:linear-gradient(160deg,#1F2A18 0%,#16210F 60%,#0F1C16 100%);border:1px solid rgba(63,185,80,.45);border-radius:14px;padding:16px;cursor:pointer;">
      <div style="display:flex;align-items:center;">
        <div style="display:inline-flex;align-items:center;gap:6px;background:rgba(63,185,80,.18);color:var(--success);font-size:10px;font-weight:800;letter-spacing:1.2px;padding:4px 9px;border-radius:999px;text-transform:uppercase;">
          <span style="width:6px;height:6px;border-radius:50%;background:var(--success);box-shadow:0 0 8px var(--success);"></span>
          Tonight · Live
        </div>
        ${countdownLabel ? `<div style="margin-left:auto;font-size:12px;font-weight:700;color:var(--success);letter-spacing:.3px;">${escapeHtml(countdownLabel)}</div>` : ''}
      </div>
      <div style="font-size:22px;font-weight:800;color:var(--text);margin:10px 0 2px;letter-spacing:-.4px;line-height:1.15;">${escapeHtml(gig.venue_name || gig.band_name || 'Untitled gig')}</div>
      ${whereLine ? `<div style="font-size:12px;color:var(--text-2);margin-bottom:12px;">📍 ${whereLine}</div>` : '<div style="height:12px;"></div>'}
      ${timesRowHtml}
      <div style="display:flex;gap:6px;">
        ${mapsUrl
          ? `<a href="${escapeAttr(mapsUrl)}" target="_blank" rel="noopener" onclick="event.stopPropagation();" style="flex:1;background:rgba(63,185,80,.14);border:1px solid rgba(63,185,80,.32);color:var(--text);padding:10px 6px;font-size:11px;font-weight:700;border-radius:10px;display:flex;flex-direction:column;align-items:center;gap:3px;cursor:pointer;text-decoration:none;"><span style="font-size:16px;">🧭</span>Navigate</a>`
          : `<button style="flex:1;background:rgba(63,185,80,.06);border:1px solid rgba(63,185,80,.18);color:var(--text-3);padding:10px 6px;font-size:11px;font-weight:700;border-radius:10px;display:flex;flex-direction:column;align-items:center;gap:3px;cursor:not-allowed;" disabled><span style="font-size:16px;">🧭</span>Navigate</button>`}
        <button onclick="event.stopPropagation(); openGigDetail('${escapeAttr(gig.id)}');" style="flex:1;background:rgba(63,185,80,.14);border:1px solid rgba(63,185,80,.32);color:var(--text);padding:10px 6px;font-size:11px;font-weight:700;border-radius:10px;display:flex;flex-direction:column;align-items:center;gap:3px;cursor:pointer;"><span style="font-size:16px;">🎵</span>Setlist</button>
        <button onclick="event.stopPropagation(); ${leaderOnclick};" style="flex:1;background:rgba(63,185,80,.14);border:1px solid rgba(63,185,80,.32);color:var(--text);padding:10px 6px;font-size:11px;font-weight:700;border-radius:10px;display:flex;flex-direction:column;align-items:center;gap:3px;cursor:pointer;"><span style="font-size:16px;">📞</span>Gig leader</button>
      </div>
    </div>`;
}

// ── Hero: Upcoming (single gig within 14 days) ───────────────────────────────
function buildHomeHeroUpcoming(gig, daysUntil) {
  const feeLine = (gig.fee != null && gig.fee !== '')
    ? ` · <span style="color:var(--success);font-weight:700;">£${escapeHtml(String(gig.fee))}</span>`
    : '';
  const timesPart = gig.start_time
    ? formatTime(gig.start_time) + (gig.end_time ? ' — ' + formatTime(gig.end_time) : '')
    : '';
  return `
    <div onclick="openGigDetail('${escapeAttr(gig.id)}')" style="margin:0 16px 10px;background:linear-gradient(160deg,#1C2A1A 0%,#182318 100%);border:1px solid rgba(63,185,80,.3);border-radius:14px;padding:14px 16px;cursor:pointer;">
      <div style="display:flex;align-items:center;gap:8px;margin-bottom:8px;">
        <span style="font-size:10px;font-weight:700;color:var(--success);letter-spacing:1.2px;text-transform:uppercase;">⚡ Your next gig</span>
        <span style="margin-left:auto;background:rgba(63,185,80,.18);color:var(--success);font-size:11px;font-weight:800;padding:3px 8px;border-radius:999px;">${daysUntil === 1 ? '1 day' : daysUntil + ' days'}</span>
      </div>
      <div style="font-size:17px;font-weight:800;color:var(--text);letter-spacing:-.3px;margin-bottom:3px;">${escapeHtml(gig.band_name || gig.venue_name || 'Untitled gig')}</div>
      <div style="font-size:12px;color:var(--text-2);line-height:1.5;">
        ${gig.venue_name ? `📍 ${escapeHtml(gig.venue_name)}<br>` : ''}
        🕖 ${formatDateLong(gig.date)}${timesPart ? ' · ' + timesPart : ''}${feeLine}
        ${gig.dress_code ? `<br>👔 ${escapeHtml(gig.dress_code)}` : ''}
      </div>
    </div>`;
}

// ── Hero: Busy week (2+ gigs in next 7 days) ─────────────────────────────────
function buildHomeHeroBusy(gig, count) {
  const timesPart = gig.start_time
    ? ' · ' + formatTime(gig.start_time) + (gig.end_time ? ' — ' + formatTime(gig.end_time) : '')
    : '';
  const feeLine = (gig.fee != null && gig.fee !== '')
    ? ` · £${escapeHtml(String(gig.fee))}`
    : '';

  return `
    <div onclick="openGigDetail('${escapeAttr(gig.id)}')" style="margin:0 16px 10px;background:linear-gradient(160deg,#1C2A1A 0%,#182318 100%);border:1px solid rgba(63,185,80,.3);border-radius:14px;padding:14px 16px;cursor:pointer;">
      <div style="display:flex;align-items:center;gap:10px;">
        <div style="width:3px;height:36px;border-radius:2px;background:var(--success);flex-shrink:0;"></div>
        <div style="flex:1;min-width:0;">
          <div style="font-size:14px;font-weight:700;color:var(--text);">${escapeHtml(gig.band_name || gig.venue_name || 'Next gig')}</div>
          <div style="font-size:11px;color:var(--text-2);margin-top:1px;">${formatDateLong(gig.date)}${timesPart}${feeLine}</div>
        </div>
        <div style="background:rgba(63,185,80,.18);color:var(--success);font-size:10px;font-weight:800;padding:4px 8px;border-radius:999px;flex-shrink:0;">${count} this week</div>
      </div>
    </div>`;
}

// ── Hero: Quiet day (no gig within 14 days) ──────────────────────────────────
// Two variants: with a far-out next gig, lead with that gig (function players
// book months ahead; "Nothing on for 73 days" reads as "you have no work" and
// contradicts the vitals row). Only a truly empty diary gets the empty state.
function buildHomeHeroQuiet(daysUntil, gig) {
  if (gig && daysUntil != null && daysUntil > 0) {
    const feePart = (gig.fee != null && gig.fee !== '')
      ? ` · <span style="color:var(--success);font-weight:700;">£${escapeHtml(String(gig.fee))}</span>`
      : '';
    return `
      <div style="margin:0 16px 10px;background:var(--card);border:1px solid var(--border);border-radius:14px;padding:14px 16px;">
        <div style="display:flex;align-items:center;gap:8px;margin-bottom:10px;">
          <span style="font-size:10px;font-weight:700;color:var(--text-3);letter-spacing:1.2px;text-transform:uppercase;">Next gig</span>
          <span style="margin-left:auto;background:var(--accent-dim);color:var(--accent);font-size:11px;font-weight:800;padding:3px 8px;border-radius:999px;">in ${daysUntil} day${daysUntil === 1 ? '' : 's'}</span>
        </div>
        <div onclick="openGigDetail('${escapeAttr(gig.id)}')" style="display:flex;align-items:center;gap:10px;background:var(--bg);border:1px solid var(--border);border-radius:10px;padding:10px 12px;cursor:pointer;">
          <div style="width:3px;height:32px;border-radius:2px;background:var(--success);flex-shrink:0;"></div>
          <div style="flex:1;min-width:0;">
            <div style="font-size:14px;font-weight:700;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${escapeHtml(gig.band_name || gig.venue_name || 'Next gig')}</div>
            <div style="font-size:11px;color:var(--text-2);margin-top:1px;">${formatDateLong(gig.date)}${feePart}</div>
          </div>
          <span style="color:var(--text-3);font-size:16px;flex-shrink:0;">›</span>
        </div>
        <div style="display:flex;align-items:center;gap:8px;margin-top:10px;">
          <div style="flex:1;font-size:11px;color:var(--text-3);">Quiet until then. Fill the gap?</div>
          <button onclick="openQuickLogSheet()" style="background:var(--accent);color:#000;border:none;font-size:12px;font-weight:700;padding:8px 16px;border-radius:999px;cursor:pointer;">+ Log a gig</button>
        </div>
      </div>`;
  }
  return `
    <div style="margin:0 16px 10px;background:var(--card);border:1px dashed var(--border);border-radius:14px;padding:18px 16px;text-align:center;">
      <div style="font-size:28px;margin-bottom:8px;">🎷</div>
      <div style="font-size:15px;font-weight:700;color:var(--text);margin-bottom:4px;">No gigs scheduled</div>
      <div style="font-size:12px;color:var(--text-2);margin-bottom:12px;">Diary's clear. Log your next gig to get it on the board.</div>
      <button onclick="openQuickLogSheet()" style="background:var(--accent);color:#000;border:none;font-size:12px;font-weight:700;padding:9px 18px;border-radius:999px;cursor:pointer;">+ Log a gig</button>
    </div>`;
}

// ── Needs you alert strip ────────────────────────────────────────────────────
// Compressed chip row replacing the v1 banners (overdue, draft, offers, dep,
// messages, missing-fee). Hidden when there's nothing to nag. On quiet days
// with no alerts, render a soft "all clear" line so the gap doesn't feel empty.
//
// Tap behaviour: the WHOLE row is one tap target. Hitting it opens the
// Needs you bottom sheet where each item is a full-width row with a
// comfortable 50px tap area. Individual chips inside the row are visual
// only (no per-chip click) so a thumb on phone never has to thread
// between adjacent chips. The chip strip earns its keep as a glance
// surface; the sheet is the precision surface.
function buildHomeNeedsStrip(stats, state) {
  const chips = [];
  if (stats.share_enquiries > 0) {
    chips.push(`<span style="display:inline-flex;align-items:center;gap:4px;font-size:11px;font-weight:700;padding:4px 9px;border-radius:999px;background:var(--success-dim, rgba(63,185,80,.15));color:var(--success);border:1px solid rgba(63,185,80,.3);"><span style="font-size:10px;">🎉</span>${stats.share_enquiries} booking enquir${stats.share_enquiries === 1 ? 'y' : 'ies'}</span>`);
  }
  if (stats.overdue_invoices > 0) {
    chips.push(`<span style="display:inline-flex;align-items:center;gap:4px;font-size:11px;font-weight:700;padding:4px 9px;border-radius:999px;background:var(--danger-dim);color:var(--danger);border:1px solid rgba(248,81,73,.3);"><span style="font-size:10px;">⚠</span>${stats.overdue_invoices} overdue</span>`);
  }
  if (stats.draft_invoices > 0) {
    chips.push(`<span style="display:inline-flex;align-items:center;gap:4px;font-size:11px;font-weight:700;padding:4px 9px;border-radius:999px;background:var(--info-dim);color:var(--info);border:1px solid rgba(88,166,255,.3);"><span style="font-size:10px;">📄</span>${stats.draft_invoices} draft${stats.draft_invoices === 1 ? '' : 's'}</span>`);
  }
  if (stats.offer_count > 0) {
    chips.push(`<span style="display:inline-flex;align-items:center;gap:4px;font-size:11px;font-weight:700;padding:4px 9px;border-radius:999px;background:var(--accent-dim);color:var(--accent);border:1px solid rgba(240,165,0,.35);"><span style="font-size:10px;">📬</span>${stats.offer_count} offer${stats.offer_count === 1 ? '' : 's'}</span>`);
  }
  if (stats.active_dep_request) {
    chips.push(`<span style="display:inline-flex;align-items:center;gap:4px;font-size:11px;font-weight:700;padding:4px 9px;border-radius:999px;background:rgba(167,139,250,.16);color:#C7B5FA;border:1px solid rgba(167,139,250,.35);"><span style="font-size:10px;">📤</span>1 dep awaiting cover</span>`);
  }
  if (stats.unread_messages > 0) {
    chips.push(`<span style="display:inline-flex;align-items:center;gap:4px;font-size:11px;font-weight:700;padding:4px 9px;border-radius:999px;background:var(--info-dim);color:var(--info);border:1px solid rgba(88,166,255,.3);"><span style="font-size:10px;">💬</span>${stats.unread_messages} message${stats.unread_messages === 1 ? '' : 's'}</span>`);
  }
  if (stats.gigs_missing_fee > 0) {
    chips.push(`<span style="display:inline-flex;align-items:center;gap:4px;font-size:11px;font-weight:700;padding:4px 9px;border-radius:999px;background:var(--accent-dim);color:var(--accent);border:1px solid rgba(240,165,0,.35);"><span style="font-size:10px;">💷</span>${stats.gigs_missing_fee} need fee${stats.gigs_missing_fee === 1 ? '' : 's'}</span>`);
  }

  if (chips.length === 0) return '';

  return `
    <div onclick="openNeedsYouSheet()" style="margin:0 16px 12px;background:var(--card);background:color-mix(in srgb, var(--accent) 6%, var(--card));border:1px solid var(--border);border:1px solid color-mix(in srgb, var(--accent) 28%, transparent);border-radius:10px;padding:10px 12px;display:flex;align-items:center;gap:8px;cursor:pointer;">
      <div style="font-size:10px;font-weight:700;color:var(--text-3);letter-spacing:.8px;text-transform:uppercase;flex-shrink:0;">Needs you</div>
      <div style="display:flex;gap:6px;flex-wrap:wrap;flex:1;">${chips.join('')}</div>
      <span style="color:var(--text-3);font-size:16px;flex-shrink:0;">›</span>
    </div>`;
}

// Open the "Needs you" bottom sheet. Reads window._cachedStats (same source
// the chip strip rendered from) and lists each active alert as a full-width
// row with a comfortable tap target. Tapping a row closes the sheet and
// jumps to the destination the chip would have. Defensive: if the cache
// isn't populated yet, falls back to closing silently rather than rendering
// an empty sheet.
function openNeedsYouSheet() {
  const stats = window._cachedStats;
  if (!stats) return;
  const items = [];
  const fmt = (n) => Math.round(Number(n) || 0).toLocaleString('en-GB');

  if (stats.share_enquiries > 0) {
    items.push({
      ico: '🎉',
      color: 'var(--success)',
      bg: 'var(--success-dim, rgba(63,185,80,.15))',
      label: `${stats.share_enquiries} booking enquir${stats.share_enquiries === 1 ? 'y' : 'ies'} from your page`,
      meta: 'Reply fast, win the gig',
      onclick: "showScreen('gigs')",
    });
  }
  if (stats.overdue_invoices > 0) {
    items.push({
      ico: '⚠',
      color: 'var(--danger)',
      bg: 'var(--danger-dim)',
      label: `${stats.overdue_invoices} overdue invoice${stats.overdue_invoices === 1 ? '' : 's'}`,
      meta: stats.overdue_total ? `£${fmt(stats.overdue_total)}` : '',
      onclick: "goToInvoicesFiltered('overdue')",
    });
  }
  if (stats.draft_invoices > 0) {
    items.push({
      ico: '📄',
      color: 'var(--info)',
      bg: 'var(--info-dim)',
      label: `${stats.draft_invoices} draft invoice${stats.draft_invoices === 1 ? '' : 's'}`,
      meta: stats.draft_total ? `£${fmt(stats.draft_total)}` : '',
      onclick: "goToInvoicesFiltered('draft')",
    });
  }
  if (stats.offer_count > 0) {
    items.push({
      ico: '📬',
      color: 'var(--accent)',
      bg: 'var(--accent-dim)',
      label: `${stats.offer_count} gig offer${stats.offer_count === 1 ? '' : 's'}`,
      meta: stats.network_offers > 0 ? `${stats.network_offers} from your network` : '',
      onclick: "showScreen('offers')",
    });
  }
  if (stats.active_dep_request) {
    const dep = stats.active_dep_request || {};
    const hours = dep.hours_left;
    const meta = hours == null ? ''
      : hours > 48 ? `${Math.ceil(hours / 24)}d left`
      : `${hours}h left`;
    items.push({
      ico: '📤',
      color: '#C7B5FA',
      bg: 'rgba(167,139,250,.16)',
      label: `1 dep awaiting cover`,
      sub: dep.band_name ? `${escapeHtml(dep.band_name)}${dep.venue_name ? ' · ' + escapeHtml(dep.venue_name) : ''}` : '',
      meta,
      onclick: "showScreen('offers')",
    });
  }
  if (stats.unread_messages > 0) {
    items.push({
      ico: '💬',
      color: 'var(--info)',
      bg: 'var(--info-dim)',
      label: `${stats.unread_messages} unread message${stats.unread_messages === 1 ? '' : 's'}`,
      meta: '',
      onclick: "openPanel('panel-chat-inbox'); if (typeof renderChatInbox === 'function') renderChatInbox();",
    });
  }
  if (stats.gigs_missing_fee > 0) {
    items.push({
      ico: '💷',
      color: 'var(--accent)',
      bg: 'var(--accent-dim)',
      label: `${stats.gigs_missing_fee} gig${stats.gigs_missing_fee === 1 ? '' : 's'} missing a fee`,
      meta: 'For tax reporting',
      onclick: "if (window.openFeeReviewWizard) window.openFeeReviewWizard();",
    });
  }

  if (items.length === 0) return;

  const overlay = document.createElement('div');
  overlay.className = 'sheet-overlay';
  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.55);z-index:99999;display:flex;align-items:flex-end;justify-content:center;';

  const rowsHtml = items.map((it) => {
    const subLine = it.sub ? `<div style="font-size:11px;color:var(--text-3);margin-top:2px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${it.sub}</div>` : '';
    const metaLine = it.meta ? `<div style="font-size:11px;color:${it.color};font-weight:700;flex-shrink:0;margin-right:8px;">${escapeHtml(it.meta)}</div>` : '';
    return `
      <div onclick="document.querySelectorAll('.sheet-overlay').forEach(o => o.remove()); ${it.onclick}" style="display:flex;align-items:center;gap:12px;padding:14px 12px;background:var(--card);border:1px solid var(--border);border-radius:12px;margin-bottom:8px;cursor:pointer;min-height:50px;">
        <div style="width:36px;height:36px;border-radius:10px;background:${it.bg};display:flex;align-items:center;justify-content:center;font-size:18px;color:${it.color};flex-shrink:0;">${it.ico}</div>
        <div style="flex:1;min-width:0;">
          <div style="font-size:14px;font-weight:600;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${escapeHtml(it.label)}</div>
          ${subLine}
        </div>
        ${metaLine}
        <span style="color:var(--text-3);font-size:16px;flex-shrink:0;">›</span>
      </div>`;
  }).join('');

  overlay.innerHTML = `
    <div style="background:var(--surface);border-top:1px solid var(--border);border-radius:16px 16px 0 0;padding:14px 16px 24px;width:100%;max-width:390px;max-height:80vh;overflow-y:auto;">
      <div style="width:36px;height:4px;background:var(--border);border-radius:2px;margin:0 auto 12px;"></div>
      <div style="font-size:12px;font-weight:700;color:var(--text-3);text-transform:uppercase;letter-spacing:.5px;margin-bottom:12px;">Needs you</div>
      ${rowsHtml}
      <button onclick="document.querySelectorAll('.sheet-overlay').forEach(o => o.remove());" style="width:100%;margin-top:6px;background:transparent;border:1px solid var(--border);color:var(--text-2);padding:11px;border-radius:12px;font-size:13px;font-weight:600;cursor:pointer;">Close</button>
    </div>`;

  overlay.addEventListener('click', (e) => { if (e.target === overlay) overlay.remove(); });
  document.body.appendChild(overlay);
}
window.openNeedsYouSheet = openNeedsYouSheet;

