// ── Nav reorder: long-press any nav button to enter wiggle/reorder mode ──────
(function setupNavReorder() {
  let longPressTimer = null;
  let reorderMode = false;
  let dragItem = null;

  function allNavItems() {
    return document.querySelectorAll('.nav-main .nav-item');
  }

  // Attach long-press listeners
  allNavItems().forEach(function (item) {
    item.addEventListener('touchstart', function () {
      if (reorderMode) return;
      longPressTimer = setTimeout(function () { enterReorderMode(item); }, 600);
    }, { passive: true });
    item.addEventListener('touchend', function () { clearTimeout(longPressTimer); });
    item.addEventListener('touchmove', function () { clearTimeout(longPressTimer); });
    item.addEventListener('mousedown', function () {
      if (reorderMode) return;
      longPressTimer = setTimeout(function () { enterReorderMode(item); }, 600);
    });
    item.addEventListener('mouseup', function () { clearTimeout(longPressTimer); });
    item.addEventListener('mouseleave', function () { clearTimeout(longPressTimer); });
  });

  function enterReorderMode(item) {
    reorderMode = true;
    allNavItems().forEach(function (ni) {
      ni.style.animation = 'wiggle .3s ease-in-out infinite alternate';
      ni.style.opacity = '.85';
      ni.setAttribute('draggable', 'true');
      ni.addEventListener('dragstart', onDragStart);
      ni.addEventListener('dragover', onDragOver);
      ni.addEventListener('drop', onDrop);
      ni.addEventListener('dragend', onDragEnd);
    });
    item.style.opacity = '1';
    item.style.transform = 'scale(1.15)';
    dragItem = item;

    // Show Done button
    const nav = document.querySelector('.app-nav');
    const exitBtn = document.createElement('div');
    exitBtn.id = 'reorder-exit';
    exitBtn.textContent = '\u2713 Done reordering';
    exitBtn.style.cssText = 'position:absolute;top:-30px;left:50%;transform:translateX(-50%);background:var(--accent);color:#000;font-size:11px;font-weight:700;padding:5px 16px;border-radius:12px;cursor:pointer;z-index:20;white-space:nowrap;box-shadow:0 2px 8px rgba(0,0,0,.3);';
    exitBtn.onclick = exitReorderMode;
    nav.style.position = 'relative';
    nav.appendChild(exitBtn);
  }

  function exitReorderMode() {
    reorderMode = false;
    allNavItems().forEach(function (ni) {
      ni.style.animation = '';
      ni.style.opacity = '';
      ni.style.transform = '';
      ni.removeAttribute('draggable');
      ni.removeEventListener('dragstart', onDragStart);
      ni.removeEventListener('dragover', onDragOver);
      ni.removeEventListener('drop', onDrop);
      ni.removeEventListener('dragend', onDragEnd);
    });
    const exit = document.getElementById('reorder-exit');
    if (exit) exit.remove();
    dragItem = null;
  }

  function onDragStart(e) {
    dragItem = this;
    this.style.opacity = '.4';
    e.dataTransfer.effectAllowed = 'move';
  }

  function onDragOver(e) {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
    this.style.transform = 'scale(1.1)';
  }

  function onDrop(e) {
    e.preventDefault();
    // Swap only within the same row
    if (dragItem !== this && dragItem.parentElement === this.parentElement) {
      const parent = this.parentElement;
      const items = Array.from(parent.children);
      const fromIdx = items.indexOf(dragItem);
      const toIdx = items.indexOf(this);
      if (fromIdx < toIdx) {
        parent.insertBefore(dragItem, this.nextSibling);
      } else {
        parent.insertBefore(dragItem, this);
      }
    }
    this.style.transform = '';
  }

  function onDragEnd() {
    allNavItems().forEach(function (ni) {
      ni.style.opacity = '.85';
      ni.style.transform = '';
    });
    if (dragItem) dragItem.style.opacity = '.85';
  }
})();

if ('serviceWorker' in navigator) {
  // Force-update: unregister any old service workers, then re-register
  // This guarantees the new network-first SW replaces any stale cache-first one
  navigator.serviceWorker.getRegistrations().then((registrations) => {
    const reRegister = () => {
      navigator.serviceWorker.register('/sw.js').catch((err) => {
        console.log('ServiceWorker registration failed:', err);
      });
    };
    if (registrations.length > 0) {
      Promise.all(registrations.map((r) => r.unregister())).then(reRegister);
    } else {
      reRegister();
    }
  });
}

// ── CSV Export ───────────────────────────────────────────────────────────────
// Escapes a value for a CSV cell: wraps in quotes, doubles internal quotes, strips newlines
function _csvCell(v) {
  if (v === null || v === undefined) return '';
  const s = String(v).replace(/\r?\n/g, ' ');
  if (s.includes(',') || s.includes('"')) return '"' + s.replace(/"/g, '""') + '"';
  return s;
}

function _downloadCSV(filename, rows) {
  const csv = rows.map(r => r.map(_csvCell).join(',')).join('\r\n');
  const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  setTimeout(() => URL.revokeObjectURL(url), 1000);
}

async function exportGigsCSV() {
  try {
    const res = await fetch('/api/gigs');
    if (!res.ok) throw new Error('Failed to fetch gigs');
    const gigs = await res.json();
    if (!gigs.length) { showToast('No gigs to export yet'); return; }

    const header = ['Date', 'Time', 'Venue', 'Address', 'Act', 'Gig type', 'Fee', 'Status', 'Paid', 'Invoiced', 'Notes'];
    const rows = [header];
    gigs.forEach(g => {
      const fee = parseFloat(g.fee || 0) || 0;
      const paid = parseFloat(g.paid_so_far || 0) || 0;
      const paidCol = (fee > 0 && paid + 0.005 >= fee) ? 'Yes' : (paid > 0 ? 'Partial' : 'No');
      rows.push([
        (g.date || '').slice(0, 10),
        g.start_time || '',
        g.venue_name || '',
        g.venue_address || '',
        g.act_name || g.band_name || '',
        g.gig_type || '',
        g.fee || '',
        g.status || '',
        paidCol,
        g.has_invoice ? 'Yes' : 'No',
        g.notes || '',
      ]);
    });

    const today = new Date().toISOString().slice(0, 10);
    _downloadCSV(`trackmygigs-gigs-${today}.csv`, rows);
    showToast(`Exported ${gigs.length} gigs`);
  } catch (err) {
    console.error('Export gigs CSV error:', err);
    showToast('Failed to export gigs');
  }
}
window.exportGigsCSV = exportGigsCSV;

async function exportExpensesCSV() {
  try {
    const res = await fetch('/api/expenses');
    if (!res.ok) throw new Error('Failed to fetch expenses');
    const data = await res.json();
    const expenses = Array.isArray(data) ? data : (data.expenses || []);
    if (!expenses.length) { showToast('No expenses to export yet'); return; }

    const header = ['Date', 'Description', 'Category', 'Amount (GBP)'];
    const rows = [header];
    expenses.forEach(e => {
      rows.push([
        (e.date || '').slice(0, 10),
        e.description || '',
        e.category || '',
        parseFloat(e.amount || 0).toFixed(2),
      ]);
    });

    const today = new Date().toISOString().slice(0, 10);
    _downloadCSV(`trackmygigs-expenses-${today}.csv`, rows);
    showToast(`Exported ${expenses.length} expenses`);
  } catch (err) {
    console.error('Export expenses CSV error:', err);
    showToast('Failed to export expenses');
  }
}
window.exportExpensesCSV = exportExpensesCSV;

// ── PDF EXPORT (browser-native Save as PDF) ─────────────────────────────────
// The server returns a printable HTML page that auto-triggers window.print() on
// load. The user saves as PDF from the browser's print dialog. Zero-dependency.

function exportGigsPDF() {
  // New tab so auth cookies are carried over; the server route is behind authMiddleware.
  window.open('/api/print/gigs', '_blank', 'noopener');
}
window.exportGigsPDF = exportGigsPDF;

function exportFinancePDF() {
  window.open('/api/print/finance', '_blank', 'noopener');
}
window.exportFinancePDF = exportFinancePDF;

// ── ONBOARDING TOUR ─────────────────────────────────────────────────────────
// A simple first-run welcome shown once (gated by users.onboarded_at).
// Fires after prefetchAllData settles so we have the profile to check.

// S10-06: the old onboarding was five info-only slides. The user landed on a
// blank home screen with no act name, no postcode, no instruments, and no
// idea that their public EPK would just show the email local-part. Two of
// the slides are now forms whose values are POSTed to /api/user/profile so
// the first-run experience actually seeds the minimum profile the rest of
// the app depends on.
const ONBOARDING_STEPS = [
  {
    kind: 'info',
    emoji: '🎵',
    title: 'Welcome to TrackMyGigs',
    body: "Your home for every gig, invoice, expense and mile. Let's set up the basics in 30 seconds.",
    cta: 'Get started',
  },
  {
    kind: 'form',
    id: 'profile-basics',
    livesIn: 'Profile › Edit profile',
    emoji: '👋',
    title: 'What should we call you?',
    render: (profile) => `
      <div style="text-align:left;margin-bottom:14px;">
        <label style="font-size:11px;font-weight:600;color:var(--text-2);text-transform:uppercase;letter-spacing:1px;display:block;margin-bottom:4px;">Name or act name</label>
        <input id="onbName" type="text" value="${escapeHtml(profile.display_name || profile.name || '')}" placeholder="Your name or band/act" style="width:100%;padding:12px;background:var(--bg);border:1px solid var(--border);border-radius:8px;color:var(--text);font-size:14px;box-sizing:border-box;">
      </div>
      <div style="text-align:left;margin-bottom:4px;">
        <label style="font-size:11px;font-weight:600;color:var(--text-2);text-transform:uppercase;letter-spacing:1px;display:block;margin-bottom:4px;">Home postcode</label>
        <input id="onbPostcode" type="text" value="${escapeHtml(profile.home_postcode || profile.postcode || '')}" placeholder="e.g. SE1 9SG" style="width:100%;padding:12px;background:var(--bg);border:1px solid var(--border);border-radius:8px;color:var(--text);font-size:14px;box-sizing:border-box;text-transform:uppercase;">
        <div style="font-size:11px;color:var(--text-3);margin-top:4px;">Used for mileage claims and travel-time estimates. Never shared.</div>
      </div>`,
    collect: () => {
      const name = (document.getElementById('onbName')?.value || '').trim();
      const postcode = (document.getElementById('onbPostcode')?.value || '').trim().toUpperCase();
      const body = {};
      if (name) { body.display_name = name; body.name = name; }
      if (postcode) body.home_postcode = postcode;
      return body;
    },
    cta: 'Next',
  },
  {
    kind: 'form',
    id: 'profile-music',
    livesIn: 'Profile › Edit profile',
    emoji: '🎸',
    title: 'What do you play?',
    render: (profile) => {
      const current = Array.isArray(profile.instruments)
        ? profile.instruments
        : (typeof profile.instruments === 'string'
            ? profile.instruments.replace(/[{}]/g, '').split(',').map(s => s.trim()).filter(Boolean)
            : []);
      const options = ['Vocals', 'Guitar', 'Bass', 'Drums', 'Keys', 'Sax', 'Trumpet', 'Violin', 'DJ'];
      const chips = options.map(opt => {
        const active = current.map(c => c.toLowerCase()).includes(opt.toLowerCase());
        return `<label style="display:inline-flex;align-items:center;gap:6px;background:${active ? 'var(--accent)' : 'var(--bg)'};color:${active ? '#000' : 'var(--text)'};border:1px solid ${active ? 'var(--accent)' : 'var(--border)'};border-radius:999px;padding:6px 12px;font-size:13px;cursor:pointer;">
          <input type="checkbox" name="onbInstrument" value="${escapeHtml(opt)}" ${active ? 'checked' : ''} style="display:none;">
          ${escapeHtml(opt)}
        </label>`;
      }).join('');
      // 2026-04-27: removed the "Available for dep gigs" toggle from
      // onboarding. New users default to available_for_deps=true (set
      // server-side in findOrCreateUser) so the marketplace has a healthy
      // pool from day one. Users who don't want dep offers can flip it
      // off in Profile > Edit Profile.
      // Chips cover the common cases; the free-text row covers everyone else
      // (cello, trombone, harp, percussion...) so no player is locked out of
      // answering, and the marketplace matching gets real data.
      const others = current.filter(c => !options.map(o => o.toLowerCase()).includes(c.toLowerCase()));
      return `
        <div style="text-align:left;margin-bottom:14px;">
          <label style="font-size:11px;font-weight:600;color:var(--text-2);text-transform:uppercase;letter-spacing:1px;display:block;margin-bottom:6px;">Instruments</label>
          <div id="onbInstrChips" style="display:flex;flex-wrap:wrap;gap:6px;">${chips}</div>
          <input id="onbInstrOther" type="text" value="${escapeHtml(others.join(', '))}" placeholder="Anything else? e.g. Cello, Trombone" style="width:100%;margin-top:10px;padding:12px;background:var(--bg);border:1px solid var(--border);border-radius:8px;color:var(--text);font-size:14px;box-sizing:border-box;">
        </div>`;
    },
    collect: () => {
      const body = {};
      const inputs = document.querySelectorAll('input[name="onbInstrument"]:checked');
      const picked = Array.from(inputs).map(i => i.value);
      const otherRaw = (document.getElementById('onbInstrOther')?.value || '');
      const others = otherRaw.split(',').map(s => s.trim()).filter(Boolean).map(s => s.slice(0, 40));
      const seen = new Set(picked.map(p => p.toLowerCase()));
      others.forEach(o => { if (!seen.has(o.toLowerCase())) { picked.push(o); seen.add(o.toLowerCase()); } });
      body.instruments = picked;
      return body;
    },
    cta: 'Next',
    // Wire chip toggle visual after render.
    afterRender: () => {
      const chipHost = document.getElementById('onbInstrChips');
      if (!chipHost) return;
      chipHost.querySelectorAll('label').forEach(lbl => {
        const input = lbl.querySelector('input');
        if (!input) return;
        input.addEventListener('change', () => {
          const active = input.checked;
          lbl.style.background = active ? 'var(--accent)' : 'var(--bg)';
          lbl.style.color = active ? '#000' : 'var(--text)';
          lbl.style.borderColor = active ? 'var(--accent)' : 'var(--border)';
        });
      });
    },
  },
  {
    kind: 'form',
    id: 'getting-paid',
    livesIn: 'Profile › Edit profile · stamped on every invoice',
    emoji: '💷',
    title: 'Get paid, stay sane',
    render: (profile) => `
      <div style="font-size:13px;color:var(--text-2);line-height:1.5;margin-bottom:14px;text-align:left;">Every gig can turn into an invoice with one tap. Add these once and they're stamped on every invoice you send. Both optional, both editable later in Profile.</div>
      <div style="text-align:left;margin-bottom:14px;">
        <label style="font-size:11px;font-weight:600;color:var(--text-2);text-transform:uppercase;letter-spacing:1px;display:block;margin-bottom:4px;">Standard gig fee (£)</label>
        <input id="onbRate" type="number" min="0" step="1" inputmode="decimal" value="${profile.rate_standard != null ? profile.rate_standard : ''}" placeholder="e.g. 300" style="width:100%;padding:12px;background:var(--bg);border:1px solid var(--border);border-radius:8px;color:var(--text);font-size:14px;box-sizing:border-box;">
        <div style="font-size:11px;color:var(--text-3);margin-top:4px;">Powers fee suggestions when you log a gig. Rough is fine.</div>
      </div>
      <div style="text-align:left;margin-bottom:14px;">
        <label style="font-size:11px;font-weight:600;color:var(--text-2);text-transform:uppercase;letter-spacing:1px;display:block;margin-bottom:4px;">Bank details for transfers</label>
        <textarea id="onbBankDetails" rows="3" placeholder="e.g. Sort code: 12-34-56&#10;Account: 12345678&#10;Your name" style="width:100%;padding:12px;background:var(--bg);border:1px solid var(--border);border-radius:8px;color:var(--text);font-size:14px;box-sizing:border-box;resize:vertical;font-family:inherit;">${escapeHtml(profile.bank_details || '')}</textarea>
      </div>
      <div style="text-align:left;margin-bottom:4px;">
        <label style="font-size:11px;font-weight:600;color:var(--text-2);text-transform:uppercase;letter-spacing:1px;display:block;margin-bottom:4px;">Payment link</label>
        <input id="onbPayLink" type="url" value="${escapeHtml(profile.payment_link_url || '')}" placeholder="Stripe, PayPal.me, Monzo.me..." style="width:100%;padding:12px;background:var(--bg);border:1px solid var(--border);border-radius:8px;color:var(--text);font-size:14px;box-sizing:border-box;">
        <div style="font-size:11px;color:var(--text-3);margin-top:4px;">Becomes a "Pay now" button on your invoices, so clients can pay by card.</div>
      </div>`,
    collect: () => {
      const body = {};
      const rate = (document.getElementById('onbRate')?.value || '').trim();
      if (rate && !isNaN(parseFloat(rate))) body.rate_standard = parseFloat(rate);
      const bank = (document.getElementById('onbBankDetails')?.value || '').trim();
      let link = (document.getElementById('onbPayLink')?.value || '').trim();
      if (bank) body.bank_details = bank;
      if (link) {
        if (!/^https?:\/\//i.test(link)) link = 'https://' + link;
        body.payment_link_url = link;
      }
      return body;
    },
    cta: 'Next',
  },
  {
    // 2026-04-27: replaces the old "Log my first gig" final slide. The biggest
    // value TMG offers a working musician is *not* having to retype their
    // existing schedule, so the onboarding now leads with bulk import. The
    // picker is intentionally not a single-pick exit — after the user finishes
    // one import we re-render the picker minus the source they just used, so
    // someone with a Google Calendar of past work AND a spreadsheet of
    // upcoming bookings can pull both in during the same setup session.
    //
    // Time framing matters: this step is the moment a user decides "is this
    // worth the effort?". The copy closes the 30-second promise ("basics
    // done") before setting an honest per-import expectation, so the two
    // never read as contradicting each other.
    kind: 'picker',
    emoji: '📥',
    // Copy lives in renderImportPicker (the picker bypasses the standard
    // step renderer, so a body here would be dead text that drifts).
    title: 'Bring your gigs in',
    final: true,
  },
];

// Tracks which import sources have been completed inside the current
// onboarding session, so the "Anything else?" pass hides them. Reset every
// time the tour starts. Sources: 'calendar' | 'upload' | 'sheets'.
window._onboardingState = window._onboardingState || { completed: [] };

function maybeStartOnboarding() {
  try {
    // BUG-AUDIT-02: Server-side onboarded_at is the canonical truth.
    // The old localStorage 'tmg_onboarded' guard suppressed the tour for
    // fresh users who signed in on a browser that had previously hosted
    // a different TMG session (shared computer, demo user then real user,
    // etc.). window._onboardingShown already dedups within a single page
    // session, so localStorage is redundant AND causes false negatives
    // across users. Drop the localStorage gate entirely and trust the
    // server. If a cached stale profile is present, still defer so we
    // don't race a pending /api/user/profile fetch.
    if (window._onboardingShown) return;
    const profile = window._cachedProfile || {};
    if (profile.onboarded_at) return;
    window._onboardingShown = true;
    // Resume path (2026-04-27): if the user just came back from Google
    // Calendar OAuth mid-onboarding, jump straight to the import picker
    // instead of replaying the welcome/profile-basics slides. The boot
    // handler set _onboardingResumePicker after stripping the URL flag.
    //
    // Subtlety: the calendar_connected handler also schedules
    // openFirstImportModal() which opens the bulk-import UI on top. We want
    // that UI to fire (it's the actual import flow), so we don't render the
    // picker until the first-import modal has been dismissed. A
    // MutationObserver watches for its removal, then re-renders the picker
    // so the user lands on "Anything else?".
    if (window._onboardingResumePicker) {
      window._onboardingResumePicker = false;
      const pickerIdx = ONBOARDING_STEPS.findIndex(s => s.kind === 'picker');
      if (pickerIdx < 0) return;
      // The boot handler schedules openFirstImportModal() at 600ms post-boot
      // when calendar_connected=true is present, so it may not be in the DOM
      // yet by the time maybeStartOnboarding runs. Wait briefly for the
      // modal to appear; if it does, watch for its removal then render the
      // picker. If it never appears within 2s, the user already did a bulk
      // import so render the picker right away.
      const renderWhenModalGone = () => {
        const obs = new MutationObserver(() => {
          if (!document.getElementById('firstImportOverlay')) {
            obs.disconnect();
            renderImportPicker(pickerIdx, { repeat: true });
          }
        });
        obs.observe(document.body, { childList: true });
      };
      const waitForModal = (attemptsLeft) => {
        if (document.getElementById('firstImportOverlay')) {
          renderWhenModalGone();
          return;
        }
        if (attemptsLeft <= 0) {
          renderImportPicker(pickerIdx, { repeat: true });
          return;
        }
        setTimeout(() => waitForModal(attemptsLeft - 1), 200);
      };
      waitForModal(10); // 10 * 200ms = 2s window for the modal to appear
      return;
    }
    showOnboardingStep(0);
  } catch (err) {
    console.error('Onboarding check failed:', err);
  }
}
window.maybeStartOnboarding = maybeStartOnboarding;

function showOnboardingStep(index) {
  const step = ONBOARDING_STEPS[index];
  if (!step) { finishOnboarding(); return; }

  // Picker step uses its own renderer so the layout can host three large
  // tappable source cards instead of the standard one-button info layout.
  if (step.kind === 'picker') {
    renderImportPicker(index, { repeat: false });
    return;
  }

  let overlay = ensureOnboardingOverlay();

  const total = ONBOARDING_STEPS.length;
  const pips = Array.from({ length: total }, (_, i) =>
    `<span style="width:6px;height:6px;border-radius:50%;background:${i === index ? 'var(--accent)' : 'var(--border)'};"></span>`
  ).join('');

  // S10-06: render info steps with step.body, form steps with step.render(profile).
  // Form steps also get an optional afterRender() hook for post-insertion wiring
  // (chip toggles, etc.) and a collect() call on Next that POSTs to /api/user/profile.
  const profile = window._cachedProfile || {};
  const bodyHtml = step.kind === 'form' && typeof step.render === 'function'
    ? step.render(profile)
    : `<div style="font-size:14px;color:var(--text-2);line-height:1.5;">${escapeHtml(step.body || '')}</div>`;

  overlay.innerHTML = `
    <div style="max-width:360px;width:100%;background:var(--card);border:1px solid var(--border);border-radius:16px;padding:28px 24px;text-align:center;box-shadow:0 30px 60px rgba(0,0,0,.5);">
      <div style="font-size:52px;margin-bottom:12px;">${step.emoji}</div>
      <div style="font-size:20px;font-weight:700;color:var(--text);margin-bottom:14px;">${escapeHtml(step.title)}</div>
      <div style="margin-bottom:${step.livesIn ? '12px' : '20px'};">${bodyHtml}</div>
      ${step.livesIn ? `<div style="display:inline-flex;align-items:center;gap:6px;background:var(--bg);border:1px solid var(--border);border-radius:999px;padding:5px 12px;font-size:11px;color:var(--text-3);margin-bottom:16px;">📍 Lives in <b style="color:var(--text-2);">${step.livesIn}</b></div>` : ''}
      <div style="display:flex;justify-content:center;gap:6px;margin-bottom:20px;">${pips}</div>
      <button id="onbNext" style="width:100%;background:var(--accent);color:#000;border:none;border-radius:10px;padding:12px;font-size:15px;font-weight:700;cursor:pointer;">${escapeHtml(step.cta)}</button>
      <button id="onbSkip" style="margin-top:10px;width:100%;background:transparent;color:var(--text-3);border:none;padding:8px;font-size:13px;cursor:pointer;">Skip tour</button>
    </div>`;

  // Wire any post-render hooks (chip toggle visuals, focus, etc.)
  if (step.kind === 'form' && typeof step.afterRender === 'function') {
    try { step.afterRender(); } catch (err) { console.error('Onboarding afterRender failed:', err); }
  }

  const nextBtn = overlay.querySelector('#onbNext');
  const skipBtn = overlay.querySelector('#onbSkip');
  nextBtn.onclick = async () => {
    // For form steps, collect values and persist before advancing.
    if (step.kind === 'form' && typeof step.collect === 'function') {
      try {
        nextBtn.disabled = true;
        nextBtn.textContent = 'Saving…';
        const body = step.collect();
        if (body && Object.keys(body).length) {
          const res = await fetch('/api/user/profile', {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body),
          });
          if (res.ok) {
            const updated = await res.json().catch(() => null);
            if (updated) window._cachedProfile = Object.assign({}, window._cachedProfile || {}, updated);
            else window._cachedProfile = Object.assign({}, window._cachedProfile || {}, body);
          }
        }
      } catch (err) {
        console.error('Onboarding step save failed (non-fatal, continuing):', err);
      }
    }
    if (step.final) {
      // Non-picker final steps still finish onboarding directly. The picker
      // path runs its own finish flow inside renderImportPicker.
      await finishOnboarding({ openGigWizard: false });
    } else {
      showOnboardingStep(index + 1);
    }
  };
  skipBtn.onclick = () => finishOnboarding({ openGigWizard: false });
}

// ── IMPORT PICKER (final onboarding step) ───────────────────────────────────
// Shown as the last onboarding step. Lets the user pick how they want to
// bring their existing gigs into TMG. Each source kicks off a different flow
// and on completion we re-render the picker with the just-used source removed
// so they can chain Calendar + CSV + Sheets in one sitting.

function ensureOnboardingOverlay() {
  let overlay = document.getElementById('onboardingOverlay');
  if (!overlay) {
    overlay = document.createElement('div');
    overlay.id = 'onboardingOverlay';
    overlay.style.cssText = 'position:fixed;inset:0;background:rgba(13,17,23,.88);backdrop-filter:blur(6px);-webkit-backdrop-filter:blur(6px);z-index:9999;display:flex;align-items:center;justify-content:center;padding:20px;overflow-y:auto;';
    document.body.appendChild(overlay);
  }
  return overlay;
}

function renderImportPicker(stepIndex, opts) {
  const repeat = !!(opts && opts.repeat);
  const completed = (window._onboardingState && window._onboardingState.completed) || [];
  const overlay = ensureOnboardingOverlay();

  const total = ONBOARDING_STEPS.length;
  const pips = Array.from({ length: total }, (_, i) =>
    `<span style="width:6px;height:6px;border-radius:50%;background:${i === stepIndex ? 'var(--accent)' : 'var(--border)'};"></span>`
  ).join('');

  const sources = [
    {
      key: 'calendar',
      emoji: '📅',
      title: 'Connect Google Calendar',
      blurb: "Pull every event from your Google Calendar. Best if your gigs already live there.",
      action: 'startImportFromCalendar',
    },
    {
      key: 'upload',
      emoji: '📊',
      title: 'Upload a spreadsheet',
      blurb: "CSV or Excel. We'll let you map columns to gig fields before importing.",
      action: 'startImportFromUpload',
    },
    {
      key: 'sheets',
      emoji: '📋',
      title: 'Connect a Google Sheet',
      blurb: "Two-way sync. Edit gigs in TrackMyGigs or your Sheet, both stay in step.",
      action: 'startImportFromSheets',
    },
  ];

  const remaining = sources.filter(s => !completed.includes(s.key));
  const allDone = remaining.length === 0;

  const titleHtml = repeat
    ? (allDone ? "Nice work, you're set" : 'Bring in another source?')
    : 'Bring your gigs in';
  const subtitleHtml = repeat
    ? (allDone
        ? "Everything imported. Hit done to land on your home screen, and you can pull more in later from Profile."
        : "You can chain as many imports as you want. Hit done when you're finished.")
    : "That's the basics done. Now bring in what you've already got - calendar, spreadsheet, or Google Sheet (you can do more than one). Each import takes a few minutes, and everything you connect is managed from Profile.";

  const cardsHtml = remaining.map(src => {
    const usedTag = completed.includes(src.key)
      ? '<span style="display:inline-block;font-size:10px;font-weight:700;color:#000;background:var(--accent);padding:2px 8px;border-radius:999px;margin-left:8px;">Imported</span>'
      : '';
    return `
      <button data-source="${src.key}" data-action="${src.action}" class="onbSourceBtn" style="display:block;width:100%;background:var(--bg);border:1px solid var(--border);border-radius:12px;padding:14px;text-align:left;cursor:pointer;margin-bottom:10px;">
        <div style="display:flex;align-items:center;gap:12px;">
          <div style="font-size:30px;line-height:1;">${src.emoji}</div>
          <div style="flex:1;">
            <div style="font-size:14px;font-weight:700;color:var(--text);margin-bottom:2px;">${escapeHtml(src.title)}${usedTag}</div>
            <div style="font-size:12px;color:var(--text-2);line-height:1.4;">${escapeHtml(src.blurb)}</div>
          </div>
          <div style="color:var(--text-3);font-size:18px;">›</div>
        </div>
      </button>`;
  }).join('');

  const doneCta = repeat
    ? (allDone ? "Take me to my home screen" : "I'm done, finish setup")
    : "Skip for now, I'll do this later";

  overlay.innerHTML = `
    <div style="max-width:380px;width:100%;background:var(--card);border:1px solid var(--border);border-radius:16px;padding:24px;text-align:center;box-shadow:0 30px 60px rgba(0,0,0,.5);">
      <div style="font-size:46px;margin-bottom:8px;">📥</div>
      <div style="font-size:20px;font-weight:700;color:var(--text);margin-bottom:10px;">${escapeHtml(titleHtml)}</div>
      <div style="font-size:13px;color:var(--text-2);line-height:1.5;margin-bottom:12px;text-align:left;">${escapeHtml(subtitleHtml)}</div>
      <div style="display:inline-flex;align-items:center;gap:6px;background:var(--bg);border:1px solid var(--border);border-radius:999px;padding:5px 12px;font-size:11px;color:var(--text-3);margin-bottom:14px;">📍 Lives in <b style="color:var(--text-2);">Profile › Connections</b></div>
      <div style="text-align:left;margin-bottom:14px;">${cardsHtml}</div>
      <div style="display:flex;justify-content:center;gap:6px;margin-bottom:14px;">${pips}</div>
      <button id="onbDone" style="width:100%;background:${allDone ? 'var(--accent)' : 'transparent'};color:${allDone ? '#000' : 'var(--text-2)'};border:1px solid ${allDone ? 'var(--accent)' : 'var(--border)'};border-radius:10px;padding:12px;font-size:14px;font-weight:600;cursor:pointer;">${escapeHtml(doneCta)}</button>
      <button id="onbBackToManual" style="margin-top:10px;width:100%;background:transparent;color:var(--text-3);border:none;padding:8px;font-size:12px;cursor:pointer;">Or just log a gig manually</button>
    </div>`;

  // Wire source buttons
  overlay.querySelectorAll('.onbSourceBtn').forEach(btn => {
    btn.onclick = () => {
      const action = btn.getAttribute('data-action');
      try {
        if (action === 'startImportFromCalendar') startImportFromCalendar();
        else if (action === 'startImportFromUpload') startImportFromUpload();
        else if (action === 'startImportFromSheets') startImportFromSheets();
      } catch (err) {
        console.error('Import source action failed:', err);
        if (typeof showToast === 'function') showToast('Could not start import. Please try again.');
      }
    };
  });

  document.getElementById('onbDone').onclick = () => finishOnboarding({ openGigWizard: false });
  document.getElementById('onbBackToManual').onclick = () => finishOnboarding({ openGigWizard: true });
}

// ── IMPORT SOURCE HANDLERS ──────────────────────────────────────────────────
// Each handler kicks off the chosen import flow. When the flow completes the
// handler should call `markImportSourceComplete(<key>)` which re-renders the
// picker minus the just-used source. For calendar this happens after the
// OAuth round-trip via the boot-time resume in maybeStartOnboarding.

function startImportFromCalendar() {
  // Stash a marker so when the OAuth callback redirects us back with
  // ?calendar_connected=true we know to resume onboarding at the picker
  // rather than just dismissing it.
  try { localStorage.setItem('tmg_onboarding_resume', 'calendar'); } catch (_) {}
  // Bounce out to Google. The /auth/google/callback handler will redirect
  // back to '/?calendar_connected=true' which the boot path already strips.
  window.location.href = '/auth/google/calendar';
}

function startImportFromUpload() {
  // Phase B (2026-04-27): hide the picker, render the upload + column-map
  // UI in its place, and rebuild the picker once the import completes (or
  // is cancelled). Both Papa Parse (CSV) and SheetJS (XLSX) are
  // lazy-loaded from CDN the first time the user picks a file so the main
  // bundle stays slim.
  const overlay = ensureOnboardingOverlay();
  overlay.innerHTML = renderUploadPickerHtml();
  wireUploadPicker(overlay);
}

// HTML for the file-picker / drag-drop step of the spreadsheet importer.
function renderUploadPickerHtml() {
  return `
    <div style="max-width:420px;width:100%;background:var(--card);border:1px solid var(--border);border-radius:16px;padding:24px;text-align:center;box-shadow:0 30px 60px rgba(0,0,0,.5);">
      <div style="font-size:46px;margin-bottom:8px;">📊</div>
      <div style="font-size:20px;font-weight:700;color:var(--text);margin-bottom:8px;">Upload a spreadsheet</div>
      <div style="font-size:13px;color:var(--text-2);line-height:1.5;margin-bottom:16px;text-align:left;">
        Drop a CSV or Excel file with one row per gig. We'll show you a column-mapping screen so you can tell us which column is the date, fee, venue, etc. Most clean spreadsheets need 30 seconds of mapping.
      </div>
      <label id="onbDropZone" for="onbFileInput" style="display:block;border:2px dashed var(--border);border-radius:12px;padding:30px 20px;background:var(--bg);cursor:pointer;color:var(--text-2);font-size:14px;margin-bottom:12px;">
        <div style="font-size:30px;margin-bottom:8px;">⬆</div>
        <div style="font-weight:700;color:var(--text);margin-bottom:4px;">Drop a file here</div>
        <div style="font-size:12px;">or tap to browse — .csv, .xlsx, .xls</div>
      </label>
      <input id="onbFileInput" type="file" accept=".csv,.xlsx,.xls,text/csv,application/vnd.ms-excel,application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" style="display:none;">
      <div id="onbUploadStatus" style="font-size:12px;color:var(--text-3);min-height:18px;margin-bottom:12px;"></div>
      <button id="onbUploadBack" style="width:100%;background:transparent;color:var(--text-2);border:1px solid var(--border);border-radius:10px;padding:12px;font-size:13px;cursor:pointer;">Back</button>
    </div>`;
}

function wireUploadPicker(overlay) {
  const input = overlay.querySelector('#onbFileInput');
  const drop = overlay.querySelector('#onbDropZone');
  const status = overlay.querySelector('#onbUploadStatus');
  const back = overlay.querySelector('#onbUploadBack');

  back.onclick = () => {
    const pickerIdx = ONBOARDING_STEPS.findIndex(s => s.kind === 'picker');
    if (pickerIdx >= 0) renderImportPicker(pickerIdx, { repeat: true });
  };

  // Drag and drop wiring
  ['dragenter', 'dragover'].forEach(ev => drop.addEventListener(ev, (e) => {
    e.preventDefault(); e.stopPropagation();
    drop.style.borderColor = 'var(--accent)';
    drop.style.background = 'rgba(76, 217, 100, 0.06)';
  }));
  ['dragleave', 'drop'].forEach(ev => drop.addEventListener(ev, (e) => {
    e.preventDefault(); e.stopPropagation();
    drop.style.borderColor = 'var(--border)';
    drop.style.background = 'var(--bg)';
  }));
  drop.addEventListener('drop', (e) => {
    e.preventDefault();
    const file = e.dataTransfer.files && e.dataTransfer.files[0];
    if (file) handleSpreadsheetFile(file, status);
  });
  input.addEventListener('change', () => {
    const file = input.files && input.files[0];
    if (file) handleSpreadsheetFile(file, status);
  });
}

// Lazy-loader for parser libraries. Returns a promise that resolves with the
// global the script attaches to window.
function loadScriptOnce(src, globalKey) {
  return new Promise((resolve, reject) => {
    if (window[globalKey]) return resolve(window[globalKey]);
    const existing = document.querySelector(`script[data-cdn="${src}"]`);
    if (existing) {
      existing.addEventListener('load', () => resolve(window[globalKey]));
      existing.addEventListener('error', () => reject(new Error('script load failed')));
      return;
    }
    const s = document.createElement('script');
    s.src = src;
    s.setAttribute('data-cdn', src);
    s.onload = () => resolve(window[globalKey]);
    s.onerror = () => reject(new Error('script load failed: ' + src));
    document.head.appendChild(s);
  });
}

async function handleSpreadsheetFile(file, statusEl) {
  if (statusEl) statusEl.textContent = `Reading ${file.name}…`;
  const name = (file.name || '').toLowerCase();
  try {
    let rows = [];
    if (name.endsWith('.csv') || file.type === 'text/csv') {
      const Papa = await loadScriptOnce('https://cdn.jsdelivr.net/npm/papaparse@5.4.1/papaparse.min.js', 'Papa');
      const text = await file.text();
      const parsed = Papa.parse(text, { header: false, skipEmptyLines: 'greedy' });
      rows = parsed.data || [];
    } else if (name.endsWith('.xlsx') || name.endsWith('.xls')) {
      const XLSX = await loadScriptOnce('https://cdn.jsdelivr.net/npm/xlsx@0.18.5/dist/xlsx.full.min.js', 'XLSX');
      const buf = await file.arrayBuffer();
      const wb = XLSX.read(buf, { type: 'array' });
      const sheetName = wb.SheetNames[0];
      const ws = wb.Sheets[sheetName];
      rows = XLSX.utils.sheet_to_json(ws, { header: 1, blankrows: false, raw: false });
    } else {
      if (statusEl) statusEl.textContent = 'Unsupported file type. Use CSV or Excel.';
      return;
    }
    if (!rows.length) {
      if (statusEl) statusEl.textContent = 'That file looked empty.';
      return;
    }
    if (statusEl) statusEl.textContent = `${rows.length} rows read. Map your columns…`;
    showColumnMapper(file.name, rows);
  } catch (err) {
    console.error('Spreadsheet parse failed:', err);
    if (statusEl) statusEl.textContent = 'Could not read that file. Try saving it as CSV and uploading again.';
  }
}

// Column mapping. Renders a header-row dropdown for each TMG field so the
// user can point us at their spreadsheet's columns. Header is auto-guessed
// from the first row whenever the column name looks recognisable.
function showColumnMapper(filename, rows) {
  const overlay = ensureOnboardingOverlay();
  // Treat first row as headers. If it looks numeric/date-y the user can
  // toggle the "First row is data" checkbox.
  const headers = (rows[0] || []).map((h, i) => String(h || `Column ${i + 1}`));
  const sample = rows.slice(1, 4); // up to 3 sample rows below the dropdowns
  const fields = [
    { key: 'date', label: 'Date', required: true,
      synonyms: ['date', 'when', 'day', 'gig date', 'event date'] },
    { key: 'start_time', label: 'Start time', required: false,
      synonyms: ['start', 'time', 'start time', 'doors', 'set start'] },
    { key: 'end_time', label: 'End time', required: false,
      synonyms: ['end', 'finish', 'end time', 'set end'] },
    { key: 'fee', label: 'Fee (£)', required: false,
      synonyms: ['fee', 'amount', 'pay', 'rate', 'price', 'cost'] },
    { key: 'band_name', label: 'Band / act', required: false,
      synonyms: ['band', 'act', 'artist', 'group', 'band name'] },
    { key: 'venue_name', label: 'Venue', required: false,
      synonyms: ['venue', 'location', 'place', 'where'] },
    { key: 'venue_address', label: 'Venue address', required: false,
      synonyms: ['address', 'venue address', 'street'] },
    { key: 'client_name', label: 'Client / contact', required: false,
      synonyms: ['client', 'contact', 'agent', 'booker', 'organiser'] },
    { key: 'notes', label: 'Notes', required: false,
      synonyms: ['notes', 'comments', 'remarks', 'description'] },
  ];

  function guessIdx(synonyms) {
    const lower = headers.map(h => h.toLowerCase().trim());
    for (const syn of synonyms) {
      const i = lower.indexOf(syn);
      if (i >= 0) return i;
    }
    for (let i = 0; i < lower.length; i++) {
      if (synonyms.some(syn => lower[i].includes(syn))) return i;
    }
    return -1;
  }

  const fieldRows = fields.map(f => {
    const guess = guessIdx(f.synonyms);
    const opts = ['<option value="-1">— Skip this field —</option>']
      .concat(headers.map((h, i) => `<option value="${i}" ${i === guess ? 'selected' : ''}>${escapeHtml(h)}</option>`))
      .join('');
    return `
      <div style="display:flex;align-items:center;gap:8px;margin-bottom:8px;text-align:left;">
        <div style="flex:1;font-size:13px;color:var(--text);">${escapeHtml(f.label)}${f.required ? ' <span style="color:var(--accent);">*</span>' : ''}</div>
        <select data-field="${f.key}" style="flex:1;padding:8px;background:var(--bg);border:1px solid var(--border);border-radius:8px;color:var(--text);font-size:13px;">${opts}</select>
      </div>`;
  }).join('');

  const sampleHtml = sample.length
    ? `<div style="margin-top:14px;border-top:1px solid var(--border);padding-top:12px;text-align:left;">
        <div style="font-size:11px;font-weight:700;color:var(--text-2);text-transform:uppercase;letter-spacing:1px;margin-bottom:6px;">First 3 rows preview</div>
        <div style="font-size:11px;color:var(--text-3);font-family:monospace;line-height:1.5;overflow-x:auto;">
          ${sample.map(r => '<div>' + escapeHtml(r.slice(0, 6).join(' | ')) + (r.length > 6 ? ' …' : '') + '</div>').join('')}
        </div>
      </div>`
    : '';

  overlay.innerHTML = `
    <div style="max-width:480px;width:100%;background:var(--card);border:1px solid var(--border);border-radius:16px;padding:24px;text-align:center;box-shadow:0 30px 60px rgba(0,0,0,.5);max-height:90vh;overflow-y:auto;">
      <div style="font-size:32px;margin-bottom:6px;">🗂</div>
      <div style="font-size:18px;font-weight:700;color:var(--text);margin-bottom:6px;">Map your columns</div>
      <div style="font-size:12px;color:var(--text-2);margin-bottom:14px;">${escapeHtml(filename)} · ${rows.length - 1} data rows</div>
      <label style="display:flex;align-items:center;gap:8px;font-size:12px;color:var(--text-2);margin-bottom:12px;text-align:left;">
        <input id="onbFirstRowData" type="checkbox" style="accent-color:var(--accent);">
        First row is data, not headers
      </label>
      <div>${fieldRows}</div>
      ${sampleHtml}
      <div id="onbMapStatus" style="font-size:12px;color:var(--text-3);min-height:18px;margin:14px 0 8px;"></div>
      <button id="onbMapImport" style="width:100%;background:var(--accent);color:#000;border:none;border-radius:10px;padding:12px;font-size:14px;font-weight:700;cursor:pointer;">Import ${rows.length - 1} gig${rows.length - 1 === 1 ? '' : 's'}</button>
      <button id="onbMapBack" style="margin-top:10px;width:100%;background:transparent;color:var(--text-3);border:none;padding:8px;font-size:12px;cursor:pointer;">Back to picker</button>
    </div>`;

  overlay.querySelector('#onbMapBack').onclick = () => {
    const pickerIdx = ONBOARDING_STEPS.findIndex(s => s.kind === 'picker');
    if (pickerIdx >= 0) renderImportPicker(pickerIdx, { repeat: true });
  };

  overlay.querySelector('#onbMapImport').onclick = async () => {
    const map = {};
    overlay.querySelectorAll('select[data-field]').forEach(sel => {
      const idx = parseInt(sel.value, 10);
      if (!isNaN(idx) && idx >= 0) map[sel.getAttribute('data-field')] = idx;
    });
    if (typeof map.date !== 'number') {
      overlay.querySelector('#onbMapStatus').textContent = 'A Date column is required to import.';
      return;
    }
    const firstRowIsData = !!overlay.querySelector('#onbFirstRowData').checked;
    const dataRows = firstRowIsData ? rows : rows.slice(1);
    await submitSpreadsheetImport(filename, dataRows, map, overlay);
  };
}

async function submitSpreadsheetImport(filename, dataRows, map, overlay) {
  const status = overlay.querySelector('#onbMapStatus');
  const btn = overlay.querySelector('#onbMapImport');
  if (btn) { btn.disabled = true; btn.textContent = 'Importing…'; }
  if (status) status.textContent = '';

  // Build payload rows. We pass raw cell strings to the server so it can
  // run a unified date parser; the client only normalises obvious things
  // like whitespace and currency symbols on the fee column.
  const events = dataRows.map((row, i) => {
    const get = (key) => {
      const idx = map[key];
      if (typeof idx !== 'number') return null;
      const v = row[idx];
      return v == null ? null : String(v).trim();
    };
    const feeRaw = get('fee');
    const fee = feeRaw ? feeRaw.replace(/[^0-9.\-]/g, '') : null;
    return {
      _row: i + 1,
      date: get('date'),
      start_time: get('start_time'),
      end_time: get('end_time'),
      fee: fee && fee !== '' ? parseFloat(fee) : null,
      band_name: get('band_name'),
      venue_name: get('venue_name'),
      venue_address: get('venue_address'),
      client_name: get('client_name'),
      notes: get('notes'),
    };
  });

  try {
    const r = await fetch('/api/gigs/import-bulk', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ source: 'csv', filename, rows: events }),
    });
    const data = await r.json();
    if (!r.ok || data.error) throw new Error(data.error || ('HTTP ' + r.status));

    if (typeof invalidateGigsCache === 'function') invalidateGigsCache();

    const imported = data.imported || 0;
    const skipped = data.skipped || 0;
    if (typeof showToast === 'function') {
      showToast(`Imported ${imported} gig${imported === 1 ? '' : 's'}${skipped ? ` (${skipped} skipped)` : ''}`);
    }
    markImportSourceComplete('upload');
  } catch (err) {
    console.error('Spreadsheet import failed:', err);
    if (status) status.textContent = 'Import failed: ' + (err.message || 'unknown error');
    if (btn) { btn.disabled = false; btn.textContent = 'Try again'; }
  }
}

async function startImportFromSheets() {
  // Phase C (2026-04-27): check if the user already has Sheets access on
  // their Google account. If yes, jump straight to the URL-paste step. If
  // not, kick off the dedicated /auth/google/sheets OAuth flow which
  // requests the spreadsheets scope (plus calendar so it stays a single
  // consent screen) and redirects back with ?sheets_connected=true.
  let status = null;
  try {
    const r = await fetch('/api/sheets/status');
    if (r.ok) status = await r.json();
  } catch (_) { /* fall through to OAuth */ }
  if (!status || !status.has_google_token) {
    try { localStorage.setItem('tmg_onboarding_resume', 'sheets'); } catch (_) {}
    window.location.href = '/auth/google/sheets';
    return;
  }
  // Already have Google token (likely connected for calendar) — but might
  // not include the spreadsheets scope yet. Show the URL paste step; if the
  // preview call comes back with a permission error we'll prompt the user
  // to re-consent.
  showSheetsUrlStep();
}

function showSheetsUrlStep() {
  const overlay = ensureOnboardingOverlay();
  // 2026-04-27: pre-fill the URL field from localStorage so users who got
  // bounced through OAuth don't have to retype. We stash the URL on
  // "Read this sheet" click and clear it when the import succeeds.
  let savedUrl = '';
  try { savedUrl = localStorage.getItem('tmg_onboarding_sheet_url') || ''; } catch (_) {}

  overlay.innerHTML = `
    <div style="max-width:420px;width:100%;background:var(--card);border:1px solid var(--border);border-radius:16px;padding:24px;text-align:center;box-shadow:0 30px 60px rgba(0,0,0,.5);">
      <div style="font-size:46px;margin-bottom:8px;">📋</div>
      <div style="font-size:20px;font-weight:700;color:var(--text);margin-bottom:8px;">Paste your Google Sheet</div>
      <div style="font-size:13px;color:var(--text-2);line-height:1.5;margin-bottom:14px;text-align:left;">
        Open the Sheet in Google Sheets, copy the URL from your browser's address bar, and paste it here. We'll show you the tabs and let you map columns.
      </div>
      <input id="onbSheetUrl" type="url" placeholder="https://docs.google.com/spreadsheets/d/..." value="${escapeHtml(savedUrl)}" style="width:100%;padding:12px;background:var(--bg);border:1px solid var(--border);border-radius:8px;color:var(--text);font-size:13px;box-sizing:border-box;margin-bottom:10px;">
      <div id="onbSheetStatus" style="font-size:12px;color:var(--text-3);min-height:18px;margin-bottom:10px;text-align:left;"></div>
      <button id="onbSheetNext" style="width:100%;background:var(--accent);color:#000;border:none;border-radius:10px;padding:12px;font-size:14px;font-weight:700;cursor:pointer;">Read this sheet</button>
      <button id="onbSheetBack" style="margin-top:10px;width:100%;background:transparent;color:var(--text-3);border:none;padding:8px;font-size:12px;cursor:pointer;">Back</button>
    </div>`;

  overlay.querySelector('#onbSheetBack').onclick = () => {
    try { localStorage.removeItem('tmg_onboarding_sheet_url'); } catch (_) {}
    const pickerIdx = ONBOARDING_STEPS.findIndex(s => s.kind === 'picker');
    if (pickerIdx >= 0) renderImportPicker(pickerIdx, { repeat: true });
  };
  overlay.querySelector('#onbSheetNext').onclick = () => {
    const url = (overlay.querySelector('#onbSheetUrl').value || '').trim();
    if (!url) {
      overlay.querySelector('#onbSheetStatus').textContent = 'Paste a Google Sheets URL or ID first.';
      return;
    }
    // Stash before any fetch so an OAuth redirect doesn't lose the URL.
    try { localStorage.setItem('tmg_onboarding_sheet_url', url); } catch (_) {}
    fetchSheetPreview(url, null);
  };

  // If we were resumed with a URL already saved, auto-trigger the preview
  // so the user lands directly on the column mapper without having to
  // click "Read this sheet" again. Belt and braces: with the calendar OAuth
  // now granting spreadsheets too, this auto-resume rarely fires anymore,
  // but it's the right fallback for any future flow that does redirect.
  if (savedUrl && window._sheetsResumeAutoFetch) {
    window._sheetsResumeAutoFetch = false;
    setTimeout(() => fetchSheetPreview(savedUrl, null), 200);
  }
}

async function fetchSheetPreview(urlOrId, tabName) {
  const overlay = ensureOnboardingOverlay();
  const status = overlay.querySelector('#onbSheetStatus');
  const btn = overlay.querySelector('#onbSheetNext');
  if (status) status.textContent = 'Reading…';
  if (btn) btn.disabled = true;
  try {
    const r = await fetch('/api/sheets/preview', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ url_or_id: urlOrId, tab_name: tabName }),
    });
    const data = await r.json();
    if (!r.ok) {
      // Permission scope mismatch: token doesn't include spreadsheets.
      if (data.needs_connect || /permission|scope/i.test(data.error || '')) {
        try { localStorage.setItem('tmg_onboarding_resume', 'sheets'); } catch (_) {}
        window.location.href = '/auth/google/sheets';
        return;
      }
      if (status) status.textContent = data.error || 'Could not read that sheet.';
      if (btn) btn.disabled = false;
      return;
    }
    showSheetsTabAndMapper(data, urlOrId);
  } catch (err) {
    console.error('Sheets preview failed:', err);
    if (status) status.textContent = 'Network error reading the sheet. Try again.';
    if (btn) btn.disabled = false;
  }
}

function showSheetsTabAndMapper(preview, urlOrId) {
  // preview = { spreadsheet_id, spreadsheet_title, tabs, tab_name,
  //             headers, sample_rows }
  const overlay = ensureOnboardingOverlay();
  const tabsHtml = preview.tabs.map(t =>
    `<option value="${escapeHtml(t.name)}" ${t.name === preview.tab_name ? 'selected' : ''}>${escapeHtml(t.name)} (${t.row_count - 1} rows)</option>`
  ).join('');

  // Reuse the column-mapper logic from Phase B by feeding it Sheets-style
  // [headers, ...sampleRows] data and an import callback that hits
  // /api/sheets/import instead of /api/gigs/import-bulk.
  const fakeRows = [preview.headers, ...preview.sample_rows];
  // We need the mapper to know about the spreadsheet ID + tab name when it
  // submits, so we stash them on a session-scoped object the mapper picks
  // up in submitSpreadsheetImport-equivalent.
  window._sheetsImportContext = {
    spreadsheet_id: preview.spreadsheet_id,
    tab_name: preview.tab_name,
    spreadsheet_title: preview.spreadsheet_title,
  };

  // Render a minimal tab-picker on top, then call the existing mapper.
  // showColumnMapper renders the entire overlay, so we render the tab
  // picker AS PART OF that overlay by patching the title HTML afterwards.
  showColumnMapper(`${preview.spreadsheet_title} · ${preview.tab_name}`, fakeRows);

  // Inject the tab picker above the column mapper. The mapper rendered a
  // <div style="...font-size:18px;font-weight:700;...">Map your columns</div>
  // which we anchor against; insert a tab dropdown immediately before it so
  // the user can switch tabs without going back to the URL step.
  const mapperBox = overlay.querySelector('div[style*="max-width:480px"]');
  if (mapperBox && preview.tabs.length > 1) {
    const titleEl = mapperBox.querySelector('div[style*="font-size:18px"]');
    const tabPicker = document.createElement('div');
    tabPicker.style.cssText = 'text-align:left;margin-bottom:12px;';
    tabPicker.innerHTML = `
      <label style="font-size:11px;font-weight:700;color:var(--text-2);text-transform:uppercase;letter-spacing:1px;display:block;margin-bottom:4px;">Sheet tab</label>
      <select id="onbSheetTabSelect" style="width:100%;padding:8px;background:var(--bg);border:1px solid var(--border);border-radius:8px;color:var(--text);font-size:13px;">${tabsHtml}</select>
    `;
    titleEl.parentNode.insertBefore(tabPicker, titleEl.nextSibling.nextSibling);
    overlay.querySelector('#onbSheetTabSelect').onchange = (e) => {
      fetchSheetPreview(urlOrId, e.target.value);
    };
  }

  // Override the import button to hit /api/sheets/import. Also fix the
  // button label: showColumnMapper bases the count on the rows it received
  // (the 10-row preview sample), so for Sheets it always says "Import 10".
  // The actual import reads the entire tab server-side via the sheets API,
  // so use the tab's real row_count from the preview metadata. Subtract 1
  // for the header row.
  const importBtn = overlay.querySelector('#onbMapImport');
  if (importBtn) {
    const tabMeta = preview.tabs.find(t => t.name === preview.tab_name);
    const dataRowCount = tabMeta && typeof tabMeta.row_count === 'number'
      ? Math.max(0, tabMeta.row_count - 1)
      : null;
    if (dataRowCount != null) {
      importBtn.textContent = `Import ${dataRowCount} gig${dataRowCount === 1 ? '' : 's'}`;
    }
    importBtn.onclick = async () => {
      const map = {};
      overlay.querySelectorAll('select[data-field]').forEach(sel => {
        const idx = parseInt(sel.value, 10);
        if (!isNaN(idx) && idx >= 0) map[sel.getAttribute('data-field')] = idx;
      });
      if (typeof map.date !== 'number') {
        const st = overlay.querySelector('#onbMapStatus');
        if (st) st.textContent = 'A Date column is required to import.';
        return;
      }
      await submitSheetsImport(map, overlay);
    };
  }
  // Override the Back button to return to the URL step rather than the picker.
  const backBtn = overlay.querySelector('#onbMapBack');
  if (backBtn) backBtn.onclick = () => showSheetsUrlStep();
}

async function submitSheetsImport(columnMap, overlay) {
  const ctx = window._sheetsImportContext || {};
  const status = overlay.querySelector('#onbMapStatus');
  const btn = overlay.querySelector('#onbMapImport');
  if (btn) { btn.disabled = true; btn.textContent = 'Importing…'; }
  if (status) status.textContent = '';
  try {
    const r = await fetch('/api/sheets/import', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        spreadsheet_id: ctx.spreadsheet_id,
        tab_name: ctx.tab_name,
        column_map: columnMap,
        link_for_sync: true,
      }),
    });
    const data = await r.json();
    if (!r.ok || data.error) throw new Error(data.error || ('HTTP ' + r.status));
    if (typeof invalidateGigsCache === 'function') invalidateGigsCache();
    const imported = data.imported || 0;
    const merged = data.merged || 0;
    const skipped = data.skipped || 0;
    if (typeof showToast === 'function') {
      const parts = [`Imported ${imported} gig${imported === 1 ? '' : 's'}`];
      if (merged) parts.push(`merged ${merged} with existing`);
      if (skipped) parts.push(`${skipped} skipped`);
      // 5s duration: the result message is multi-clause and worth letting
      // the user actually read it. Default 2200ms vanishes too fast.
      showToast(parts.join(', '), 5000);
    }
    // Clear the stashed URL so the next time the user opens the Sheets
    // step it doesn't pre-fill with a stale value.
    try { localStorage.removeItem('tmg_onboarding_sheet_url'); } catch (_) {}
    markImportSourceComplete('sheets');
  } catch (err) {
    console.error('Sheets import failed:', err);
    if (status) status.textContent = 'Import failed: ' + (err.message || 'unknown error');
    if (btn) { btn.disabled = false; btn.textContent = 'Try again'; }
  }
}

function markImportSourceComplete(key) {
  if (!window._onboardingState) window._onboardingState = { completed: [] };
  if (!window._onboardingState.completed.includes(key)) {
    window._onboardingState.completed.push(key);
  }
  // The picker is the final ONBOARDING_STEPS index. Find it dynamically so
  // the index doesn't go stale if steps are reordered later.
  const pickerIdx = ONBOARDING_STEPS.findIndex(s => s.kind === 'picker');
  if (pickerIdx >= 0) {
    renderImportPicker(pickerIdx, { repeat: true });
  }
}
window.markImportSourceComplete = markImportSourceComplete;

async function finishOnboarding(opts) {
  const overlay = document.getElementById('onboardingOverlay');
  if (overlay) overlay.remove();
  // The import flows reuse this finish path when launched from the Gigs
  // screen / More sheet; an established user doesn't need the first-run tip.
  const wasAlreadyOnboarded = !!(window._cachedProfile && window._cachedProfile.onboarded_at);
  try {
    localStorage.setItem('tmg_onboarded', '1');
    // Clear any in-flight resume marker — the user has finished.
    localStorage.removeItem('tmg_onboarding_resume');
    await fetch('/api/user/onboarded', { method: 'POST' });
    if (window._cachedProfile) window._cachedProfile.onboarded_at = new Date().toISOString();
  } catch (err) {
    console.error('Mark onboarded failed (non-fatal):', err);
  }
  // Reset session state so a re-fired tour starts clean.
  window._onboardingState = { completed: [] };
  // The picker has its own "log a gig manually" affordance which sets
  // openGigWizard=true.
  if (opts && opts.openGigWizard) {
    try {
      if (typeof openGigWizard === 'function') setTimeout(() => openGigWizard(), 200);
    } catch (err) {
      console.error('Auto-open gig wizard failed (non-fatal):', err);
    }
    return;
  }
  // All other paths land on Home: the day-zero dashboard (vitals, week strip,
  // "Finish setting up" checklist) is the guided next step, and stranding a
  // brand-new user on the Profile sub-screen made their first landing a
  // Back-button dead end. A toast still teaches where connections and payment
  // details live without dragging them there.
  try {
    if (typeof showScreen === 'function') showScreen('home');
    if (!wasAlreadyOnboarded) {
      setTimeout(() => {
        try { showToast('Tip: Google connections and payment details live in Profile'); } catch (_) {}
      }, 700);
    }
  } catch (err) {
    console.error('Onboarding settings tour failed (non-fatal):', err);
  }
}
window.finishOnboarding = finishOnboarding;

// ── NUDGE FEEDBACK CAPTURE ──────────────────────────────────────────────────
// Fire-and-forget POST so the server can learn which nudges users act on vs
// dismiss, letting us tune scoring. Action: 'accepted' | 'dismissed' | 'snoozed'.

function recordNudgeFeedback(nudgeType, action, gigId) {
  try {
    fetch('/api/nudge-feedback', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        nudge_type: String(nudgeType || 'unknown'),
        action: String(action || 'unknown'),
        gig_id: gigId || null,
      }),
    }).catch(() => { /* non-fatal */ });
  } catch (_) { /* silent */ }
}
window.recordNudgeFeedback = recordNudgeFeedback;

// ── TRAVEL-TIME & PACK-DOWN AUTO-BLOCKS ─────────────────────────────────────
// Given the user's gigs, return pseudo-blocked windows representing drive time
// before + pack-down + drive time home after. Purely client-side visualisation
// — they display as "soft" entries on the calendar without touching blocked_dates.
// Defaults: 60min travel each way, 30min load-in, 30min pack-down.

function computeAutoBlocksForGigs(gigs) {
  if (!Array.isArray(gigs) || gigs.length === 0) return [];
  const TRAVEL_MIN = Number(localStorage.getItem('tmg_travel_mins')) || 60;
  const LOAD_MIN = Number(localStorage.getItem('tmg_load_mins')) || 30;
  const PACKDOWN_MIN = Number(localStorage.getItem('tmg_packdown_mins')) || 30;
  const out = [];
  for (const g of gigs) {
    if (!g.date || g.status === 'cancelled') continue;
    if (!g.start_time) continue;
    const startIso = `${String(g.date).slice(0, 10)}T${g.start_time.length === 5 ? g.start_time + ':00' : g.start_time}`;
    const start = new Date(startIso);
    if (isNaN(+start)) continue;
    const end = g.end_time
      ? new Date(`${String(g.date).slice(0, 10)}T${g.end_time.length === 5 ? g.end_time + ':00' : g.end_time}`)
      : new Date(start.getTime() + 3 * 3600000);
    const preStart = new Date(start.getTime() - (TRAVEL_MIN + LOAD_MIN) * 60000);
    const postEnd = new Date(end.getTime() + (TRAVEL_MIN + PACKDOWN_MIN) * 60000);
    out.push({
      gig_id: g.id,
      kind: 'travel_out',
      start: preStart.toISOString(),
      end: start.toISOString(),
      label: `Drive + load-in for ${g.venue_name || g.band_name || 'gig'}`,
    });
    out.push({
      gig_id: g.id,
      kind: 'travel_home',
      start: end.toISOString(),
      end: postEnd.toISOString(),
      label: `Pack-down + drive home from ${g.venue_name || g.band_name || 'gig'}`,
    });
  }
  return out;
}
window.computeAutoBlocksForGigs = computeAutoBlocksForGigs;

// Returns true if a candidate window (ISO strings) collides with any auto-block
// derived from the user's current gigs. Used by the availability calendar to
// warn when a potential new gig clashes with travel/pack-down of an existing one.
function isTimeAutoBlocked(startIso, endIso) {
  try {
    const gigs = window._cachedGigs || [];
    const blocks = computeAutoBlocksForGigs(gigs);
    const s = new Date(startIso).getTime();
    const e = new Date(endIso).getTime();
    for (const b of blocks) {
      const bs = new Date(b.start).getTime();
      const be = new Date(b.end).getTime();
      if (s < be && e > bs) return b; // overlap — return offending block
    }
    return null;
  } catch (_) {
    return null;
  }
}
window.isTimeAutoBlocked = isTimeAutoBlocked;

// ── First-import modal + quick-fire wizard ──────────────────────────────────
// Triggered automatically after the OAuth callback appends ?calendar_connected=true
// to the URL (see setupApp). User sees a full-screen overlay with a fetched
// count of likely gigs, three window choices (current tax year default, future
// only, custom range), and a single "Import all" CTA. On success, we kick off
// the quick-fire fee wizard which steps through each imported gig that came
// back without a fee, auto-focusing the fee input for keyboard-first entry.
//
// All markup is injected dynamically so there's no dependency on index.html
// having panels declared up-front. State lives on window._firstImport so a
// page refresh mid-flow can pick up where the user left off (best-effort).

(function () {
  const ov = () => document.getElementById('firstImportOverlay');
  const closeOverlay = () => { const el = ov(); if (el) el.remove(); };

  // Public entry point exposed on window. Idempotent - if the overlay is
  // already open, this just re-fetches the events.
  window.openFirstImportModal = async function openFirstImportModal(opts = {}) {
    const existing = ov();
    if (existing) existing.remove();

    const overlay = document.createElement('div');
    overlay.id = 'firstImportOverlay';
    overlay.style.cssText = 'position:fixed;inset:0;z-index:10000;background:rgba(0,0,0,.82);display:flex;align-items:center;justify-content:center;padding:20px;overflow:auto;';
    overlay.innerHTML = `
      <div style="background:var(--bg);border:1px solid var(--border);border-radius:18px;width:100%;max-width:440px;padding:24px;box-shadow:0 20px 60px rgba(0,0,0,.5);">
        <div id="fiBody">
          <div style="text-align:center;padding:40px 20px;">
            <div style="width:44px;height:44px;border-radius:50%;border:3px solid var(--border);border-top-color:var(--accent);margin:0 auto 16px;animation:fiSpin 1s linear infinite;"></div>
            <div style="font-size:14px;color:var(--text-2);">Looking through your calendar...</div>
          </div>
        </div>
      </div>
      <style>@keyframes fiSpin{to{transform:rotate(360deg);}}</style>`;
    document.body.appendChild(overlay);

    // Fetch the current tax year by default; the UI lets users widen it.
    await fiFetchAndRender('future');
  };

  async function fiFetchAndRender(windowMode, from, to) {
    const body = document.getElementById('fiBody');
    if (!body) return;
    body.innerHTML = `
      <div style="text-align:center;padding:40px 20px;">
        <div style="width:44px;height:44px;border-radius:50%;border:3px solid var(--border);border-top-color:var(--accent);margin:0 auto 16px;animation:fiSpin 1s linear infinite;"></div>
        <div style="font-size:14px;color:var(--text-2);">Classifying events with AI...</div>
        <div style="font-size:11px;color:var(--text-3);margin-top:6px;">This takes 10-30 seconds for a full year.</div>
      </div>`;

    let url = '/api/calendar/events?window=' + encodeURIComponent(windowMode);
    if (windowMode === 'custom' && from && to) {
      url += '&from=' + encodeURIComponent(from) + '&to=' + encodeURIComponent(to);
    }
    let events = [];
    try {
      const r = await fetch(url);
      const data = await r.json();
      if (!data.connected) {
        body.innerHTML = `
          <div style="text-align:center;padding:30px 16px;">
            <div style="font-size:15px;font-weight:600;color:var(--text);margin-bottom:6px;">Calendar not connected</div>
            <div style="font-size:12px;color:var(--text-2);margin-bottom:16px;">Connect Google Calendar in Profile first.</div>
            <button onclick="document.getElementById('firstImportOverlay').remove();" style="background:var(--card);color:var(--text);border:1px solid var(--border);border-radius:10px;padding:10px 20px;font-size:13px;cursor:pointer;">Close</button>
          </div>`;
        return;
      }
      events = (data.events || []).filter(e => !e.already_imported);
    } catch (err) {
      body.innerHTML = `
        <div style="text-align:center;padding:30px 16px;">
          <div style="font-size:15px;font-weight:600;color:var(--danger);margin-bottom:6px;">Couldn't read your calendar</div>
          <div style="font-size:12px;color:var(--text-2);margin-bottom:16px;">${escapeHtml(err.message || String(err))}</div>
          <button onclick="document.getElementById('firstImportOverlay').remove();" style="background:var(--card);color:var(--text);border:1px solid var(--border);border-radius:10px;padding:10px 20px;font-size:13px;cursor:pointer;">Close</button>
        </div>`;
      return;
    }

    // No candidates? Friendly empty state and a "maybe try a wider range" tip.
    if (events.length === 0) {
      body.innerHTML = `
        <div style="text-align:center;padding:30px 16px;">
          <div style="font-size:32px;margin-bottom:10px;">&#x1F4C5;</div>
          <div style="font-size:15px;font-weight:600;color:var(--text);margin-bottom:6px;">No gigs found in this range</div>
          <div style="font-size:12px;color:var(--text-2);margin-bottom:20px;line-height:1.5;">We didn't spot anything that looks like a gig in ${windowLabel(windowMode)}. Try a wider range or check your calendar choice in Settings.</div>
          <div style="display:flex;gap:8px;justify-content:center;flex-wrap:wrap;margin-bottom:12px;">
            <button onclick="fiFetchAndRender('all')" style="background:var(--card);color:var(--text);border:1px solid var(--border);border-radius:10px;padding:8px 14px;font-size:12px;cursor:pointer;">Try last 2 years</button>
            <button onclick="document.getElementById('firstImportOverlay').remove();" style="background:transparent;color:var(--text-2);border:1px solid var(--border);border-radius:10px;padding:8px 14px;font-size:12px;cursor:pointer;">Skip for now</button>
          </div>
        </div>`;
      window.fiFetchAndRender = fiFetchAndRender;
      return;
    }

    // Store the fetched events for the import call. Also compute earliest
    // and latest dates so the copy can say "going back to 6 Apr 2025".
    window._firstImport = { events, windowMode };
    const sortedByDate = events.slice().sort((a, b) => (a.start || '').localeCompare(b.start || ''));
    const earliest = sortedByDate[0] && sortedByDate[0].start ? new Date(sortedByDate[0].start) : null;
    const latest = sortedByDate[sortedByDate.length - 1] && sortedByDate[sortedByDate.length - 1].start
      ? new Date(sortedByDate[sortedByDate.length - 1].start) : null;
    const rangeLine = (earliest && latest)
      ? `${earliest.toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' })} to ${latest.toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' })}`
      : '';

    body.innerHTML = `
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:14px;">
        <div style="font-size:11px;font-weight:700;letter-spacing:1.2px;color:var(--accent);text-transform:uppercase;">Calendar import</div>
        <button onclick="document.getElementById('firstImportOverlay').remove();" aria-label="Close" style="background:transparent;border:none;color:var(--text-3);font-size:22px;cursor:pointer;line-height:1;padding:0 4px;">&times;</button>
      </div>
      <div style="font-size:24px;font-weight:700;color:var(--text);margin-bottom:6px;line-height:1.2;">We found <span style="color:var(--accent);">${events.length}</span> gig${events.length === 1 ? '' : 's'} in your calendar.</div>
      <div style="font-size:13px;color:var(--text-2);margin-bottom:18px;line-height:1.5;">${rangeLine ? 'Covering ' + escapeHtml(rangeLine) + '. ' : ''}Importing pulls venues, dates, times, and fees into TrackMyGigs. Your Google Calendar isn't touched.</div>

      <div style="background:var(--card);border:1px solid var(--border);border-radius:12px;padding:12px 14px;margin-bottom:12px;display:flex;align-items:flex-start;gap:10px;">
        <div style="font-size:16px;line-height:1;">&#x1F50D;</div>
        <div style="flex:1;">
          <div style="font-size:12px;color:var(--text);font-weight:600;margin-bottom:2px;">Range</div>
          <div style="display:flex;gap:6px;margin-top:6px;flex-wrap:wrap;">
            ${rangeChip('future', 'Future only', windowMode)}
            ${rangeChip('current_tax_year', 'This tax year', windowMode)}
            ${rangeChip('all', 'Last 2 years', windowMode)}
          </div>
        </div>
      </div>

      <div style="max-height:200px;overflow-y:auto;background:var(--card);border:1px solid var(--border);border-radius:12px;margin-bottom:8px;">
        ${events.map((e, i) => {
          const d = e.start ? new Date(e.start).toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' }) : '';
          const sub = [d, e.suggested_venue_name || e.location].filter(Boolean).join(' · ');
          return `
        <label style="display:flex;align-items:center;gap:10px;padding:9px 12px;border-bottom:1px solid var(--border);cursor:pointer;">
          <input type="checkbox" class="fi-event-check" data-idx="${i}" checked onchange="fiUpdateImportCount()" style="width:16px;height:16px;accent-color:var(--accent);flex-shrink:0;">
          <div style="flex:1;min-width:0;">
            <div style="font-size:13px;font-weight:600;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${escapeHtml(e.suggested_band_name || e.title || 'Untitled event')}</div>
            ${sub ? `<div style="font-size:11px;color:var(--text-2);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${escapeHtml(sub)}</div>` : ''}
          </div>
        </label>`;
        }).join('')}
      </div>
      <div style="font-size:11px;color:var(--text-3);margin-bottom:10px;">Untick anything that isn't really a gig (birthdays, anniversaries...).</div>
      <button id="fiImportBtn" onclick="fiStartImport()" style="width:100%;background:var(--accent);color:#000;border:none;border-radius:14px;padding:14px;font-size:15px;font-weight:700;cursor:pointer;margin-bottom:8px;">Import all ${events.length}</button>
      <button onclick="document.getElementById('firstImportOverlay').remove();localStorage.setItem(window._currentUser?.id ? 'tmg_first_import_done:' + window._currentUser.id : 'tmg_first_import_done','1');" style="width:100%;background:transparent;color:var(--text-2);border:1px solid var(--border);border-radius:14px;padding:12px;font-size:13px;cursor:pointer;">Skip for now</button>

      <div style="font-size:11px;color:var(--text-3);margin-top:14px;line-height:1.5;">We'll add fees, dress code, and load-in times where the AI could find them. Anything blank, you can fill in seconds with the quick-fire review.</div>`;

    // Expose for inline handlers; closures on re-render.
    window.fiFetchAndRender = fiFetchAndRender;
    window.fiStartImport = fiStartImport;
    window.fiUpdateImportCount = fiUpdateImportCount;
  }

  // Per-event review (June 2026): keep the Import button's count in step
  // with the checkboxes so "Import selected (4)" always tells the truth.
  function fiUpdateImportCount() {
    const checks = document.querySelectorAll('.fi-event-check');
    const on = Array.from(checks).filter(c => c.checked).length;
    const btn = document.getElementById('fiImportBtn');
    if (!btn) return;
    btn.textContent = on === checks.length ? `Import all ${on}` : `Import selected (${on})`;
    btn.disabled = on === 0;
    btn.style.opacity = on === 0 ? '0.5' : '';
  }

  function rangeChip(val, label, current) {
    const on = val === current;
    return `<button onclick="fiFetchAndRender('${val}')" style="background:${on ? 'var(--accent)' : 'var(--card)'};color:${on ? '#000' : 'var(--text-2)'};border:1px solid ${on ? 'var(--accent)' : 'var(--border)'};border-radius:999px;padding:5px 12px;font-size:11px;font-weight:600;cursor:pointer;">${label}</button>`;
  }

  function windowLabel(mode) {
    if (mode === 'current_tax_year') return 'this tax year';
    if (mode === 'all') return 'the last two years';
    if (mode === 'future') return 'the next 60 days';
    return 'that range';
  }

  async function fiStartImport() {
    const state = window._firstImport;
    if (!state || !Array.isArray(state.events)) return;
    const body = document.getElementById('fiBody');
    if (!body) return;
    // Honour the review checkboxes: only ticked events import.
    const checks = document.querySelectorAll('.fi-event-check');
    if (checks.length > 0) {
      const keep = new Set(Array.from(checks).filter(c => c.checked).map(c => parseInt(c.dataset.idx, 10)));
      state.events = state.events.filter((_, i) => keep.has(i));
      if (state.events.length === 0) return;
    }
    body.innerHTML = `
      <div style="text-align:center;padding:30px 16px;">
        <div style="width:44px;height:44px;border-radius:50%;border:3px solid var(--border);border-top-color:var(--accent);margin:0 auto 16px;animation:fiSpin 1s linear infinite;"></div>
        <div style="font-size:14px;font-weight:600;color:var(--text);margin-bottom:4px;">Importing ${state.events.length} gig${state.events.length === 1 ? '' : 's'}...</div>
        <div style="font-size:11px;color:var(--text-3);">This takes a few seconds.</div>
      </div>`;

    // Build the payload: one object per event with whatever the AI pulled
    // plus the fallbacks. Server UPSERTs by google_event_id so re-runs are safe.
    const payload = {
      events: state.events.map(e => ({
        event_id: e.id,
        title: e.title,
        location: e.location,
        start: e.start,
        end: e.end,
        band_name: e.suggested_band_name || null,
        venue_name: e.suggested_venue_name || null,
        fee: e.suggested_fee || null,
        dress_code: e.suggested_dress_code || null,
        load_in_time: e.suggested_load_in_time || null,
        client_name: e.suggested_client_name || null,
        client_email: e.suggested_client_email || null,
        client_phone: e.suggested_client_phone || null,
        notes: e.suggested_notes || null,
        classifier_used: e.classifier_used || null,
        classify_confidence: typeof e.score === 'number' ? e.score : null,
        classify_reasons: e.reasons || null,
      })),
    };

    try {
      const r = await fetch('/api/calendar/import-bulk', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });
      const data = await r.json();
      if (!r.ok || data.error) {
        throw new Error(data.error || ('HTTP ' + r.status));
      }

      // 2026-04-27: per-user key (see firstImportKey in bootstrap).
      const _fid = window._currentUser?.id;
      localStorage.setItem(_fid ? `tmg_first_import_done:${_fid}` : 'tmg_first_import_done', '1');
      // Invalidate cached gigs so the Gigs + Home screens re-pull on next render.
      if (typeof invalidateGigsCache === 'function') invalidateGigsCache();

      const imported = (data.imported || 0) + (data.merged || 0);
      const gigs = Array.isArray(data.gigs) ? data.gigs : [];
      const needsFee = gigs.filter(g => g.fee == null || g.fee === '' || g.fee === 0);

      // Success state - show totals and kick off quick-fire if there are any
      // rows with missing fees. Otherwise one-tap close.
      const totalFee = gigs.reduce((s, g) => s + (parseFloat(g.fee) || 0), 0);
      body.innerHTML = `
        <div style="text-align:center;padding:10px 6px 0;">
          <div style="font-size:32px;margin-bottom:10px;">&#x1F389;</div>
          <div style="font-size:20px;font-weight:700;color:var(--text);margin-bottom:6px;">Imported ${imported} gig${imported === 1 ? '' : 's'}.</div>
          <div style="font-size:13px;color:var(--text-2);margin-bottom:18px;line-height:1.5;">
            ${totalFee > 0 ? `Pre-filled fees total &pound;${totalFee.toLocaleString('en-GB')}. ` : ''}
            ${needsFee.length > 0 ? `${needsFee.length} need${needsFee.length === 1 ? 's' : ''} a fee filling in.` : 'Every gig has a fee.'}
          </div>
          ${needsFee.length > 0 ? `
            <button onclick="fiStartWizard()" style="width:100%;background:var(--accent);color:#000;border:none;border-radius:14px;padding:14px;font-size:15px;font-weight:700;cursor:pointer;margin-bottom:8px;">Fill in fees now (${needsFee.length})</button>
            <button onclick="document.getElementById('firstImportOverlay').remove();" style="width:100%;background:transparent;color:var(--text-2);border:1px solid var(--border);border-radius:14px;padding:12px;font-size:13px;cursor:pointer;">Do it later</button>
          ` : `
            <button onclick="document.getElementById('firstImportOverlay').remove();" style="width:100%;background:var(--accent);color:#000;border:none;border-radius:14px;padding:14px;font-size:15px;font-weight:700;cursor:pointer;">See my gigs</button>
          `}
        </div>`;

      window._firstImport.imported = gigs;
      window._firstImport.needsFee = needsFee;
      window.fiStartWizard = fiStartWizard;
    } catch (err) {
      console.error('[first-import] bulk error:', err);
      body.innerHTML = `
        <div style="text-align:center;padding:30px 16px;">
          <div style="font-size:15px;font-weight:600;color:var(--danger);margin-bottom:6px;">Import failed</div>
          <div style="font-size:12px;color:var(--text-2);margin-bottom:16px;">${escapeHtml(err.message || String(err))}</div>
          <button onclick="document.getElementById('firstImportOverlay').remove();" style="background:var(--card);color:var(--text);border:1px solid var(--border);border-radius:10px;padding:10px 20px;font-size:13px;cursor:pointer;">Close</button>
        </div>`;
    }
  }
  window.fiStartImport = fiStartImport;

  // ── Quick-fire wizard ────────────────────────────────────────────────────
  // Steps through each imported gig without a fee. One gig per screen, fee
  // input pre-focused, Enter saves and advances. Keyboard-first so a musician
  // with 30 gigs to fill can clear them in 2-3 minutes.

  function fiStartWizard() {
    const state = window._firstImport;
    if (!state || !Array.isArray(state.needsFee) || state.needsFee.length === 0) {
      const o = ov(); if (o) o.remove();
      return;
    }
    state.wizardIndex = 0;
    state.wizardCompleted = 0;
    fiRenderWizardStep();
  }
  window.fiStartWizard = fiStartWizard;

  function fiRenderWizardStep() {
    const state = window._firstImport;
    const body = document.getElementById('fiBody');
    if (!state || !body) return;
    const gig = state.needsFee[state.wizardIndex];
    if (!gig) { fiFinishWizard(); return; }
    const total = state.needsFee.length;
    const pos = state.wizardIndex + 1;
    const pct = Math.round((pos / total) * 100);
    const dateLabel = gig.date ? new Date(gig.date).toLocaleDateString('en-GB', { weekday: 'short', day: 'numeric', month: 'short', year: 'numeric' }) : '';
    const venueLabel = gig.venue_name || '(no venue)';
    const bandLabel = gig.band_name || gig.title || 'Untitled';

    body.innerHTML = `
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:6px;">
        <div style="font-size:11px;font-weight:700;letter-spacing:1.2px;color:var(--accent);text-transform:uppercase;">Fill in fees - ${pos} of ${total}</div>
        <button onclick="fiFinishWizard()" aria-label="Close wizard" style="background:transparent;border:none;color:var(--text-3);font-size:22px;cursor:pointer;line-height:1;padding:0 4px;">&times;</button>
      </div>
      <div style="height:4px;background:var(--border);border-radius:2px;margin-bottom:16px;overflow:hidden;">
        <div style="height:100%;width:${pct}%;background:var(--accent);transition:width 0.25s;"></div>
      </div>

      <div style="font-size:17px;font-weight:600;color:var(--text);margin-bottom:2px;">${escapeHtml(bandLabel)}</div>
      <div style="font-size:13px;color:var(--text-2);margin-bottom:2px;">${escapeHtml(venueLabel)}</div>
      <div style="font-size:12px;color:var(--text-3);margin-bottom:18px;">${escapeHtml(dateLabel)}${gig.start_time ? ' &middot; ' + String(gig.start_time).substring(0, 5) : ''}</div>

      <label style="display:block;font-size:11px;font-weight:600;color:var(--text-2);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:6px;">Fee (&pound;)</label>
      <input id="fiFee" type="number" inputmode="decimal" step="10" placeholder="0" style="width:100%;padding:16px 14px;background:var(--bg);border:2px solid var(--accent);border-radius:12px;color:var(--text);font-size:24px;font-weight:700;box-sizing:border-box;margin-bottom:14px;" onkeydown="if(event.key==='Enter'){event.preventDefault();fiSaveAndNext();}" />

      <label style="display:block;font-size:11px;font-weight:600;color:var(--text-2);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:6px;">Dress code</label>
      <div style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:14px;" id="fiDress">
        ${['Smart', 'Black tie', 'All black', 'Casual'].map(v => `<button type="button" onclick="fiPickDress('${v}')" data-dress="${v}" style="background:var(--card);color:var(--text);border:1px solid var(--border);border-radius:16px;padding:6px 12px;font-size:12px;font-weight:600;cursor:pointer;">${v}</button>`).join('')}
      </div>

      <label style="display:block;font-size:11px;font-weight:600;color:var(--text-2);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:6px;">Notes (optional)</label>
      <textarea id="fiNotes" rows="2" placeholder="Anything else to remember..." style="width:100%;padding:10px 12px;background:var(--bg);border:1px solid var(--border);border-radius:10px;color:var(--text);font-size:13px;box-sizing:border-box;margin-bottom:16px;resize:vertical;font-family:inherit;"></textarea>

      <div style="display:flex;gap:8px;">
        <button onclick="fiSkip()" style="flex:1;background:var(--card);color:var(--text-2);border:1px solid var(--border);border-radius:14px;padding:12px;font-size:13px;font-weight:600;cursor:pointer;">Skip</button>
        <button onclick="fiSaveAndNext()" style="flex:2;background:var(--accent);color:#000;border:none;border-radius:14px;padding:12px;font-size:14px;font-weight:700;cursor:pointer;">Save &amp; next &rarr;</button>
      </div>
      <div style="font-size:10px;color:var(--text-3);margin-top:10px;text-align:center;">Tip: hit Enter to save and advance.</div>`;

    // Pre-focus the fee input so the user can start typing immediately.
    setTimeout(() => {
      const fee = document.getElementById('fiFee');
      if (fee) fee.focus();
    }, 50);
  }
  window.fiRenderWizardStep = fiRenderWizardStep;

  function fiPickDress(val) {
    const wrap = document.getElementById('fiDress');
    if (!wrap) return;
    wrap.dataset.chosen = val;
    Array.from(wrap.querySelectorAll('button')).forEach(btn => {
      const on = btn.dataset.dress === val;
      btn.style.background = on ? 'var(--accent)' : 'var(--card)';
      btn.style.color = on ? '#000' : 'var(--text)';
      btn.style.borderColor = on ? 'var(--accent)' : 'var(--border)';
    });
  }
  window.fiPickDress = fiPickDress;

  async function fiSaveAndNext() {
    const state = window._firstImport;
    if (!state) return;
    const gig = state.needsFee[state.wizardIndex];
    if (!gig) { fiFinishWizard(); return; }
    const feeEl = document.getElementById('fiFee');
    const notesEl = document.getElementById('fiNotes');
    const dressEl = document.getElementById('fiDress');
    const feeVal = feeEl ? parseFloat(feeEl.value) : NaN;
    const notes = notesEl ? notesEl.value.trim() : '';
    const dress = dressEl ? dressEl.dataset.chosen : null;
    if (!Number.isFinite(feeVal) || feeVal < 0) {
      // No fee typed. Treat as Skip rather than blocking progress - we
      // want the wizard to feel quick even if some gigs have unknown fees.
      return fiSkip();
    }
    try {
      await fetch('/api/gigs/' + encodeURIComponent(gig.id), {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ fee: feeVal, notes: notes || null, dress_code: dress || null }),
      });
      state.wizardCompleted++;
    } catch (err) {
      console.error('[wizard] save error:', err);
    }
    state.wizardIndex++;
    if (state.wizardIndex >= state.needsFee.length) {
      fiFinishWizard();
    } else {
      fiRenderWizardStep();
    }
  }
  window.fiSaveAndNext = fiSaveAndNext;

  function fiSkip() {
    const state = window._firstImport;
    if (!state) return;
    state.wizardIndex++;
    if (state.wizardIndex >= state.needsFee.length) {
      fiFinishWizard();
    } else {
      fiRenderWizardStep();
    }
  }
  window.fiSkip = fiSkip;

  function fiFinishWizard() {
    const state = window._firstImport;
    const body = document.getElementById('fiBody');
    if (!body) { closeOverlay(); return; }
    const done = state ? state.wizardCompleted : 0;
    const total = state && state.needsFee ? state.needsFee.length : 0;
    body.innerHTML = `
      <div style="text-align:center;padding:20px 10px;">
        <div style="font-size:40px;margin-bottom:10px;">&#x2705;</div>
        <div style="font-size:20px;font-weight:700;color:var(--text);margin-bottom:6px;">Nice work.</div>
        <div style="font-size:13px;color:var(--text-2);margin-bottom:20px;line-height:1.5;">
          ${done} of ${total} fee${total === 1 ? '' : 's'} saved. ${total - done > 0 ? 'You can fill the rest any time from the Gigs tab.' : 'Every imported gig has a fee. Tax time just got easier.'}
        </div>
        <button onclick="document.getElementById('firstImportOverlay').remove();" style="width:100%;background:var(--accent);color:#000;border:none;border-radius:14px;padding:14px;font-size:15px;font-weight:700;cursor:pointer;">See my gigs</button>
      </div>`;
    // Invalidate gigs cache so the Gigs screen reflects all the saved fees.
    if (typeof invalidateGigsCache === 'function') invalidateGigsCache();
    // Nudge Home to re-fetch so the "needs a fee" banner reflects the new count.
    try {
      window._cachedStats = null;
      window._cachedStatsTime = 0;
    } catch (_) {}
  }
  window.fiFinishWizard = fiFinishWizard;

  // ── Reusable entry point (task #291) ─────────────────────────────────────
  // Opens the quick-fire wizard from anywhere (Home banner, Gigs screen,
  // manual call) without going through the first-import flow. Fetches the
  // current pool of imported gigs missing a fee, seeds the same state shape
  // the wizard expects, and kicks off at step 1. Idempotent — multiple calls
  // just re-open the overlay with a fresh fetch.
  window.openFeeReviewWizard = async function openFeeReviewWizard() {
    const existing = ov();
    if (existing) existing.remove();

    const overlay = document.createElement('div');
    overlay.id = 'firstImportOverlay';
    overlay.style.cssText = 'position:fixed;inset:0;z-index:10000;background:rgba(0,0,0,.82);display:flex;align-items:center;justify-content:center;padding:20px;overflow:auto;';
    overlay.innerHTML = `
      <div style="background:var(--bg);border:1px solid var(--border);border-radius:18px;width:100%;max-width:440px;padding:24px;box-shadow:0 20px 60px rgba(0,0,0,.5);">
        <div id="fiBody">
          <div style="text-align:center;padding:40px 20px;">
            <div style="width:44px;height:44px;border-radius:50%;border:3px solid var(--border);border-top-color:var(--accent);margin:0 auto 16px;animation:fiSpin 1s linear infinite;"></div>
            <div style="font-size:14px;color:var(--text-2);">Finding imported gigs without a fee...</div>
          </div>
        </div>
      </div>
      <style>@keyframes fiSpin{to{transform:rotate(360deg);}}</style>`;
    document.body.appendChild(overlay);

    let gigs = [];
    try {
      const r = await fetch('/api/gigs');
      const data = await r.json();
      const all = Array.isArray(data) ? data : (data.gigs || []);
      // Candidates = gcal-sourced rows with no fee recorded. Matches the
      // /api/stats counting rule so the banner and the wizard stay in sync.
      gigs = all.filter((g) => {
        const src = g.source || '';
        const fee = g.fee;
        const missing = fee == null || Number(fee) === 0;
        return src.startsWith('gcal:') && missing;
      });
    } catch (err) {
      const body = document.getElementById('fiBody');
      if (body) {
        body.innerHTML = `
          <div style="text-align:center;padding:30px 16px;">
            <div style="font-size:15px;font-weight:600;color:var(--danger);margin-bottom:6px;">Couldn&#x2019;t load gigs</div>
            <div style="font-size:12px;color:var(--text-2);margin-bottom:16px;">${escapeHtml(err.message || String(err))}</div>
            <button onclick="document.getElementById('firstImportOverlay').remove();" style="background:var(--card);color:var(--text);border:1px solid var(--border);border-radius:10px;padding:10px 20px;font-size:13px;cursor:pointer;">Close</button>
          </div>`;
      }
      return;
    }

    if (gigs.length === 0) {
      const body = document.getElementById('fiBody');
      if (body) {
        body.innerHTML = `
          <div style="text-align:center;padding:30px 16px;">
            <div style="font-size:40px;margin-bottom:10px;">&#x1F389;</div>
            <div style="font-size:17px;font-weight:700;color:var(--text);margin-bottom:6px;">All caught up</div>
            <div style="font-size:12px;color:var(--text-2);margin-bottom:18px;line-height:1.5;">Every gig imported from Google has a fee recorded.</div>
            <button onclick="document.getElementById('firstImportOverlay').remove();" style="width:100%;background:var(--accent);color:#000;border:none;border-radius:14px;padding:14px;font-size:15px;font-weight:700;cursor:pointer;">Nice</button>
          </div>`;
      }
      return;
    }

    // Sort oldest first so the user works chronologically — makes it easier to
    // remember fees as they go (early-year gigs usually have better recall
    // than "yeah I did one in October, I think").
    gigs.sort((a, b) => (a.date || '').localeCompare(b.date || ''));

    // Seed the same state shape the first-import flow uses so the wizard
    // functions work without modification. `imported` is only used by the
    // summary screen that we bypass, but we set it defensively.
    window._firstImport = {
      events: [],
      windowMode: 'fee_review',
      imported: gigs,
      needsFee: gigs,
      wizardIndex: 0,
      wizardCompleted: 0,
    };

    fiRenderWizardStep();
  };
})();

// Helper referenced by the modal in case it isn't defined elsewhere.
if (typeof invalidateGigsCache !== 'function') {
  window.invalidateGigsCache = function () {
    try { window._cachedGigs = null; } catch (_) {}
    try { window._gigsCacheTime = 0; } catch (_) {}
    // Also drop the persisted calendar cache + its freshness stamp, otherwise a
    // page reload re-hydrates the stale gig list and a just-created gig (e.g.
    // from quick-log) goes missing from the calendar until the cache expires.
    try { window._cachedBlockedTime = 0; } catch (_) {}
    try { localStorage.removeItem('tmg_cachedCalendar_v1'); } catch (_) {}
  };
}

// "Import all" helper on the ongoing Imports-to-review bar. Piggy-backs on
// the first-import flow: pre-seeds the events from the cached nudges array
// and routes straight to the import + quick-fire path. Returns early if
// there are no nudges to import.
window.importAllNudges = async function importAllNudges() {
  const nudges = Array.isArray(window._calendarNudges) ? window._calendarNudges : [];
  if (nudges.length === 0) {
    if (typeof toast === 'function') toast('No imports to review');
    return;
  }
  // Open the same overlay the first-import modal uses, but skip the fetch
  // step by seeding _firstImport directly with the already-scored nudges.
  const overlay = document.createElement('div');
  overlay.id = 'firstImportOverlay';
  overlay.style.cssText = 'position:fixed;inset:0;z-index:10000;background:rgba(0,0,0,.82);display:flex;align-items:center;justify-content:center;padding:20px;overflow:auto;';
  overlay.innerHTML = `
    <div style="background:var(--bg);border:1px solid var(--border);border-radius:18px;width:100%;max-width:440px;padding:24px;">
      <div id="fiBody">
        <div style="text-align:center;padding:30px 16px;">
          <div style="font-size:24px;font-weight:700;color:var(--text);margin-bottom:6px;">Import all ${nudges.length}?</div>
          <div style="font-size:13px;color:var(--text-2);margin-bottom:18px;line-height:1.5;">Pulls the full batch into TrackMyGigs. Your Google Calendar isn't touched. You can fill in fees right after.</div>
          <button onclick="fiStartImport()" style="width:100%;background:var(--accent);color:#000;border:none;border-radius:14px;padding:14px;font-size:15px;font-weight:700;cursor:pointer;margin-bottom:8px;">Import ${nudges.length} now</button>
          <button onclick="document.getElementById('firstImportOverlay').remove();" style="width:100%;background:transparent;color:var(--text-2);border:1px solid var(--border);border-radius:14px;padding:12px;font-size:13px;cursor:pointer;">Cancel</button>
        </div>
      </div>
    </div>
    <style>@keyframes fiSpin{to{transform:rotate(360deg);}}</style>`;
  document.body.appendChild(overlay);
  // Seed the same state the first-import modal uses so fiStartImport works.
  window._firstImport = { events: nudges, windowMode: 'future' };
};

// ── Premium checkout + billing portal wiring (task #282) ────────────────────
// startPremiumCheckout(plan) posts to /api/stripe/create-checkout-session and
// redirects the tab to the returned Stripe URL. openBillingPortal() does the
// same for existing subscribers, routing them to Stripe's hosted portal to
// manage card, plan, or cancellation. Both are idempotent and surface errors
// via toast rather than silent failure, which was the previous inert state.
window.startPremiumCheckout = async function startPremiumCheckout(plan) {
  const chosen = plan === 'annual' ? 'annual' : 'monthly';
  if (typeof toast === 'function') toast('Opening Stripe checkout...');
  try {
    const res = await fetch('/api/stripe/create-checkout-session', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ plan: chosen }),
    });
    if (res.status === 401 || res.status === 403) {
      // Shouldn't happen from in-app (we only call this when authed), but
      // fall back to login anyway so we never leave the user stuck.
      window.location.href = '/login?next=' + encodeURIComponent('/app?intent=premium&plan=' + chosen);
      return;
    }
    if (res.status === 503) {
      if (typeof toast === 'function') toast('Premium signup is not live yet. Try again soon.');
      return;
    }
    const data = await res.json().catch(() => ({}));
    if (data && data.url) {
      window.location.href = data.url;
      return;
    }
    if (typeof toast === 'function') toast((data && data.error) || 'Could not start checkout.');
  } catch (err) {
    console.error('[premium] checkout error:', err);
    if (typeof toast === 'function') toast('Network hiccup. Try again.');
  }
};

window.openBillingPortal = async function openBillingPortal() {
  if (typeof toast === 'function') toast('Opening billing portal...');
  try {
    const res = await fetch('/api/stripe/billing-portal', { method: 'POST' });
    if (res.status === 503) {
      if (typeof toast === 'function') toast('Billing portal is not live yet.');
      return;
    }
    const data = await res.json().catch(() => ({}));
    if (data && data.url) {
      window.location.href = data.url;
      return;
    }
    if (data && data.error === 'no_subscription') {
      if (typeof toast === 'function') toast('Subscribe first to access the billing portal.');
      return;
    }
    if (typeof toast === 'function') toast((data && data.error) || 'Could not open portal.');
  } catch (err) {
    console.error('[premium] billing portal error:', err);
    if (typeof toast === 'function') toast('Network hiccup. Try again.');
  }
};

// Small plan-picker modal for free users tapping "Go premium" from Profile.
// Intentionally tiny — two big pills (Monthly / Annual save £50), copy
// matching the landing page so nothing changes semantically when the user
// crosses over from marketing to in-app.
window.openPremiumPicker = function openPremiumPicker() {
  const existing = document.getElementById('premiumPickerOverlay');
  if (existing) existing.remove();
  const overlay = document.createElement('div');
  overlay.id = 'premiumPickerOverlay';
  overlay.style.cssText = 'position:fixed;inset:0;z-index:10000;background:rgba(0,0,0,.82);display:flex;align-items:center;justify-content:center;padding:20px;';
  overlay.innerHTML = `
    <div style="background:var(--bg);border:1px solid var(--border);border-radius:18px;width:100%;max-width:380px;padding:22px;box-shadow:0 20px 60px rgba(0,0,0,.5);">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px;">
        <div style="font-size:17px;font-weight:700;color:var(--text);">Go premium</div>
        <button onclick="document.getElementById('premiumPickerOverlay').remove();" aria-label="Close" style="background:transparent;border:none;color:var(--text-3);font-size:22px;cursor:pointer;line-height:1;padding:0 4px;">&times;</button>
      </div>
      <div style="font-size:12px;color:var(--text-2);margin-bottom:14px;line-height:1.5;">14-day free trial on both plans. Cancel any time before day 14 and you will not be charged.</div>
      <button onclick="document.getElementById('premiumPickerOverlay').remove(); window.startPremiumCheckout('monthly');" style="width:100%;background:var(--card);border:1px solid var(--border);border-radius:14px;padding:14px;font-size:14px;font-weight:600;color:var(--text);cursor:pointer;margin-bottom:8px;text-align:left;display:flex;align-items:center;justify-content:space-between;gap:12px;">
        <span><span style="font-weight:700;">Monthly</span><br><span style="font-size:11px;color:var(--text-2);font-weight:400;">&pound;14.99 per month</span></span>
        <span style="color:var(--accent);">&rsaquo;</span>
      </button>
      <button onclick="document.getElementById('premiumPickerOverlay').remove(); window.startPremiumCheckout('annual');" style="width:100%;background:var(--accent);color:#000;border:none;border-radius:14px;padding:14px;font-size:14px;font-weight:700;cursor:pointer;text-align:left;display:flex;align-items:center;justify-content:space-between;gap:12px;">
        <span><span>Annual <span style="background:#000;color:var(--accent);font-size:9px;font-weight:700;padding:2px 6px;border-radius:999px;margin-left:4px;letter-spacing:0.4px;">SAVE &pound;50</span></span><br><span style="font-size:11px;color:#000;opacity:.75;font-weight:500;">&pound;129 per year</span></span>
        <span>&rsaquo;</span>
      </button>
    </div>`;
  document.body.appendChild(overlay);
};


// Two-step accept (June 2026, Gareth): sender locks in or releases a
// provisional yes from the Sent tab.
async function confirmProvisionalOffer(offerId) {
  try {
    const res = await fetch(`/api/offers/${offerId}/confirm`, { method: 'POST' });
    if (!res.ok) throw new Error('confirm failed');
    showToast('Confirmed. They have the gig in their diary now.');
    if (typeof loadSentOffers === 'function' && document.getElementById('sentOffersList')) {
      loadSentOffers();
    }
  } catch (err) {
    console.error('Confirm offer error:', err);
    showToast('Could not confirm. Try again.');
  }
}
window.confirmProvisionalOffer = confirmProvisionalOffer;

async function releaseProvisionalOffer(offerId) {
  const ok = window.confirmModal
    ? await window.confirmModal('Release this yes? They will be told the gig went another way.')
    : confirm('Release this yes?');
  if (!ok) return;
  try {
    const res = await fetch(`/api/offers/${offerId}/release`, { method: 'POST' });
    if (!res.ok) throw new Error('release failed');
    showToast('Released.');
    if (typeof loadSentOffers === 'function' && document.getElementById('sentOffersList')) {
      loadSentOffers();
    }
  } catch (err) {
    console.error('Release offer error:', err);
    showToast('Could not release. Try again.');
  }
}
window.releaseProvisionalOffer = releaseProvisionalOffer;


// ── Message quick actions: swipe-left / long-press (June 2026, Gareth) ──────
function wireMessageGestures() {
  const area = document.getElementById('chatMessagesArea');
  if (!area || area._gesturesWired) return;
  area._gesturesWired = true;
  let startX = 0, startY = 0, row = null, longTimer = null, moved = false, fired = false;
  const clear = () => { if (longTimer) { clearTimeout(longTimer); longTimer = null; } row = null; fired = false; };
  area.addEventListener('pointerdown', (e) => {
    row = e.target.closest('[data-msg-id]');
    if (!row || !row.dataset.msgId) { row = null; return; }
    moved = false; fired = false; startX = e.clientX; startY = e.clientY;
    const id = row.dataset.msgId;
    longTimer = setTimeout(() => {
      if (!moved && !fired) { fired = true; openMessageActionsSheet(id); }
    }, 550);
  });
  area.addEventListener('pointermove', (e) => {
    if (!row) return;
    const dx = e.clientX - startX;
    const dy = e.clientY - startY;
    if (Math.abs(dx) > 10 || Math.abs(dy) > 10) moved = true;
    if (!fired && Math.abs(dy) < 40 && dx < -56) {
      fired = true;
      const id = row.dataset.msgId;
      if (longTimer) { clearTimeout(longTimer); longTimer = null; }
      openMessageActionsSheet(id);
    }
  });
  ['pointerup', 'pointercancel'].forEach(ev => area.addEventListener(ev, clear));
}

function openMessageActionsSheet(msgId) {
  if (!msgId) return;
  const msgs = (window._chatThreadCache && window._chatThreadCache.messages) || [];
  const msg = msgs.find(m => m && (m.id === msgId || m.tempId === msgId));
  if (!msg) return;
  const me = window.currentUser || (typeof currentUser !== 'undefined' ? currentUser : null);
  const isOwn = me && msg.sender_id === me.id && !msg.pending;
  const hasText = !!(msg.content && String(msg.content).trim());
  const wrap = document.createElement('div');
  wrap.className = 'sheet-overlay';
  wrap.id = 'msgActionsSheet';
  wrap.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.55);z-index:99999;display:flex;align-items:flex-end;justify-content:center;';
  wrap.innerHTML = `
    <div class="sheet-panel" onclick="event.stopPropagation()" style="background:var(--card);border-top:1px solid var(--border);border-radius:16px 16px 0 0;width:100%;max-width:480px;padding-bottom:8px;">
      <div style="height:4px;width:36px;background:var(--text-3);border-radius:2px;margin:8px auto 4px;"></div>
      ${hasText ? `<button onclick="copyMessageText('${escapeAttr(msgId)}')" style="width:100%;text-align:left;background:transparent;border:none;color:var(--text);font-size:15px;padding:14px 20px;cursor:pointer;border-bottom:1px solid var(--border);">\u{1F4CB} Copy text</button>` : ''}
      ${isOwn ? `<button onclick="deleteOwnMessage('${escapeAttr(msgId)}')" style="width:100%;text-align:left;background:transparent;border:none;color:var(--danger);font-size:15px;padding:14px 20px;cursor:pointer;border-bottom:1px solid var(--border);">\u{1F5D1} Delete message</button>` : ''}
      <button onclick="closeMessageActionsSheet()" style="width:100%;text-align:center;background:transparent;border:none;color:var(--text-2);font-size:14px;padding:14px;cursor:pointer;">Cancel</button>
    </div>`;
  wrap.addEventListener('click', (e) => { if (e.target === wrap) closeMessageActionsSheet(); });
  document.body.appendChild(wrap);
}
window.openMessageActionsSheet = openMessageActionsSheet;

function closeMessageActionsSheet() {
  const el = document.getElementById('msgActionsSheet');
  if (el && el.parentNode) el.parentNode.removeChild(el);
}
window.closeMessageActionsSheet = closeMessageActionsSheet;

async function copyMessageText(msgId) {
  closeMessageActionsSheet();
  const msgs = (window._chatThreadCache && window._chatThreadCache.messages) || [];
  const msg = msgs.find(m => m && (m.id === msgId || m.tempId === msgId));
  if (!msg || !msg.content) return;
  try {
    await navigator.clipboard.writeText(msg.content);
    try { toast('Copied'); } catch (_) {}
  } catch (_) {
    _showCopySheet('Message text', msg.content, true);
  }
}
window.copyMessageText = copyMessageText;

async function deleteOwnMessage(msgId) {
  closeMessageActionsSheet();
  const ok = window.confirmModal
    ? await window.confirmModal('Delete this message for everyone?')
    : confirm('Delete this message?');
  if (!ok) return;
  try {
    const res = await fetch(`/api/chat/threads/${_currentThreadId}/messages/${msgId}`, { method: 'DELETE' });
    if (!res.ok) throw new Error('delete failed');
    if (window._chatThreadCache && Array.isArray(window._chatThreadCache.messages)) {
      window._chatThreadCache.messages = window._chatThreadCache.messages.filter(m => m && m.id !== msgId);
      renderChatThread(window._chatThreadCache.thread, window._chatThreadCache.messages);
    }
    try { toast('Message deleted'); } catch (_) {}
  } catch (err) {
    console.error('Delete message error:', err);
    try { toast('Could not delete that message.'); } catch (_) {}
  }
}
window.deleteOwnMessage = deleteOwnMessage;


// ── Saved invoice items (June 2026, Gareth) ─────────────────────────────────
//
// Every itemised row used on a sent/draft invoice is remembered server-side
// with its last rate. The itemise inputs autocomplete from them and picking
// a known description autofills the rate.

async function loadSavedInvoiceItems() {
  try {
    const res = await fetch('/api/invoice-items');
    if (!res.ok) return;
    const data = await res.json();
    window._invSavedItems = Array.isArray(data.items) ? data.items : [];
    let dl = document.getElementById('invItemSuggest');
    if (!dl) {
      dl = document.createElement('datalist');
      dl.id = 'invItemSuggest';
      document.body.appendChild(dl);
    }
    dl.innerHTML = window._invSavedItems
      .map(it => `<option value="${escapeAttr(it.description)}">${it.rate != null ? '£' + parseFloat(it.rate).toFixed(2) : ''}</option>`)
      .join('');
    paintSavedItemChips();
  } catch (_) {}
}
window.loadSavedInvoiceItems = loadSavedInvoiceItems;

// One-tap chips for the items you bill again and again, painted above the
// line rows so they are impossible to miss. Tapping adds a prefilled line
// at the saved rate (filling an empty first row instead of stacking).
function paintSavedItemChips() {
  const rowsEl = document.getElementById('invItemRows');
  if (!rowsEl) return;
  let strip = document.getElementById('invSavedChips');
  const items = window._invSavedItems || [];
  if (!items.length) { if (strip) strip.remove(); return; }
  if (!strip) {
    strip = document.createElement('div');
    strip.id = 'invSavedChips';
    strip.style.cssText = 'display:flex;flex-wrap:wrap;gap:6px;margin-bottom:8px;';
    rowsEl.parentElement.insertBefore(strip, rowsEl);
  }
  strip.innerHTML = '<span style="font-size:10px;color:var(--text-3);width:100%;">Your usual items, tap to add:</span>'
    + items.slice(0, 8).map((it, i) =>
      `<span onclick="quickAddSavedItem(${i})" style="background:var(--surface);border:1px solid var(--accent);color:var(--accent);border-radius:8px;padding:6px 10px;font-size:12px;font-weight:600;cursor:pointer;">${escapeHtml(it.description)}${it.rate != null ? ' \u00B7 \u00A3' + (parseFloat(it.rate) < 10 ? parseFloat(it.rate).toFixed(2) : Math.round(parseFloat(it.rate))) : ''}</span>`).join('')
    + `<span onclick="openSavedItemsManager()" style="border:1px dashed var(--border);color:var(--text-3);border-radius:8px;padding:6px 10px;font-size:12px;cursor:pointer;">Manage\u2026</span>`;
}
window.paintSavedItemChips = paintSavedItemChips;

function quickAddSavedItem(index) {
  const it = (window._invSavedItems || [])[index];
  if (!it) return;
  // Fill the first completely empty row before adding a new one.
  const rows = document.querySelectorAll('#invItemRows .inv-item-row');
  for (const row of rows) {
    const d = row.querySelector('.inv-item-desc');
    const r = row.querySelector('.inv-item-rate');
    if (d && !d.value.trim() && r && !r.value) {
      d.value = it.description;
      if (it.rate != null) r.value = parseFloat(it.rate).toFixed(2);
      recalcInvoiceItems();
      return;
    }
  }
  addInvoiceItemRow(it.description, 1, it.rate != null ? parseFloat(it.rate).toFixed(2) : '');
  recalcInvoiceItems();
}
window.quickAddSavedItem = quickAddSavedItem;

function autofillSavedItemRate(descInput) {
  const items = window._invSavedItems || [];
  const hit = items.find(it => (it.description || '').toLowerCase() === (descInput.value || '').trim().toLowerCase());
  if (!hit || hit.rate == null) return;
  const row = descInput.closest('.inv-item-row');
  const rateInput = row && row.querySelector('.inv-item-rate');
  if (rateInput && !rateInput.value) {
    rateInput.value = parseFloat(hit.rate).toFixed(2);
    recalcInvoiceItems();
  }
}
window.autofillSavedItemRate = autofillSavedItemRate;

async function openSavedItemsManager() {
  await loadSavedInvoiceItems();
  const items = window._invSavedItems || [];
  const wrap = document.createElement('div');
  wrap.className = 'sheet-overlay';
  wrap.id = 'savedItemsSheet';
  wrap.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.55);z-index:99999;display:flex;align-items:flex-end;justify-content:center;';
  wrap.innerHTML = `
    <div class="sheet-panel" onclick="event.stopPropagation()" style="background:var(--card);border-top:1px solid var(--border);border-radius:16px 16px 0 0;width:100%;max-width:480px;max-height:70vh;display:flex;flex-direction:column;">
      <div style="height:4px;width:36px;background:var(--text-3);border-radius:2px;margin:8px auto 4px;flex-shrink:0;"></div>
      <div style="font-size:11px;font-weight:700;color:var(--text-2);text-transform:uppercase;letter-spacing:0.5px;padding:14px 20px 6px;flex-shrink:0;">Saved invoice items</div>
      <div id="savedItemsList" style="flex:1;overflow-y:auto;">
        ${items.length === 0
          ? '<div style="padding:24px;text-align:center;color:var(--text-3);font-size:13px;">Nothing saved yet. Items you put on invoices are remembered here with their last price.</div>'
          : items.map(it => `
          <div style="display:flex;align-items:center;gap:10px;padding:11px 20px;border-bottom:1px solid var(--border);" data-saved-item="${escapeAttr(it.id)}">
            <div style="flex:1;min-width:0;">
              <div style="font-size:13px;font-weight:600;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${escapeHtml(it.description)}</div>
              ${it.rate != null ? `<div style="font-size:11px;color:var(--text-2);">£${parseFloat(it.rate).toFixed(2)}</div>` : ''}
            </div>
            <button onclick="deleteSavedInvoiceItem('${escapeAttr(it.id)}', this)" style="background:none;border:none;color:var(--danger);font-size:15px;cursor:pointer;padding:4px;" aria-label="Delete">✕</button>
          </div>`).join('')}
      </div>
      <button onclick="closeSavedItemsManager()" style="width:100%;text-align:center;background:transparent;border:none;color:var(--text-2);font-size:14px;padding:14px;cursor:pointer;flex-shrink:0;border-top:1px solid var(--border);">Done</button>
    </div>`;
  wrap.addEventListener('click', (e) => { if (e.target === wrap) closeSavedItemsManager(); });
  document.body.appendChild(wrap);
}
window.openSavedItemsManager = openSavedItemsManager;

function closeSavedItemsManager() {
  const el = document.getElementById('savedItemsSheet');
  if (el && el.parentNode) el.parentNode.removeChild(el);
}
window.closeSavedItemsManager = closeSavedItemsManager;

async function deleteSavedInvoiceItem(id, btn) {
  try {
    const res = await fetch(`/api/invoice-items/${id}`, { method: 'DELETE' });
    if (!res.ok) throw new Error('delete failed');
    const row = btn && btn.closest('[data-saved-item]');
    if (row && row.parentNode) row.parentNode.removeChild(row);
    window._invSavedItems = (window._invSavedItems || []).filter(it => it.id !== id);
    loadSavedInvoiceItems();
  } catch (err) {
    console.error('Delete saved item error:', err);
    try { toast('Could not delete that item.'); } catch (_) {}
  }
}
window.deleteSavedInvoiceItem = deleteSavedInvoiceItem;


// ── Calendar List view (June 2026, approved mockup) ─────────────────────────
//
// Apple-style flow: compact month grid with 4-colour activity bars, then a
// continuous list grouped by day. Scrolling the list moves the grid
// highlight; tapping a grid day scrolls the list. List is the default,
// remembered view.

function _calIso(d) {
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
}

// Offers feed the purple "dep activity" rows. Cached for 60s; re-renders the
// list when fresh data lands (same pattern as the Google pins).
async function loadCalendarListOffers() {
  const now = Date.now();
  if (window._calOffers && (now - (window._calOffersAt || 0)) < 60000) return;
  try {
    const [recRes, sentRes] = await Promise.all([
      fetch('/api/offers'),
      fetch('/api/offers/sent'),
    ]);
    const rec = recRes.ok ? await recRes.json() : [];
    const sentBody = sentRes.ok ? await sentRes.json() : [];
    const sent = Array.isArray(sentBody) ? sentBody : (sentBody.offers || []);
    window._calOffers = {
      received: (Array.isArray(rec) ? rec : []).filter(o => o.status === 'pending' || o.status === 'provisional'),
      sent: sent.filter(o => o.status === 'provisional'),
    };
    window._calOffersAt = Date.now();
    // Repaint if the list is on screen so the purple rows appear.
    const panel = document.getElementById('calendarScreen');
    if (panel && panel.classList.contains('active') && (window._calViewMode !== 'day' && window._calViewMode !== 'week')) {
      renderCalendarScreen();
    }
  } catch (_) {}
}

function renderCalendarListView(currentDate, gigs, blocked, googlePins) {
  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();
  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const firstDow = (new Date(year, month, 1).getDay() + 6) % 7;
  const todayIso = _calIso(new Date());
  const monthLabel = currentDate.toLocaleDateString('en-GB', { month: 'long', year: 'numeric' });
  const inMonth = (iso) => iso.slice(0, 7) === `${year}-${String(month + 1).padStart(2, '0')}`;

  const liveGigs = (gigs || []).filter(g => g && g.date && g.status !== 'cancelled');
  const gigsByDate = {};
  liveGigs.forEach(g => {
    const iso = String(g.date).slice(0, 10);
    (gigsByDate[iso] = gigsByDate[iso] || []).push(g);
  });

  // Blocked: expanded date set for the grid + collapsed runs for the list.
  const blockedSet = new Set();
  const blockedRuns = [];
  (blocked || []).forEach(row => {
    const dates = (Array.isArray(row.expanded_dates) && row.expanded_dates.length
      ? row.expanded_dates
      : [String(row.start_date || row.date || '').slice(0, 10)]).filter(d => d && inMonth(d)).sort();
    dates.forEach(d => blockedSet.add(d));
    let run = null;
    dates.forEach(d => {
      if (run && new Date(d) - new Date(run.to) === 86400000) { run.to = d; return; }
      run = { from: d, to: d, reason: row.reason || null, id: row.id };
      blockedRuns.push(run);
    });
  });

  // Google pins, minus ones already linked to a gig.
  const linkedEventIds = new Set(liveGigs.map(g => g.google_event_id).filter(Boolean));
  const pinsByDate = {};
  (googlePins || []).forEach(p => {
    if (!p || (p.id && linkedEventIds.has(p.id))) return;
    const iso = String(p.start || p.date || '').slice(0, 10);
    if (!iso || !inMonth(iso)) return;
    (pinsByDate[iso] = pinsByDate[iso] || []).push(p);
  });

  // Dep activity (purple): received pending/provisional + sent provisional.
  const offers = window._calOffers || { received: [], sent: [] };
  const depByDate = {};
  offers.received.forEach(o => {
    const iso = String(o.gig_date || '').slice(0, 10);
    if (!iso || !inMonth(iso)) return;
    (depByDate[iso] = depByDate[iso] || []).push({ kind: 'received', o });
  });
  offers.sent.forEach(o => {
    const iso = String(o.gig_date || '').slice(0, 10);
    if (!iso || !inMonth(iso)) return;
    (depByDate[iso] = depByDate[iso] || []).push({ kind: 'sent', o });
  });

  // Money strip: confirmed money only, per the house rule.
  let confirmedSum = 0;
  let gigCount = 0;
  liveGigs.forEach(g => {
    const iso = String(g.date).slice(0, 10);
    if (!inMonth(iso)) return;
    gigCount += 1;
    if (g.status === 'confirmed') confirmedSum += parseFloat(g.fee) || 0;
  });
  const blockedDays = Array.from(blockedSet).length;

  // ── Grid ──
  let cells = ['Mo','Tu','We','Th','Fr','Sa','Su']
    .map(d => `<div style="font-size:9px;color:var(--text-3);text-align:center;text-transform:uppercase;padding:4px 0;">${d}</div>`).join('');
  for (let i = 0; i < firstDow; i++) cells += '<div></div>';
  for (let d = 1; d <= daysInMonth; d++) {
    const iso = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
    const bars = [];
    if (gigsByDate[iso]) bars.push('var(--accent)');
    if (depByDate[iso]) bars.push('#A78BFA');
    if (pinsByDate[iso]) bars.push('var(--info)');
    if (blockedSet.has(iso)) bars.push('var(--text-3)');
    const isToday = iso === todayIso;
    const isPast = iso < todayIso;
    const isWeekend = ((firstDow + d - 1) % 7) >= 5;
    cells += `
      <div class="cal-list-cell" data-date="${iso}" onclick="selectCalListDay('${iso}')" style="aspect-ratio:.95;border-radius:8px;display:flex;flex-direction:column;align-items:center;padding-top:5px;cursor:pointer;${isWeekend ? 'background:rgba(255,255,255,.035);' : ''}">
        <span style="${isToday ? 'background:var(--accent);color:#000;font-weight:800;border-radius:50%;width:24px;height:24px;display:flex;align-items:center;justify-content:center;' : `color:${isPast ? 'var(--text-3)' : 'var(--text)'};`}font-size:13px;">${d}</span>
        <div style="display:flex;gap:2px;margin-top:3px;height:4px;${isPast ? 'opacity:.5;' : ''}">${bars.slice(0, 4).map(c => `<div style="width:9px;height:4px;border-radius:2px;background:${c};"></div>`).join('')}</div>
      </div>`;
  }

  // ── List items per day ──
  const fmtT = (t) => t ? String(t).slice(0, 5) : '';
  const TRAVEL_MIN = Number(localStorage.getItem('tmg_travel_mins')) || 60;
  const LOAD_MIN = Number(localStorage.getItem('tmg_load_mins')) || 30;
  const leaveBy = (g) => {
    if (!g.start_time || !(parseFloat(g.mileage_miles) > 0)) return '';
    const [h, m] = String(g.start_time).split(':').map(Number);
    let mins = h * 60 + m - TRAVEL_MIN - LOAD_MIN;
    if (mins < 0) mins = 0;
    return `Leave by ${String(Math.floor(mins / 60)).padStart(2, '0')}:${String(mins % 60).padStart(2, '0')} · ${Math.round(g.mileage_miles)} mi`;
  };

  const itemsByDate = {};
  const push = (iso, sortKey, html) => {
    (itemsByDate[iso] = itemsByDate[iso] || []).push({ sortKey, html });
  };

  liveGigs.forEach(g => {
    const iso = String(g.date).slice(0, 10);
    if (!inMonth(iso)) return;
    const fee = parseFloat(g.fee) > 0 ? '£' + Math.round(parseFloat(g.fee)) : '';
    const noFee = !fee ? '<span style="font-size:9px;color:var(--accent);background:var(--accent-dim);border-radius:6px;padding:1px 6px;margin-left:6px;font-weight:700;">No fee set</span>' : '';
    const subBits = [g.band_name && g.venue_name ? g.band_name : '', leaveBy(g), g.setlist_id ? 'setlist attached' : ''].filter(Boolean);
    push(iso, (g.start_time || '99:99'), `
      <div onclick="openGigDetail('${escapeAttr(g.id)}')" style="display:flex;gap:10px;padding:10px 4px;border-bottom:1px solid var(--border);align-items:center;cursor:pointer;">
        <div style="width:4px;align-self:stretch;border-radius:2px;background:var(--accent);flex-shrink:0;"></div>
        <div style="flex:1;min-width:0;">
          <div style="font-size:14px;font-weight:600;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${escapeHtml(g.venue_name || g.band_name || 'Gig')}${noFee}</div>
          ${subBits.length ? `<div style="font-size:11px;color:var(--text-2);margin-top:1px;">${escapeHtml(subBits.join(' · '))}</div>` : ''}
        </div>
        <div style="text-align:right;font-size:12px;color:var(--text-2);flex-shrink:0;line-height:1.5;">
          ${g.start_time ? `<b style="display:block;color:var(--text);">${fmtT(g.start_time)}${g.end_time ? '–' + fmtT(g.end_time) : ''}</b>` : '<b style="display:block;color:var(--text-3);">all-day</b>'}
          ${fee ? `<span style="color:var(--success);font-weight:700;">${fee}</span>` : ''}
        </div>
      </div>`);
  });

  Object.keys(depByDate).forEach(iso => {
    depByDate[iso].forEach(({ kind, o }) => {
      const isSent = kind === 'sent';
      const who = isSent
        ? (o.recipient_display_name || o.recipient_name || 'them')
        : (o.sender_display_name || o.sender_name || 'a band leader');
      const chip = isSent
        ? 'Confirm their yes?'
        : (o.status === 'provisional' ? 'Waiting for confirm' : 'Needs answer');
      const deadline = o.deadline ? `respond by ${new Date(o.deadline).toLocaleDateString('en-GB', { weekday: 'short' })}` : '';
      const fee = parseFloat(o.fee) > 0 ? '£' + Math.round(parseFloat(o.fee)) : '';
      push(iso, '98:98', `
        <div onclick="showScreen('offers')" style="display:flex;gap:10px;padding:10px 4px;border-bottom:1px solid var(--border);align-items:center;cursor:pointer;">
          <div style="width:4px;align-self:stretch;border-radius:2px;background:#A78BFA;flex-shrink:0;"></div>
          <div style="flex:1;min-width:0;">
            <div style="font-size:14px;font-weight:600;color:var(--text);">${isSent ? 'Dep offer out' : 'Dep request'} <span style="font-size:9px;color:#A78BFA;background:rgba(167,139,250,.14);border:1px solid rgba(167,139,250,.4);border-radius:6px;padding:1px 6px;margin-left:6px;font-weight:700;">${chip}</span></div>
            <div style="font-size:11px;color:var(--text-2);margin-top:1px;">${escapeHtml((isSent ? 'To ' : 'From ') + who)}${o.band_name ? ' · ' + escapeHtml(o.band_name) : ''}</div>
          </div>
          <div style="text-align:right;font-size:12px;color:var(--text-2);flex-shrink:0;line-height:1.5;">
            ${fee ? `<b style="display:block;color:var(--text);">${fee}</b>` : ''}
            ${deadline ? `<span style="font-size:10px;color:var(--text-3);">${escapeHtml(deadline)}</span>` : ''}
          </div>
        </div>`);
    });
  });

  Object.keys(pinsByDate).forEach(iso => {
    pinsByDate[iso].forEach(p => {
      const title = p.title || p.summary || 'Busy';
      const timed = !p.all_day && !!p.start_time;
      const timeLabel = timed ? p.start_time : 'all-day';
      const isNudge = !!(window._calendarNudgesById && window._calendarNudgesById[p.id]);
      // Personal events open a clean detail; only AI gig-candidates get the
      // import/busy/ignore sheet (promotion also lives in the imports-review bar).
      const click = (!isNudge && p.pe_id)
        ? `openPersonalEventDetail('${escapeAttr(p.pe_id)}')`
        : `openGooglePinSheet('${escapeAttr(p.id)}')`;
      const subtitle = isNudge ? 'Tap to review as a gig' : (p.location ? escapeHtml(p.location) : 'Tap for details');
      push(iso, timed ? p.start_time : '97:97', `
        <div onclick="${click}" style="display:flex;gap:10px;padding:10px 4px;border-bottom:1px solid var(--border);align-items:center;cursor:pointer;">
          <div style="width:4px;align-self:stretch;border-radius:2px;background:var(--info);flex-shrink:0;"></div>
          <div style="flex:1;min-width:0;">
            <div style="font-size:14px;font-weight:600;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${escapeHtml(title)} <span style="font-size:9px;color:var(--info);background:rgba(88,166,255,.12);border-radius:6px;padding:1px 6px;margin-left:6px;font-weight:700;">From Google</span></div>
            <div style="font-size:11px;color:var(--text-2);margin-top:1px;">${subtitle}</div>
          </div>
          <div style="text-align:right;font-size:12px;color:var(--text-3);flex-shrink:0;">${timeLabel}</div>
        </div>`);
    });
  });

  blockedRuns.forEach(run => {
    const label = run.from === run.to
      ? new Date(run.from).toLocaleDateString('en-GB', { weekday: 'short', day: 'numeric', month: 'short' })
      : `${new Date(run.from).toLocaleDateString('en-GB', { weekday: 'short', day: 'numeric' })} – ${new Date(run.to).toLocaleDateString('en-GB', { weekday: 'short', day: 'numeric', month: 'short' })}`;
    // Day-panel mode: the run row appears on every day it covers.
    const runDays = [];
    for (let d = new Date(run.from + 'T00:00:00'); _calIso(d) <= run.to; d.setDate(d.getDate() + 1)) runDays.push(_calIso(d));
    runDays.forEach(dayIso => push(dayIso, '00:00', `
      <div onclick="openMyAvailabilityPanel()" style="display:flex;gap:10px;padding:10px 4px;border-bottom:1px solid var(--border);align-items:center;cursor:pointer;">
        <div style="width:4px;align-self:stretch;border-radius:2px;background:var(--text-3);flex-shrink:0;"></div>
        <div style="flex:1;min-width:0;">
          <div style="font-size:14px;font-weight:600;color:var(--text);">Blocked${run.reason ? ' · ' + escapeHtml(run.reason) : ''}</div>
          <div style="font-size:11px;color:var(--text-2);margin-top:1px;">${escapeHtml(label)} · hidden from your public availability</div>
        </div>
        <div style="text-align:right;font-size:12px;color:var(--text-3);flex-shrink:0;">all-day</div>
      </div>`));
  });

  // Apple behaviour (Gareth's correction): the list shows ONLY the
  // highlighted day. Selection defaults to today in the current month, or
  // the 1st when browsing another month. Stash itemsByDate so day taps can
  // repaint just the list without a full screen render.
  window._calListItems = itemsByDate;
  let selected = window._calListSelected;
  if (!selected || !inMonth(selected)) {
    selected = inMonth(todayIso) ? todayIso : `${year}-${String(month + 1).padStart(2, '0')}-01`;
    window._calListSelected = selected;
  }
  const listHtml = buildCalListDayHtml(selected);

  return `
    <div style="display:flex;align-items:center;justify-content:space-between;padding:10px 16px 2px;">
      <button onclick="prevCalendarMonth()" style="background:none;border:none;color:var(--accent);font-size:20px;cursor:pointer;">&#8249;</button>
      <span onclick="openMonthJumpSheet()" style="font-size:15px;font-weight:700;color:var(--text);cursor:pointer;">${escapeHtml(monthLabel)} <span style="color:var(--text-3);font-size:11px;">&#9662;</span></span>
      <button onclick="nextCalendarMonth()" style="background:none;border:none;color:var(--accent);font-size:20px;cursor:pointer;">&#8250;</button>
    </div>
    <div style="display:flex;align-items:center;justify-content:space-between;padding:0 16px 6px;">
      <span style="font-size:11px;color:var(--text-2);">${gigCount} gig${gigCount === 1 ? '' : 's'} · <span style="color:var(--success);font-weight:700;">£${Math.round(confirmedSum).toLocaleString()} confirmed</span></span>
      <span style="font-size:11px;color:var(--text-2);">${blockedDays ? blockedDays + ' day' + (blockedDays === 1 ? '' : 's') + ' blocked' : ''}</span>
    </div>
    <div id="calListGrid" style="display:grid;grid-template-columns:repeat(7,1fr);gap:2px;padding:0 12px;-webkit-user-select:none;user-select:none;">${cells}</div>
    <div style="display:flex;gap:12px;justify-content:center;font-size:10px;color:var(--text-2);padding:8px 0 2px;">
      <span><i style="display:inline-block;width:8px;height:8px;border-radius:2px;margin-right:4px;background:var(--accent);"></i>Gig</span>
      <span class="feat-dep"><i style="display:inline-block;width:8px;height:8px;border-radius:2px;margin-right:4px;background:#A78BFA;"></i>Dep</span>
      <span><i style="display:inline-block;width:8px;height:8px;border-radius:2px;margin-right:4px;background:var(--info);"></i>Google</span>
      <span><i style="display:inline-block;width:8px;height:8px;border-radius:2px;margin-right:4px;background:var(--text-3);"></i>Blocked</span>
    </div>
    <div id="calListBody" style="padding:4px 12px 24px;">${listHtml}</div>`;
}

// Render one day's rows (header with prev/next chevrons + items or empty state).
function buildCalListDayHtml(iso) {
  const items = (window._calListItems || {})[iso] || [];
  const todayIso = _calIso(new Date());
  const d = new Date(iso + 'T00:00:00');
  const label = (iso === todayIso ? 'Today · ' : '') + d.toLocaleDateString('en-GB', { weekday: 'long', day: 'numeric', month: 'long' });
  let html = `
    <div style="display:flex;align-items:center;justify-content:space-between;padding:12px 0 6px;border-bottom:1px solid var(--border);">
      <div style="display:flex;align-items:center;"><span style="width:30px;"></span><button onclick="calListShiftDay(-1)" style="background:none;border:none;color:var(--accent);font-size:18px;cursor:pointer;padding:0 8px;">&#8249;</button></div>
      <span style="font-size:12px;font-weight:700;color:${iso === todayIso ? 'var(--accent)' : 'var(--text-2)'};text-transform:uppercase;letter-spacing:.6px;">${escapeHtml(label)}${iso !== todayIso ? ` <span onclick="event.stopPropagation();calListGoToday()" style="color:#000;background:var(--accent);border-radius:8px;padding:2px 8px;font-size:10px;font-weight:800;cursor:pointer;margin-left:6px;letter-spacing:0;text-transform:none;">Today</span>` : ''}</span>
      <div style="display:flex;align-items:center;"><button onclick="calListShiftDay(1)" style="background:none;border:none;color:var(--accent);font-size:18px;cursor:pointer;padding:0 8px;">&#8250;</button><button onclick="window._prefillGigDate='${iso}';openGigWizard();" aria-label="Add gig on this day" style="background:none;border:none;color:var(--accent);font-size:20px;font-weight:600;cursor:pointer;padding:0 8px;width:30px;">+</button></div>
    </div>`;
  if (items.length === 0) {
    html += `
      <div style="padding:28px 16px;text-align:center;color:var(--text-3);font-size:13px;">
        Nothing on this day.
        <div style="margin-top:10px;"><span onclick="openDayActionSheet('${iso}')" style="color:var(--accent);font-weight:600;cursor:pointer;font-size:12px;">Day options ›</span></div>
      </div>`;
  } else {
    items.sort((a, b) => a.sortKey.localeCompare(b.sortKey)).forEach(it => { html += it.html; });
    html += `<div style="padding:10px 4px;text-align:right;"><span onclick="openDayActionSheet('${iso}')" style="color:var(--text-3);font-size:11px;cursor:pointer;">Day options ›</span></div>`;
  }
  return html;
}

function selectCalListDay(iso) {
  window._calListSelected = iso;
  document.querySelectorAll('.cal-list-cell').forEach(c => {
    c.style.outline = c.dataset.date === iso ? '2px solid var(--accent)' : '';
    c.style.outlineOffset = c.dataset.date === iso ? '-2px' : '';
  });
  const body = document.getElementById('calListBody');
  if (body) body.innerHTML = buildCalListDayHtml(iso);
}
window.selectCalListDay = selectCalListDay;

// Prev/next day chevrons and swipe both route here; crossing a month
// boundary moves the whole view to that month.
function calListShiftDay(delta) {
  const cur = new Date((window._calListSelected || _calIso(new Date())) + 'T00:00:00');
  cur.setDate(cur.getDate() + delta);
  const iso = _calIso(cur);
  const grid = document.querySelector(`.cal-list-cell[data-date="${iso}"]`);
  if (!grid) {
    window._calDate = cur;
    window._calListSelected = iso;
    renderCalendarScreen();
    return;
  }
  selectCalListDay(iso);
}
window.calListShiftDay = calListShiftDay;

function calListGoToday() {
  const now = new Date();
  const cur = window._calDate || now;
  window._calListSelected = _calIso(now);
  if (cur.getFullYear() !== now.getFullYear() || cur.getMonth() !== now.getMonth()) {
    window._calDate = now;
    renderCalendarScreen();
  } else {
    selectCalListDay(_calIso(now));
  }
}
window.calListGoToday = calListGoToday;

function initCalListBehaviour() {
  // Paint the selection ring and the Today pill state.
  const sel = window._calListSelected || _calIso(new Date());
  document.querySelectorAll('.cal-list-cell').forEach(c => {
    c.style.outline = c.dataset.date === sel ? '2px solid var(--accent)' : '';
    c.style.outlineOffset = c.dataset.date === sel ? '-2px' : '';
  });
  // Swipe left/right on the day panel moves a day, like Apple.
  const body = document.getElementById('calListBody');
  if (body && !body._swipeWired) {
    body._swipeWired = true;
    let sx = 0, sy = 0;
    body.addEventListener('touchstart', (e) => {
      sx = e.touches[0].clientX; sy = e.touches[0].clientY;
    }, { passive: true });
    body.addEventListener('touchend', (e) => {
      const dx = e.changedTouches[0].clientX - sx;
      const dy = e.changedTouches[0].clientY - sy;
      if (Math.abs(dx) > 56 && Math.abs(dy) < 48) calListShiftDay(dx < 0 ? 1 : -1);
    }, { passive: true });
  }
  // On the grid itself: sideways swipe flips the month, long-press a day
  // opens its options sheet. A fired long-press swallows the click that
  // follows pointerup so the day doesn't also get selected.
  const grid = document.getElementById('calListGrid');
  if (grid && !grid._gesturesWired) {
    grid._gesturesWired = true;
    let gsx = 0, gsy = 0;
    grid.addEventListener('touchstart', (e) => {
      gsx = e.touches[0].clientX; gsy = e.touches[0].clientY;
    }, { passive: true });
    grid.addEventListener('touchend', (e) => {
      const dx = e.changedTouches[0].clientX - gsx;
      const dy = e.changedTouches[0].clientY - gsy;
      if (Math.abs(dx) > 56 && Math.abs(dy) < 48) (dx < 0 ? nextCalendarMonth : prevCalendarMonth)();
    }, { passive: true });
    let lpTimer = null, lpX = 0, lpY = 0;
    const cancelLp = () => { if (lpTimer) { clearTimeout(lpTimer); lpTimer = null; } };
    grid.addEventListener('pointerdown', (e) => {
      const cell = e.target.closest('.cal-list-cell');
      if (!cell) return;
      lpX = e.clientX; lpY = e.clientY;
      cancelLp();
      lpTimer = setTimeout(() => {
        lpTimer = null;
        grid._lpFired = true;
        openDayActionSheet(cell.dataset.date);
      }, 500);
    });
    grid.addEventListener('pointermove', (e) => {
      if (lpTimer && (Math.abs(e.clientX - lpX) > 10 || Math.abs(e.clientY - lpY) > 10)) cancelLp();
    });
    grid.addEventListener('pointerup', cancelLp);
    grid.addEventListener('pointercancel', cancelLp);
    grid.addEventListener('click', (e) => {
      if (grid._lpFired) {
        grid._lpFired = false;
        e.stopPropagation();
        e.preventDefault();
      }
    }, true);
  }
}
